import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Camera } from 'lucide-react';
import { SubjectConfig, CameraConfig } from '../types';

interface FloorPlannerProps {
  subjectA: SubjectConfig;
  subjectB: SubjectConfig;
  activeCount: 1 | 2;
  cameras: CameraConfig[];
  activeCameraIndex: number;
  onUpdateSubject: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  subjectA, 
  subjectB, 
  activeCount, 
  cameras, 
  activeCameraIndex,
  onUpdateSubject,
  onUpdateCamera,
  onSelectCamera
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragState, setDragState] = useState<{ type: 'subject' | 'camera'; id: any } | null>(null);

  const handlersRef = useRef({ onUpdateSubject, onUpdateCamera, onSelectCamera });
  useEffect(() => {
    handlersRef.current = { onUpdateSubject, onUpdateCamera, onSelectCamera };
  }, [onUpdateSubject, onUpdateCamera, onSelectCamera]);

  const getFovAngle = (lens: string) => {
    const mmMatch = lens.match(/(\d+)mm/);
    const mm = mmMatch ? parseInt(mmMatch[1]) : 50;
    return 2 * Math.atan(18 / mm) * (180 / Math.PI);
  };

  const startDrag = (type: 'subject' | 'camera', id: any) => (e: React.MouseEvent | React.TouchEvent) => {
    // Prevent default to stop scrolling/text selection during drag
    if (e.cancelable) e.preventDefault();
    e.stopPropagation();

    if (type === 'camera') handlersRef.current.onSelectCamera(id as number);
    setDragState({ type, id });
  };

  const handleMove = useCallback((clientX: number, clientY: number) => {
    if (!dragState || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();

    // Calculate 0-1 normalized coordinates
    const normX = (clientX - rect.left) / rect.width;
    const normY = (clientY - rect.top) / rect.height;

    // Map to -100 to 100 for X
    const x = Math.max(-100, Math.min(100, normX * 200 - 100));
    // Map to 0 to 100 for Y (flipped so 0 is bottom/near-camera)
    const y = Math.max(0, Math.min(100, (1 - normY) * 100));

    if (dragState.type === 'subject') {
      handlersRef.current.onUpdateSubject(dragState.id, { x, y });
    } else {
      handlersRef.current.onUpdateCamera(dragState.id, { x, y });
    }
  }, [dragState]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    handleMove(e.clientX, e.clientY);
  }, [handleMove]);

  const onTouchMove = useCallback((e: TouchEvent) => {
    if (e.touches.length > 0) {
      handleMove(e.touches[0].clientX, e.touches[0].clientY);
    }
  }, [handleMove]);

  const endDrag = useCallback(() => {
    setDragState(null);
  }, []);

  useEffect(() => {
    if (dragState) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', endDrag);
      window.addEventListener('touchmove', onTouchMove, { passive: false });
      window.addEventListener('touchend', endDrag);
      window.addEventListener('touchcancel', endDrag);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', endDrag);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('touchend', endDrag);
      window.removeEventListener('touchcancel', endDrag);
    };
  }, [dragState, onMouseMove, onTouchMove, endDrag]);

  const renderSubject = (id: 'a' | 'b', config: SubjectConfig) => {
    const left = `${((config.x + 100) / 200) * 100}%`;
    const top = `${100 - config.y}%`;
    const isDragging = dragState?.type === 'subject' && dragState.id === id;

    return (
      <div 
        key={id}
        onMouseDown={startDrag('subject', id)}
        onTouchStart={startDrag('subject', id)}
        style={{ left, top }}
        className={`absolute -translate-x-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing z-20 group select-none touch-none`}
      >
        <div className={`relative w-12 h-12 flex items-center justify-center transition-transform ${isDragging ? 'scale-125' : 'hover:scale-110'}`}>
          <div 
            className="absolute inset-0 transition-transform duration-200"
            style={{ transform: `rotate(${config.rotation}deg)` }}
          >
            <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-md">
              <ellipse cx="50" cy="50" rx="35" ry="18" fill={id === 'a' ? 'rgba(99, 102, 241, 0.4)' : 'rgba(168, 85, 247, 0.4)'} stroke={id === 'a' ? '#6366f1' : '#a855f7'} strokeWidth="4" />
              <circle cx="50" cy="50" r="14" fill={id === 'a' ? '#6366f1' : '#a855f7'} />
              <path d="M44 42 L50 32 L56 42 Z" fill={id === 'a' ? '#818cf8' : '#c084fc'} />
            </svg>
          </div>
          <div 
            className="absolute inset-0 pointer-events-none transition-transform duration-200"
            style={{ transform: `rotate(${config.gaze}deg)` }}
          >
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[180%] flex flex-col items-center">
                <div className="w-0.5 h-6 bg-gradient-to-t from-emerald-500 to-transparent rounded-full"></div>
                <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full -mt-1 shadow-[0_0_8px_rgba(52,211,153,0.5)]"></div>
             </div>
          </div>
          <div className="absolute -top-6 left-1/2 -translate-x-1/2 text-[7px] font-black uppercase text-white/40 tracking-tighter whitespace-nowrap">
            SUB {id.toUpperCase()}
          </div>
        </div>
      </div>
    );
  };

  const renderCamera = (cam: CameraConfig, index: number) => {
    const left = `${((cam.x + 100) / 200) * 100}%`;
    const top = `${100 - cam.y}%`;
    const isActive = activeCameraIndex === index;
    const fov = getFovAngle(cam.lens);

    return (
      <div 
        key={cam.id}
        style={{ left, top }}
        onMouseDown={startDrag('camera', index)}
        onTouchStart={startDrag('camera', index)}
        className={`absolute -translate-x-1/2 -translate-y-1/2 select-none z-30 group cursor-grab active:cursor-grabbing touch-none ${isActive ? 'z-40' : 'z-20'}`}
      >
        <div 
          className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none transition-all duration-200"
          style={{ transform: `rotate(${cam.rotation}deg)`, opacity: isActive ? 0.35 : 0.08 }}
        >
          <svg className="w-[400px] h-[400px] -translate-y-1/2">
             <path 
                d={`M 200 200 L ${200 - Math.tan((fov / 2) * Math.PI / 180) * 200} 0 L ${200 + Math.tan((fov / 2) * Math.PI / 180) * 200} 0 Z`} 
                fill="url(#fovGradient)"
              />
          </svg>
        </div>

        <div className={`relative p-2.5 rounded-xl border transition-all ${isActive ? 'bg-indigo-600 border-indigo-300 shadow-xl scale-110' : 'bg-black/90 border-white/20 hover:border-white/40 opacity-70'}`}>
          <div className="transition-transform duration-200" style={{ transform: `rotate(${cam.rotation}deg)` }}>
            <Camera className="w-4 h-4 text-white" />
          </div>
          <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 bg-black/80 px-1.5 py-0.5 rounded text-[7px] font-bold text-white/80 uppercase whitespace-nowrap tracking-widest border border-white/10">
            CAM {index + 1}
          </div>
        </div>
      </div>
    );
  };

  return (
    <section className="space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-white/50">Production Stage</h2>
        <div className="flex gap-2 text-[8px] font-mono text-white/20 uppercase">
          {cameras.length} Nodes Active
        </div>
      </div>

      <div 
        ref={containerRef}
        className="relative aspect-square w-full bg-[#050505] rounded-[2rem] border border-white/10 overflow-hidden shadow-2xl cursor-crosshair select-none"
        style={{ boxShadow: 'inset 0 0 60px rgba(0,0,0,0.8)' }}
      >
        <svg className="absolute w-0 h-0">
          <defs>
            <linearGradient id="fovGradient" x1="0.5" y1="1" x2="0.5" y2="0">
              <stop offset="0%" stopColor="#818cf8" stopOpacity="0.9" />
              <stop offset="100%" stopColor="#6366f1" stopOpacity="0" />
            </linearGradient>
          </defs>
        </svg>

        <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', backgroundSize: '20px 20px' }}></div>
        <div className="absolute inset-0 bg-gradient-to-b from-indigo-500/5 to-transparent pointer-events-none"></div>

        {renderSubject('a', subjectA)}
        {activeCount === 2 && renderSubject('b', subjectB)}
        {cameras.map((cam, idx) => renderCamera(cam, idx))}
      </div>

      <div className="flex justify-center items-center px-1">
        <p className="text-[7px] text-white/20 uppercase tracking-[0.3em] font-black">Spatial Mapping Matrix</p>
      </div>
    </section>
  );
};

export default FloorPlanner;

import React, { useState } from 'react';
import { Camera, Layers, Sun, Trash2, Download, Wand2, Loader2, Settings2, Copy, Check, X, FileText, RotateCw, Monitor, UserPlus, UserMinus, ArrowUpDown, Compass, Code2, Eye, Plus, ChevronRight, ChevronLeft } from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage, SubjectConfig, CameraConfig } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, LIGHT_POSITIONS, SHOT_SCALES, VERTICAL_ANGLES } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import LightRig from './components/LightRig';
import ShotScalePicker from './components/ShotScalePicker';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import { generateDraftPrompt, generateStudioImage } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    subjects: {
      a: { x: -20, y: 30, rotation: 0, gaze: 0 },
      b: { x: 30, y: 50, rotation: 180, gaze: 180 },
      activeCount: 2,
    },
    cameras: [
      {
        id: 'cam-1',
        x: 0,
        y: 5,
        rotation: 0,
        model: CAMERA_MODELS[0],
        lens: LENSES[1],
        shotScale: SHOT_SCALES[1].label,
        verticalAngle: VERTICAL_ANGLES[1],
      }
    ],
    activeCameraIndex: 0,
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    draftPrompt: '',
  });

  const activeCamera = state.cameras[state.activeCameraIndex];

  const [promptView, setPromptView] = useState<'text' | 'json'>('text');
  const [isCopied, setIsCopied] = useState(false);

  const handleUpload = (type: ReferenceType, dataUrl: string, mimeType: string) => {
    setState(prev => ({
      ...prev,
      references: { ...prev.references, [type]: { ...prev.references[type], dataUrl, mimeType } }
    }));
  };

  const updateSubject = (id: 'a' | 'b', updates: Partial<SubjectConfig>) => {
    setState(prev => ({
      ...prev,
      subjects: {
        ...prev.subjects,
        [id]: { ...prev.subjects[id], ...updates }
      }
    }));
  };

  const updateCamera = (index: number, updates: Partial<CameraConfig>) => {
    setState(prev => {
      const newCameras = [...prev.cameras];
      newCameras[index] = { ...newCameras[index], ...updates };
      return { ...prev, cameras: newCameras };
    });
  };

  const addCamera = () => {
    if (state.cameras.length >= 4) return;
    const newCam: CameraConfig = {
      ...activeCamera,
      id: `cam-${Date.now()}`,
      x: activeCamera.x + 20,
      y: activeCamera.y
    };
    setState(prev => ({
      ...prev,
      cameras: [...prev.cameras, newCam],
      activeCameraIndex: prev.cameras.length
    }));
  };

  const removeCamera = (index: number) => {
    if (state.cameras.length <= 1) return;
    setState(prev => {
      const newCameras = prev.cameras.filter((_, i) => i !== index);
      const newIndex = Math.min(prev.activeCameraIndex, newCameras.length - 1);
      return { ...prev, cameras: newCameras, activeCameraIndex: newIndex };
    });
  };

  const handleGeneratePrompt = async () => {
    setState(prev => ({ ...prev, isGeneratingPrompt: true }));
    try {
      const prompt = await generateDraftPrompt(state);
      setState(prev => ({ ...prev, draftPrompt: prompt, isGeneratingPrompt: false, isReviewingPrompt: true }));
    } catch (err: any) {
      console.error(err);
      setState(prev => ({ ...prev, isGeneratingPrompt: false }));
    }
  };

  const handleFinalRender = async () => {
    setState(prev => ({ ...prev, isGenerating: true, isReviewingPrompt: false }));
    try {
      const result = await generateStudioImage(state, state.draftPrompt);
      setState(prev => ({ ...prev, generatedImage: result, isGenerating: false }));
    } catch (err: any) {
      console.error(err);
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const getJsonPrompt = () => {
    try {
      const aiResponse = JSON.parse(state.draftPrompt);
      const fullState = {
        scene_config: {
          subjects: state.subjects,
          active_camera: activeCamera,
          lighting: state.lighting.positions.map((on, i) => on ? LIGHT_POSITIONS[i].label : null).filter(Boolean),
          assets: (Object.values(state.references) as ReferenceImage[]).filter(r => !!r.dataUrl).map(r => r.label),
        },
        ai_script: aiResponse
      };
      return JSON.stringify(fullState, null, 2);
    } catch (e) {
      return JSON.stringify({ error: "Invalid JSON structure in draft", raw: state.draftPrompt }, null, 2);
    }
  };

  const getDisplayText = () => {
    try {
      const parsed = JSON.parse(state.draftPrompt);
      return parsed.script || state.draftPrompt;
    } catch (e) {
      return state.draftPrompt;
    }
  };

  const handleCopyPrompt = () => {
    const textToCopy = promptView === 'text' ? getDisplayText() : getJsonPrompt();
    navigator.clipboard.writeText(textToCopy);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  const downloadImage = () => {
    if (!state.generatedImage) return;
    const link = document.createElement('a');
    link.href = state.generatedImage;
    link.download = `cinematic-render-${Date.now()}.png`;
    link.click();
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] flex flex-col overflow-hidden text-white">
      {/* Header */}
      <header className="border-b border-white/10 p-4 bg-[#0d0d0d]/90 backdrop-blur-md flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-lg shadow-lg shadow-indigo-600/20">
            <Camera className="w-6 h-6" />
          </div>
          <div>
            <h1 className="text-lg font-bold tracking-tight text-indigo-50">Cinematic Studio</h1>
            <p className="text-[8px] text-white/40 uppercase tracking-[0.2em] font-bold">Pro AI Production</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {!state.isReviewingPrompt && !state.generatedImage && (
            <button
              onClick={handleGeneratePrompt}
              disabled={state.isGeneratingPrompt}
              className="flex items-center gap-2 px-6 py-2.5 rounded-full text-sm font-bold bg-indigo-600 hover:bg-indigo-500 transition-all shadow-lg shadow-indigo-500/20 disabled:opacity-50"
            >
              {state.isGeneratingPrompt ? <Loader2 className="w-4 h-4 animate-spin" /> : <Wand2 className="w-4 h-4" />}
              <span>{state.isGeneratingPrompt ? 'Analyzing Stage...' : 'Build Scene'}</span>
            </button>
          )}

          {state.isReviewingPrompt && (
            <button onClick={handleFinalRender} className="flex items-center gap-2 px-6 py-2.5 rounded-full text-sm font-bold bg-emerald-600 hover:bg-emerald-500 shadow-lg shadow-emerald-500/20 animate-pulse">
              <Check className="w-4 h-4" />
              <span>Finalize & Render</span>
            </button>
          )}

          {state.generatedImage && (
            <button onClick={() => setState(prev => ({ ...prev, generatedImage: undefined, isReviewingPrompt: false }))} className="flex items-center gap-2 px-6 py-2.5 rounded-full text-sm font-semibold bg-white/10 hover:bg-white/20">
              <RotateCw className="w-4 h-4" />
              <span>Reset Studio</span>
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 flex flex-col lg:flex-row overflow-hidden">
        {/* Main Viewport */}
        <section className="flex-1 bg-black relative flex items-center justify-center p-8 overflow-hidden">
          <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at center, #312e81 0%, transparent 70%)' }}></div>

          {!state.isReviewingPrompt && !state.isGeneratingPrompt && !state.isGenerating && !state.generatedImage && (
            <div className="text-center max-w-sm">
              <div className="w-20 h-20 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-6 border border-white/10">
                <Monitor className="w-8 h-8 text-white/20" />
              </div>
              <h3 className="text-xl font-bold mb-2 text-white/90 tracking-tight">Stage Ready</h3>
              <p className="text-white/40 text-sm font-medium">Configure assets and blocking to start rendering.</p>
            </div>
          )}

          {state.isReviewingPrompt && (
            <div className="w-full max-w-3xl bg-[#0d0d0d] border border-white/10 rounded-3xl p-8 shadow-2xl animate-in fade-in zoom-in-95 z-10 flex flex-col max-h-[90%]">
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-3">
                  <button 
                    onClick={() => setPromptView('text')}
                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all ${promptView === 'text' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'bg-white/5 text-white/40 hover:text-white/60'}`}
                  >
                    <FileText className="w-3.5 h-3.5" /> Technical Script
                  </button>
                  <button 
                    onClick={() => setPromptView('json')}
                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all ${promptView === 'json' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'bg-white/5 text-white/40 hover:text-white/60'}`}
                  >
                    <Code2 className="w-3.5 h-3.5" /> Scene JSON
                  </button>
                </div>

                <button 
                  onClick={handleCopyPrompt}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all ${isCopied ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/20' : 'bg-white/5 text-white/40 hover:text-white/60 border border-transparent'}`}
                >
                  {isCopied ? <Check className="w-3.5 h-3.5" /> : <Copy className="w-3.5 h-3.5" />}
                  {isCopied ? 'Copied!' : 'Copy to Clipboard'}
                </button>
              </div>

              <div className="flex-1 overflow-hidden rounded-2xl border border-white/5 bg-black/40 relative">
                <textarea
                  value={promptView === 'text' ? getDisplayText() : getJsonPrompt()}
                  onChange={(e) => {
                    if (promptView === 'text') {
                      try {
                        const parsed = JSON.parse(state.draftPrompt);
                        parsed.script = e.target.value;
                        setState(prev => ({ ...prev, draftPrompt: JSON.stringify(parsed) }));
                      } catch (err) {
                        setState(prev => ({ ...prev, draftPrompt: e.target.value }));
                      }
                    }
                  }}
                  readOnly={promptView === 'json'}
                  className="w-full h-full p-6 text-sm leading-relaxed font-mono focus:outline-none bg-transparent resize-none overflow-y-auto custom-scrollbar text-indigo-100/80"
                  spellCheck={false}
                />
              </div>

              <div className="mt-8 flex gap-4">
                <button onClick={handleFinalRender} className="flex-1 py-4 bg-indigo-600 rounded-2xl font-bold hover:bg-indigo-500 transition-all shadow-xl shadow-indigo-600/20 text-sm tracking-wide">Render From Camera {state.activeCameraIndex + 1}</button>
                <button onClick={() => setState(prev => ({ ...prev, isReviewingPrompt: false }))} className="px-8 py-4 bg-white/5 rounded-2xl font-bold text-xs uppercase tracking-widest text-white/40 hover:bg-white/10 hover:text-white/60 transition-all">Revise Settings</button>
              </div>
            </div>
          )}

          {state.generatedImage && (
            <div className="relative group max-h-full">
              <img src={state.generatedImage} className="max-h-[80vh] rounded-3xl border border-white/10 shadow-2xl" />
              <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex gap-3 opacity-0 group-hover:opacity-100 transition-all">
                <button onClick={downloadImage} className="flex items-center gap-2 bg-white text-black px-6 py-3 rounded-full font-bold shadow-2xl hover:scale-105 transition-transform"><Download className="w-4 h-4" /> Save 4K</button>
                <button onClick={() => setState(prev => ({ ...prev, generatedImage: undefined }))} className="p-3 bg-red-500/20 text-red-400 rounded-full border border-red-500/20 hover:bg-red-500 hover:text-white transition-all"><Trash2 className="w-6 h-6" /></button>
              </div>
            </div>
          )}

          {(state.isGenerating || state.isGeneratingPrompt) && (
            <div className="flex flex-col items-center gap-6 animate-pulse">
               <div className="w-16 h-16 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin shadow-2xl shadow-indigo-500/20"></div>
               <div className="text-center space-y-2">
                 <p className="text-white/40 font-mono text-[10px] uppercase tracking-widest">Orchestrating scene components...</p>
                 <p className="text-white/20 text-[10px] uppercase font-bold tracking-tighter">Gemini is processing technical optics & light harmony</p>
               </div>
            </div>
          )}
        </section>

        {/* Control Sidebar */}
        <aside className="w-full lg:w-[420px] bg-[#0d0d0d] border-l border-white/10 overflow-y-auto custom-scrollbar">
          <div className="p-6 space-y-10 pb-20">

            {/* Camera Management */}
            <section className="space-y-4">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Camera className="w-4 h-4 text-indigo-400" />
                  <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-white/50">Camera Rig</h2>
                </div>
                <button 
                  onClick={addCamera}
                  disabled={state.cameras.length >= 4}
                  className="p-1.5 bg-indigo-500/10 hover:bg-indigo-500/20 rounded-lg text-indigo-400 disabled:opacity-30 transition-all"
                >
                  <Plus className="w-4 h-4" />
                </button>
              </div>

              <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                {state.cameras.map((cam, idx) => (
                  <button
                    key={cam.id}
                    onClick={() => setState(prev => ({ ...prev, activeCameraIndex: idx }))}
                    className={`flex-shrink-0 px-4 py-2 rounded-xl text-[10px] font-bold transition-all border ${
                      state.activeCameraIndex === idx 
                        ? 'bg-indigo-600 border-indigo-400 text-white shadow-lg shadow-indigo-600/20' 
                        : 'bg-white/5 border-white/10 text-white/40 hover:text-white/60'
                    }`}
                  >
                    CAM {idx + 1}
                  </button>
                ))}
              </div>

