import { GoogleGenAI, Type } from "@google/genai";
import { StudioState, CameraConfig } from "../types";
import { LIGHT_POSITIONS } from "../constants";

/**
 * Robustly downscales images to stay within Gemini API payload limits
 * and prevent "Deadline Exceeded" (RPC error 6) errors.
 */
async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.3): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;

      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));

      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);

      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Image load failed"));
    img.src = dataUrl;
  });
}

const getShotScaleInstructions = (scale: string) => {
  if (scale.includes("Close Up")) return "MANDATORY FRAMING: CLOSE-UP (CU). Shoulder-up framing.";
  if (scale.includes("Medium Shot")) return "MANDATORY FRAMING: MEDIUM SHOT (MS). Waist-up framing.";
  if (scale.includes("Long Shot")) return "MANDATORY FRAMING: LONG SHOT (LS). Full-body framing.";
  if (scale.includes("Wide Shot")) return "MANDATORY FRAMING: WIDE SHOT (WS). Subject small in large environment.";
  return "";
};

export const generateDraftPrompt = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  // Use aggressive downscaling for prompt drafting to avoid RPC timeouts
  for (const slotId of Object.keys(state.references)) {
    const ref = state.references[slotId as keyof typeof state.references];
    if (ref.dataUrl && (state.subjects.activeCount === 2 || !slotId.includes('_b'))) {
      try {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 160, 0.2);
        parts.push({ text: `REFERENCE_${slotId.toUpperCase()}:` });
        parts.push({ inlineData: { data, mimeType } });
      } catch (e) {
        console.warn(`Failed to process reference ${slotId}:`, e);
      }
    }
  }

  const getBlockingDesc = (id: 'a' | 'b') => {
    const config = state.subjects[id];
    const dx = config.x - activeCamera.x;
    const dy = config.y - activeCamera.y;
    const dist = Math.sqrt(dx*dx + dy*dy).toFixed(1);

    const angleToCamRad = Math.atan2(activeCamera.x - config.x, activeCamera.y - config.y);
    const angleToCamDeg = (angleToCamRad * 180 / Math.PI + 360) % 360;

    const rotationDiff = Math.abs(config.rotation - angleToCamDeg);
    const facingDesc = rotationDiff < 20 ? "directly facing the camera" : 
                       rotationDiff > 160 ? "facing directly away from the camera" :
                       "at a profile angle relative to the camera lens";

    return `Subject ${id.toUpperCase()} (Dist: ${dist}): World Rot ${config.rotation}°, Gaze ${config.gaze}°, ${facingDesc}.`;
  };

  const activeLights = state.lighting.positions
    .map((active, i) => active ? LIGHT_POSITIONS[i].label : null)
    .filter(Boolean);

  const systemInstruction = `You are a Senior Cinematic Technical Director.
  Describe the scene POV for an AI renderer based on the active lens at (${activeCamera.x}, ${activeCamera.y}) with rotation ${activeCamera.rotation}°.

  Format: JSON ONLY.
  {
    "script": "Detailed cinematic description including environment expansion.",
    "technical_summary": "Optics notes."
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `CONTEXT:
          Cam: Pos(${activeCamera.x}, ${activeCamera.y}), Rot(${activeCamera.rotation}°)
          Optics: Lens(${activeCamera.lens}), Scale(${activeCamera.shotScale})
          Blocking: ${getBlockingDesc('a')} ${state.subjects.activeCount === 2 ? getBlockingDesc('b') : ''}
          Lights: ${activeLights.join(', ')}` 
        }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 0 }
    }
  });

  return response.text || "";
};

export const generateStudioImage = async (state: StudioState, finalPrompt: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  const addRef = async (id: string, label: string) => {
    const ref = state.references[id as keyof typeof state.references];
    if (ref && ref.dataUrl) {
      try {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.4);
        parts.push({ text: `REFERENCE_${id.toUpperCase()}: ${label}` });
        parts.push({ inlineData: { data, mimeType } });
      } catch (e) {
        console.warn(`Failed to process render reference ${id}:`, e);
      }
    }
  };

  await addRef('background', 'Environment');
  await addRef('char_a', 'Subject A Visuals');
  await addRef('pose_a', 'Subject A Pose');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Subject B Visuals');
    await addRef('pose_b', 'Subject B Pose');
  }
  await addRef('prop', 'Prop');

  const technicalDirective = `DIRECTIVE:
  ${finalPrompt}

  OPTICS:
  - Lens: ${activeCamera.lens}
  - Angle: ${activeCamera.verticalAngle}
  - Framing: ${getShotScaleInstructions(activeCamera.shotScale)}
  - Spatial: Render POV from Cam (${activeCamera.x}, ${activeCamera.y}) rotated ${activeCamera.rotation}°.
  - Aesthetics: Hyper-photorealistic cinematic 8k, raw color, ultra-detailed textures.`;

  parts.push({ text: technicalDirective });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
    config: { 
      imageConfig: { 
        aspectRatio: "16:9" 
      } 
    }
  });

  const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!part?.inlineData) throw new Error("Renderer timed out or failed to return image data. Check your references.");
  return `data:image/png;base64,${part.inlineData.data}`;
};

