  if (scale.includes("Wide Shot")) return "MANDATORY FRAMING: WIDE SHOT (WS). Subject is a small element in a massive landscape.";
  return "";
};

/**
 * Translates raw degree values into relational human descriptions
 */
const getGazeDescription = (subject: SubjectConfig, other: SubjectConfig | null, camera: CameraConfig, label: string) => {
  const getAngleTo = (tx: number, ty: number) => {
    const dx = tx - subject.x;
    const dy = ty - subject.y;
    let angleRad = Math.atan2(dx, dy);
    let angleDeg = (angleRad * 180) / Math.PI;
    return (angleDeg + 360) % 360;
  };

  const angleToCam = getAngleTo(camera.x, camera.y);
  const diffCam = Math.min(Math.abs(subject.gaze - angleToCam), 360 - Math.abs(subject.gaze - angleToCam));

  if (diffCam < 15) return `${label} is LOOKING DIRECTLY INTO THE CAMERA LENS, breaking the fourth wall.`;

  if (other) {
    const angleToPartner = getAngleTo(other.x, other.y);
    const diffPartner = Math.min(Math.abs(subject.gaze - angleToPartner), 360 - Math.abs(subject.gaze - angleToPartner));
    if (diffPartner < 20) return `${label} is LOOKING DIRECTLY AT THEIR PARTNER, maintaining intense eye contact.`;
  }

  // Fallback to cardinal directions relative to camera
  const relativeToCam = (subject.gaze - camera.rotation + 360) % 360;
  if (relativeToCam > 330 || relativeToCam < 30) return `${label} is looking straight ahead past the camera.`;
  if (relativeToCam >= 30 && relativeToCam < 150) return `${label} is looking off to the right of the frame.`;
  if (relativeToCam >= 150 && relativeToCam < 210) return `${label} is looking behind them, away from the scene.`;
  return `${label} is looking off to the left of the frame.`;
};

