import { GoogleGenAI, Type } from "@google/genai";
import { StudioState, CameraConfig, SubjectConfig } from "../types";
import { LIGHT_POSITIONS } from "../constants";

/**
 * Robustly downscales images to stay within Gemini API payload limits
 */
async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.3): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;

      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));

      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);

      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Image load failed"));
    img.src = dataUrl;
  });
}

const getShotScaleInstructions = (scale: string) => {
  if (scale.includes("Close Up")) return "FRAME: CLOSE-UP. Head and shoulders only. High emotional intimacy.";
  if (scale.includes("Medium Shot")) return "FRAME: MEDIUM SHOT. Waist up. Clear interaction with environment.";
  if (scale.includes("Long Shot")) return "FRAME: LONG SHOT. Full body visible. Establishing subject in space.";
  if (scale.includes("Wide Shot")) return "FRAME: WIDE SHOT. Subject is small. Environment is the main focus.";
  return "";
};

