    const dy = ty - subject.y;
    let angleRad = Math.atan2(dx, dy);
    let angleDeg = (angleRad * 180) / Math.PI;
    return (angleDeg + 360) % 360;
  };

  const angleToCam = getAngleTo(camera.x, camera.y);
  const diffCam = Math.min(Math.abs(subject.gaze - angleToCam), 360 - Math.abs(subject.gaze - angleToCam));

  if (diffCam < 20) return `GAZE COMMAND: ${label} must be LOOKING DIRECTLY INTO THE CAMERA LENS. Eyes locked with the viewer.`;

  if (other) {
    const angleToPartner = getAngleTo(other.x, other.y);
    const diffPartner = Math.min(Math.abs(subject.gaze - angleToPartner), 360 - Math.abs(subject.gaze - angleToPartner));
