  if (relativeToCam >= 20 && relativeToCam < 160) return `GAZE COMMAND: ${label} is looking significantly to the RIGHT of the frame.`;
  if (relativeToCam >= 160 && relativeToCam < 200) return `GAZE COMMAND: ${label} is looking directly away from the camera.`;
