const getShotScaleInstructions = (scale: string) => {
  if (scale.includes("Close Up")) return "FRAME: CLOSE-UP. Lens is very tight on subject features. Background is heavily blurred (bokeh).";
  if (scale.includes("Medium Shot")) return "FRAME: MEDIUM SHOT. Waist-up framing. Clear interaction between subject and surrounding objects.";
  if (scale.includes("Long Shot")) return "FRAME: LONG SHOT. Full body visible. The floor and ceiling/sky are part of the composition.";
  if (scale.includes("Wide Shot")) return "FRAME: WIDE SHOT. Subject is small. The environment's architecture and scale are the primary focus.";
  return "";
};

/**
 * Advanced Spatial Reasoning: Translates 2D Floor Plan coordinates into 3D Screen Space
 */
const getSpatialComposition = (state: StudioState, camera: CameraConfig) => {
  const getRelativePosition = (subj: SubjectConfig) => {
    // Basic translation: distance from camera and horizontal offset in the lens field
    const dx = subj.x - camera.x;
    const dy = subj.y - camera.y;

    // Distance (Z-Depth)
    const distance = Math.sqrt(dx*dx + dy*dy);

    // Angle from camera to subject
    const angleToSub = (Math.atan2(dx, dy) * 180 / Math.PI + 360) % 360;

    // Relative angle within the camera's FOV
    let relAngle = (angleToSub - camera.rotation + 540) % 360 - 180;

    const depthDesc = distance < 30 ? "Extreme Foreground" : distance < 60 ? "Foreground" : distance < 100 ? "Midground" : "Background";
    const screenSide = relAngle < -15 ? "Left Third" : relAngle > 15 ? "Right Third" : "Center Frame";

    return { depthDesc, screenSide, distance, relAngle };
  };

  const aComp = getRelativePosition(state.subjects.a);
  const bComp = state.subjects.activeCount === 2 ? getRelativePosition(state.subjects.b) : null;

  let composition = `COMPOSITION: Subject A is in the ${aComp.depthDesc} on the ${aComp.screenSide}. `;
  if (bComp) {
    composition += `Subject B is in the ${bComp.depthDesc} on the ${bComp.screenSide}. `;
    const distBetween = Math.sqrt(Math.pow(state.subjects.a.x - state.subjects.b.x, 2) + Math.pow(state.subjects.a.y - state.subjects.b.y, 2));
    composition += `They are approximately ${distBetween.toFixed(0)} units apart. `;
  }

  return composition;
};

const getGazeInstruction = (subj: SubjectConfig, other: SubjectConfig | null, camera: CameraConfig, label: string) => {
  const getAngleTo = (tx: number, ty: number) => {
    const dx = tx - subj.x;
    const dy = ty - subj.y;
    return (Math.atan2(dx, dy) * 180 / Math.PI + 360) % 360;
  };

  const angleToCam = getAngleTo(camera.x, camera.y);
  const camDiff = Math.min(Math.abs(subj.gaze - angleToCam), 360 - Math.abs(subj.gaze - angleToCam));

  if (camDiff < 20) return `GAZE: ${label} is looking STRAIGHT INTO THE LENS. Breaking the fourth wall with absolute eye contact.`;

  if (other) {
    const angleToPartner = getAngleTo(other.x, other.y);
    const partnerDiff = Math.min(Math.abs(subj.gaze - angleToPartner), 360 - Math.abs(subj.gaze - angleToPartner));
    if (partnerDiff < 30) return `GAZE: ${label} is looking DIRECTLY AT THE OTHER CHARACTER. Intimate eye contact. Ignore any other gaze in references.`;
  }

  return `GAZE: ${label} is looking off-camera at a ${subj.gaze}° angle relative to the world North.`;
};

