          <div className="p-4 space-y-8">
            <section>
              <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
                <Layers className="w-3.5 h-3.5 text-indigo-400" />
                <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40">Studio Assets</h2>
              </div>
              <div className="grid grid-cols-2 gap-2">
                {(REFERENCE_SLOTS.filter(s => {
                  if (s.id.includes('_b') && state.subjects.activeCount < 2) return false;
                  return true;
                })).map((slot) => (
                  <ReferenceUploader
                    key={slot.id}
                    slot={slot}
                    dataUrl={state.references[slot.id].dataUrl}
                    onUpload={(data, mime) => handleUpload(slot.id, data, mime)}
                    onRemove={() => setState(prev => ({ ...prev, references: { ...prev.references, [slot.id]: { ...prev.references[slot.id], dataUrl: undefined } } }))}
                  />
                ))}
              </div>
            </section>

            <section>
