import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Camera } from 'lucide-react';
import { SubjectConfig, CameraConfig } from '../types';

interface FloorPlannerProps {
  subjectA: SubjectConfig;
  subjectB: SubjectConfig;
  activeCount: 1 | 2;
  cameras: CameraConfig[];
  activeCameraIndex: number;
  onUpdateSubject: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  subjectA, 
  subjectB, 
  activeCount, 
  cameras, 
  activeCameraIndex,
  onUpdateSubject,
  onUpdateCamera,
  onSelectCamera
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragState, setDragState] = useState<{ type: 'subject' | 'camera'; id: any } | null>(null);

  const handlersRef = useRef({ onUpdateSubject, onUpdateCamera, onSelectCamera });
  useEffect(() => {
    handlersRef.current = { onUpdateSubject, onUpdateCamera, onSelectCamera };
  }, [onUpdateSubject, onUpdateCamera, onSelectCamera]);

  const getFovAngle = (lens: string) => {
    const mmMatch = lens.match(/(\d+)mm/);
    const mm = mmMatch ? parseInt(mmMatch[1]) : 50;
    return 2 * Math.atan(18 / mm) * (180 / Math.PI);
  };

  const startDrag = (type: 'subject' | 'camera', id: any) => (e: React.MouseEvent | React.TouchEvent) => {
    if (e.cancelable) e.preventDefault();
    e.stopPropagation();

    if (type === 'camera') handlersRef.current.onSelectCamera(id as number);
    setDragState({ type, id });
  };

  const handleMove = useCallback((clientX: number, clientY: number) => {
    if (!dragState || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const normX = (clientX - rect.left) / rect.width;
    const normY = (clientY - rect.top) / rect.height;

    const x = Math.max(-100, Math.min(100, normX * 200 - 100));
    const y = Math.max(0, Math.min(100, (1 - normY) * 100));

    if (dragState.type === 'subject') {
      handlersRef.current.onUpdateSubject(dragState.id, { x, y });
    } else {
      handlersRef.current.onUpdateCamera(dragState.id, { x, y });
    }
  }, [dragState]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    handleMove(e.clientX, e.clientY);
  }, [handleMove]);

  const onTouchMove = useCallback((e: TouchEvent) => {
    if (e.touches.length > 0) {
      handleMove(e.touches[0].clientX, e.touches[0].clientY);
    }
  }, [handleMove]);

  const endDrag = useCallback(() => {
    setDragState(null);
  }, []);

  useEffect(() => {
    if (dragState) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', endDrag);
      window.addEventListener('touchmove', onTouchMove, { passive: false });
      window.addEventListener('touchend', endDrag);
      window.addEventListener('touchcancel', endDrag);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', endDrag);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('touchend', endDrag);
      window.removeEventListener('touchcancel', endDrag);
    };
  }, [dragState, onMouseMove, onTouchMove, endDrag]);

  const renderSubject = (id: 'a' | 'b', config: SubjectConfig) => {
    const left = `${((config.x + 100) / 200) * 100}%`;
    const top = `${100 - config.y}%`;
    const isDragging = dragState?.type === 'subject' && dragState.id === id;

    return (
      <div 
        key={id}
        onMouseDown={startDrag('subject', id)}
        onTouchStart={startDrag('subject', id)}
        style={{ left, top }}
        className="absolute -translate-x-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing z-20 group select-none touch-none"
      >
        <div className={`relative w-16 h-16 flex items-center justify-center transition-all ${isDragging ? 'scale-125' : 'hover:scale-110'}`}>
          <div 
            className="absolute inset-0 transition-transform duration-200"
            style={{ transform: `rotate(${config.rotation}deg)` }}
          >
            <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-2xl">
              <ellipse cx="50" cy="50" rx="38" ry="20" fill={id === 'a' ? 'rgba(99, 102, 241, 0.4)' : 'rgba(168, 85, 247, 0.4)'} stroke={id === 'a' ? '#6366f1' : '#a855f7'} strokeWidth="5" />
              <circle cx="50" cy="50" r="16" fill={id === 'a' ? '#6366f1' : '#a855f7'} />
              <path d="M44 42 L50 30 L56 42 Z" fill={id === 'a' ? '#818cf8' : '#c084fc'} />
            </svg>
          </div>
          <div 
            className="absolute inset-0 pointer-events-none transition-transform duration-200"
            style={{ transform: `rotate(${config.gaze}deg)` }}
          >
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[220%] flex flex-col items-center">
                <div className="w-1 h-10 bg-gradient-to-t from-emerald-500 to-transparent rounded-full opacity-60"></div>
                <div className="w-2.5 h-2.5 bg-emerald-400 rounded-full -mt-2 shadow-[0_0_12px_rgba(52,211,153,0.8)] border border-emerald-200/20"></div>
             </div>
          </div>
          <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-black/60 px-2 py-0.5 rounded-lg border border-white/5 text-[8px] font-black uppercase text-white/60 tracking-widest whitespace-nowrap">
            ACTOR {id.toUpperCase()}
          </div>
        </div>
      </div>
    );
  };

  const renderCamera = (cam: CameraConfig, index: number) => {
    const left = `${((cam.x + 100) / 200) * 100}%`;
    const top = `${100 - cam.y}%`;
    const isActive = activeCameraIndex === index;
    const fov = getFovAngle(cam.lens);

    return (
      <div 
        key={cam.id}
        style={{ left, top }}
        onMouseDown={startDrag('camera', index)}
        onTouchStart={startDrag('camera', index)}
        className={`absolute -translate-x-1/2 -translate-y-1/2 select-none group cursor-grab active:cursor-grabbing touch-none ${isActive ? 'z-40' : 'z-20'}`}
      >
        <div 
          className="absolute top-1/2 left-1/2 pointer-events-none transition-all duration-300 flex items-center justify-center"
          style={{ 
            transform: `translate(-50%, -50%) rotate(${cam.rotation}deg)`, 
            opacity: isActive ? 0.4 : 0.1,
            width: '800px',
            height: '800px'
          }}
        >
          <svg viewBox="0 0 800 800" className="w-full h-full overflow-visible">
             <path 
                d={`M 400 400 L ${400 - Math.tan((fov / 2) * Math.PI / 180) * 400} 0 L ${400 + Math.tan((fov / 2) * Math.PI / 180) * 400} 0 Z`} 
                fill="url(#fovGradientLarge)"
              />
          </svg>
        </div>

        <div className={`relative p-3.5 rounded-2xl border transition-all duration-300 ${isActive ? 'bg-indigo-600 border-indigo-300 shadow-2xl scale-125' : 'bg-[#111] border-white/10 hover:border-white/30 opacity-60'}`}>
          <div className="transition-transform duration-200" style={{ transform: `rotate(${cam.rotation}deg)` }}>
            <Camera className="w-5 h-5 text-white" />
          </div>
          <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 bg-[#0d0d0d] px-2 py-0.5 rounded-lg text-[9px] font-black text-white/60 uppercase whitespace-nowrap tracking-widest border border-white/5">
            NODE {index + 1}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="w-full h-full relative flex flex-col">
      <div className="flex items-center justify-between mb-4 px-2">
        <h2 className="text-[11px] font-black uppercase tracking-[0.3em] text-white/40">Studio Floor Plan</h2>
        <div className="flex gap-4 text-[9px] font-black text-white/20 uppercase tracking-widest">
          <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-indigo-500"></div> Stage Active</span>
          <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div> Gaze Vectors Live</span>
        </div>
      </div>

      <div 
        ref={containerRef}
        className="flex-1 bg-[#050505] rounded-[3rem] border border-white/5 overflow-hidden shadow-[inset_0_0_100px_rgba(0,0,0,0.9)] cursor-crosshair relative select-none"
      >
        <svg className="absolute w-0 h-0">
          <defs>
            <linearGradient id="fovGradientLarge" x1="0.5" y1="1" x2="0.5" y2="0">
              <stop offset="0%" stopColor="#818cf8" stopOpacity="0.8" />
              <stop offset="100%" stopColor="#6366f1" stopOpacity="0" />
            </linearGradient>
          </defs>
        </svg>

        {/* Deep Background Visual Guide */}
        <div className="absolute inset-0 opacity-[0.03]" style={{ backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', backgroundSize: '40px 40px' }}></div>
        <div className="absolute inset-0 pointer-events-none bg-gradient-to-t from-indigo-500/[0.02] to-transparent"></div>

        {/* Depth Markers */}
        <div className="absolute left-6 inset-y-0 flex flex-col justify-between py-10 pointer-events-none opacity-20">
           <span className="text-[7px] font-black text-white uppercase tracking-widest -rotate-90">Deep Background</span>
           <span className="text-[7px] font-black text-white uppercase tracking-widest -rotate-90">Midground</span>
           <span className="text-[7px] font-black text-white uppercase tracking-widest -rotate-90">Forestage</span>
        </div>

        {renderSubject('a', subjectA)}
        {activeCount === 2 && renderSubject('b', subjectB)}
        {cameras.map((cam, idx) => renderCamera(cam, idx))}
      </div>
    </div>
  );
};

