import { GoogleGenAI, Type } from "@google/genai";
import { StudioState, CameraConfig, SubjectConfig } from "../types";
import { LIGHT_POSITIONS } from "../constants";

/**
 * Robustly downscales images to stay within Gemini API payload limits
 */
async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.3): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;

      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));

      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);

      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Image load failed"));
    img.src = dataUrl;
  });
}

const getShotScaleInstructions = (scale: string) => {
  if (scale.includes("Close Up")) return "FRAME: CLOSE-UP (CU). Lens is tight on the subject. Shallow depth of field.";
  if (scale.includes("Medium Shot")) return "FRAME: MEDIUM SHOT (MS). Waist-up framing.";
  if (scale.includes("Long Shot")) return "FRAME: LONG SHOT (LS). Full body visible within the environment.";
  if (scale.includes("Wide Shot")) return "FRAME: WIDE SHOT (WS). Subject is a smaller part of a vast landscape.";
  return "";
};

/**
 * Translates subject rotation relative to camera into human-readable body orientation
 */
const getOrientationInstruction = (subj: SubjectConfig, camera: CameraConfig, label: string) => {
  // Normalize angles to 0-360
  const camRot = (camera.rotation + 360) % 360;
  const subjRot = (subj.rotation + 360) % 360;

  // Relative angle: 0 means facing exactly where the camera is looking (back to camera)
  // 180 means facing exactly at the camera
  const relativeAngle = (subjRot - camRot + 540) % 360;

  if (relativeAngle > 165 && relativeAngle < 195) return `${label} BODY ORIENTATION: Full-frontal, facing directly TOWARD the lens.`;
  if (relativeAngle >= 195 && relativeAngle < 255) return `${label} BODY ORIENTATION: Three-quarter view, angled towards the RIGHT of the frame.`;
  if (relativeAngle >= 255 && relativeAngle < 285) return `${label} BODY ORIENTATION: Pure profile, facing the RIGHT edge of the frame.`;
  if (relativeAngle >= 285 && relativeAngle < 345) return `${label} BODY ORIENTATION: Turned away, angled towards the back-right.`;
  if (relativeAngle >= 345 || relativeAngle < 15) return `${label} BODY ORIENTATION: BACK-TO-CAMERA, facing directly away from the lens.`;
  if (relativeAngle >= 15 && relativeAngle < 75) return `${label} BODY ORIENTATION: Turned away, angled towards the back-left.`;
  if (relativeAngle >= 75 && relativeAngle < 105) return `${label} BODY ORIENTATION: Pure profile, facing the LEFT edge of the frame.`;
  return `${label} BODY ORIENTATION: Three-quarter view, angled towards the LEFT of the frame.`;
};

const getGazeInstruction = (subj: SubjectConfig, other: SubjectConfig | null, camera: CameraConfig, label: string) => {
  const getAngleTo = (tx: number, ty: number) => {
    const dx = tx - subj.x;
    const dy = ty - subj.y;
    return (Math.atan2(dx, dy) * 180 / Math.PI + 360) % 360;
  };

  const angleToCam = getAngleTo(camera.x, camera.y);
  const camDiff = Math.min(Math.abs(subj.gaze - angleToCam), 360 - Math.abs(subj.gaze - angleToCam));

  if (camDiff < 20) return `${label} GAZE: LOOKING DIRECTLY INTO THE CAMERA LENS. Eyes locked with the viewer.`;

  if (other) {
    const angleToPartner = getAngleTo(other.x, other.y);
    const partnerDiff = Math.min(Math.abs(subj.gaze - angleToPartner), 360 - Math.abs(subj.gaze - angleToPartner));
    if (partnerDiff < 25) return `${label} GAZE: LOOKING DIRECTLY AT THEIR PARTNER. Intense eye contact.`;
  }

  // Relative gaze to body
  const bodyGazeDiff = (subj.gaze - subj.rotation + 540) % 360 - 180;
  if (Math.abs(bodyGazeDiff) < 15) return `${label} GAZE: Looking straight ahead relative to their body posture.`;
  if (bodyGazeDiff > 0) return `${label} GAZE: Head is turned significantly to their LEFT.`;
  return `${label} GAZE: Head is turned significantly to their RIGHT.`;
};

const getSpatialComposition = (state: StudioState, camera: CameraConfig) => {
  const getRelativePosition = (subj: SubjectConfig) => {
    const dx = subj.x - camera.x;
    const dy = subj.y - camera.y;
    const distance = Math.sqrt(dx*dx + dy*dy);
    const angleToSub = (Math.atan2(dx, dy) * 180 / Math.PI + 360) % 360;
    const relAngle = (angleToSub - camera.rotation + 540) % 360 - 180;

    // Y coord in floor planner is 0-100 (100 being furthest away)
    const depthDesc = subj.y > 80 ? "Deep Background (far distance)" : subj.y > 50 ? "Mid-distance" : subj.y > 20 ? "Foreground" : "Extreme Foreground (close to lens)";
    const screenSide = relAngle < -15 ? "Left of Frame" : relAngle > 15 ? "Right of Frame" : "Center of Frame";

    return { depthDesc, screenSide, distance };
  };

  const aComp = getRelativePosition(state.subjects.a);
  const bComp = state.subjects.activeCount === 2 ? getRelativePosition(state.subjects.b) : null;

  let composition = `SPATIAL MAPPING: Subject A is in the ${aComp.depthDesc} on the ${aComp.screenSide}. `;
  if (bComp) {
    composition += `Subject B is in the ${bComp.depthDesc} on the ${bComp.screenSide}. `;
  }

  return composition;
};

export const generateDraftPrompt = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  for (const slotId of Object.keys(state.references)) {
    const ref = state.references[slotId as keyof typeof state.references];
    if (ref.dataUrl && (state.subjects.activeCount === 2 || !slotId.includes('_b'))) {
      try {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 200, 0.2);
        parts.push({ text: `REFERENCE_${slotId.toUpperCase()}:` });
        parts.push({ inlineData: { data, mimeType } });
      } catch (e) {
        console.warn(`Failed to process reference ${slotId}:`, e);
      }
    }
  }

  const composition = getSpatialComposition(state, activeCamera);
  const orientA = getOrientationInstruction(state.subjects.a, activeCamera, "Subject A");
  const orientB = state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "Subject B") : "";
  const gazeA = getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "Subject A");
  const gazeB = state.subjects.activeCount === 2 ? getGazeInstruction(state.subjects.b, state.subjects.a, activeCamera, "Subject B") : "";

  const systemInstruction = `You are a Technical Director for a high-end CGI/Photography studio. 
  Your mission is to produce a JSON-based cinematic script that translates a 3D floor plan into a unified visual description.

  CRITICAL COMMANDS:
  1. IGNORE POSE REFERENCES FOR DIRECTION: You must use the provided orientations and gazes. If the reference pose is facing left but the technical data says "Back-to-camera", the FINAL description MUST say "Back-to-camera".
  2. SPATIAL CONSISTENCY: Ensure all elements occupy the same 3D world space. 
  3. BACKGROUND: Treat 'REFERENCE_BACKGROUND' as textures/mood. Re-render the perspective based on the camera coordinates.

  OUTPUT FORMAT: JSON ONLY
  {
    "script": "A detailed paragraph for an image generator focusing on: Unified environment, Camera POV, Lighting, Precise body orientation, and Head/Eye gaze directions.",
    "technical_summary": "Notes on how stage geometry was applied."
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `STAGE SPECIFICATIONS:
          Camera Node: ${state.activeCameraIndex + 1} (${activeCamera.model}, ${activeCamera.lens}, ${activeCamera.shotScale})
          Position: (${activeCamera.x}, ${activeCamera.y}), Tilt: ${activeCamera.verticalAngle}

          ${composition}

          SUBJECT A:
          - ${orientA}
          - ${gazeA}

          SUBJECT B:
          - ${orientB}
          - ${gazeB}

          LIGHTING: ${state.lighting.positions.map((on, i) => on ? LIGHT_POSITIONS[i].label : null).filter(Boolean).join(', ') || 'Natural'}` }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json"
    }
  });

  return response.text || "";
};

export const generateStudioImage = async (state: StudioState, draftJsonString: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  let script = "";

  try {
    const parsed = JSON.parse(draftJsonString);
    script = parsed.script || draftJsonString;
  } catch(e) {
    script = draftJsonString;
  }

  const parts: any[] = [];

  const addRef = async (id: string, role: string) => {
    const ref = state.references[id as keyof typeof state.references];
    if (ref && ref.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.4);
      parts.push({ text: `### [ASSET: ${id.toUpperCase()} | ROLE: ${role}] ###` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  await addRef('background', 'Environment texture and style swatch. RE-PROJECT PERSPECTIVE.');
  await addRef('char_a', 'Visual identity of Subject A');
  await addRef('pose_a', 'Body silhouette of Subject A. IGNORE ITS ORIGINAL DIRECTION.');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Visual identity of Subject B');
    await addRef('pose_b', 'Body silhouette of Subject B. IGNORE ITS ORIGINAL DIRECTION.');
  }
  await addRef('prop', 'Scene object');

  const composition = getSpatialComposition(state, activeCamera);
  const orientA = getOrientationInstruction(state.subjects.a, activeCamera, "Subject A");
  const orientB = state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "Subject B") : "";
  const gazeA = getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "Subject A");
  const gazeB = state.subjects.activeCount === 2 ? getGazeInstruction(state.subjects.b, state.subjects.a, activeCamera, "Subject B") : "";

  const finalDirective = `### MANDATORY PHOTOGRAPHY COMMANDS (OVERRIDE ALL REFERENCES) ###

  1. **VIEWPOINT**: Camera at (${activeCamera.x}, ${activeCamera.y}) rotated ${activeCamera.rotation}°. Tilt: ${activeCamera.verticalAngle}.
  2. **SPATIAL BLOCKING**: ${composition}
  3. **SUBJECT A ORIENTATION**: ${orientA} 
  4. **SUBJECT A GAZE**: ${gazeA} (Absolute eye-direction override)
  5. **SUBJECT B ORIENTATION**: ${orientB}
  6. **SUBJECT B GAZE**: ${gazeB} (Absolute eye-direction override)
  7. **OPTICS**: ${activeCamera.model}, ${activeCamera.lens}, ${getShotScaleInstructions(activeCamera.shotScale)}
  8. **INTEGRATION SCRIPT**: ${script}

  **STYLING**: Hyper-realistic, 8k, volumetric lighting, Arri Alexa color grade.`;

  parts.push({ text: finalDirective });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Renderer failed to interpret conflicting geometry.");
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Camera } from 'lucide-react';
import { SubjectConfig, CameraConfig } from '../types';

interface FloorPlannerProps {
  subjectA: SubjectConfig;
  subjectB: SubjectConfig;
  activeCount: 1 | 2;
  cameras: CameraConfig[];
  activeCameraIndex: number;
  onUpdateSubject: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  subjectA, 
  subjectB, 
  activeCount, 
  cameras, 
  activeCameraIndex,
  onUpdateSubject,
  onUpdateCamera,
  onSelectCamera
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragState, setDragState] = useState<{ type: 'subject' | 'camera'; id: any } | null>(null);

  const handlersRef = useRef({ onUpdateSubject, onUpdateCamera, onSelectCamera });
  useEffect(() => {
    handlersRef.current = { onUpdateSubject, onUpdateCamera, onSelectCamera };
  }, [onUpdateSubject, onUpdateCamera, onSelectCamera]);

  const getFovAngle = (lens: string) => {
    const mmMatch = lens.match(/(\d+)mm/);
    const mm = mmMatch ? parseInt(mmMatch[1]) : 50;
    return 2 * Math.atan(18 / mm) * (180 / Math.PI);
  };

  const startDrag = (type: 'subject' | 'camera', id: any) => (e: React.MouseEvent | React.TouchEvent) => {
    if (e.cancelable) e.preventDefault();
    e.stopPropagation();

    if (type === 'camera') handlersRef.current.onSelectCamera(id as number);
    setDragState({ type, id });
  };

  const handleMove = useCallback((clientX: number, clientY: number) => {
    if (!dragState || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const normX = (clientX - rect.left) / rect.width;
    const normY = (clientY - rect.top) / rect.height;

    // Support wide X placement (-100 to 100) and Y placement (0 to 100)
    const x = Math.max(-100, Math.min(100, normX * 200 - 100));
    const y = Math.max(0, Math.min(100, (1 - normY) * 100));

    if (dragState.type === 'subject') {
      handlersRef.current.onUpdateSubject(dragState.id, { x, y });
    } else {
      handlersRef.current.onUpdateCamera(dragState.id, { x, y });
    }
  }, [dragState]);

  const onMouseMove = useCallback((e: MouseEvent) => {
    handleMove(e.clientX, e.clientY);
  }, [handleMove]);

  const onTouchMove = useCallback((e: TouchEvent) => {
    if (e.touches.length > 0) {
      handleMove(e.touches[0].clientX, e.touches[0].clientY);
    }
  }, [handleMove]);

  const endDrag = useCallback(() => {
    setDragState(null);
  }, []);

  useEffect(() => {
    if (dragState) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', endDrag);
      window.addEventListener('touchmove', onTouchMove, { passive: false });
      window.addEventListener('touchend', endDrag);
      window.addEventListener('touchcancel', endDrag);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', endDrag);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('touchend', endDrag);
      window.removeEventListener('touchcancel', endDrag);
    };
  }, [dragState, onMouseMove, onTouchMove, endDrag]);

  const renderSubject = (id: 'a' | 'b', config: SubjectConfig) => {
    const left = `${((config.x + 100) / 200) * 100}%`;
    const top = `${100 - config.y}%`;
    const isDragging = dragState?.type === 'subject' && dragState.id === id;

    return (
      <div 
        key={id}
        onMouseDown={startDrag('subject', id)}
        onTouchStart={startDrag('subject', id)}
        style={{ left, top }}
        className="absolute -translate-x-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing z-20 group select-none touch-none"
      >
        <div className={`relative w-16 h-16 flex items-center justify-center transition-all ${isDragging ? 'scale-125' : 'hover:scale-110'}`}>
          <div 
            className="absolute inset-0 transition-transform duration-200"
            style={{ transform: `rotate(${config.rotation}deg)` }}
          >
            <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-2xl">
              <ellipse cx="50" cy="50" rx="38" ry="20" fill={id === 'a' ? 'rgba(99, 102, 241, 0.4)' : 'rgba(168, 85, 247, 0.4)'} stroke={id === 'a' ? '#6366f1' : '#a855f7'} strokeWidth="5" />
              <circle cx="50" cy="50" r="16" fill={id === 'a' ? '#6366f1' : '#a855f7'} />
              <path d="M44 42 L50 30 L56 42 Z" fill={id === 'a' ? '#818cf8' : '#c084fc'} />
            </svg>
          </div>
          <div 
            className="absolute inset-0 pointer-events-none transition-transform duration-200"
            style={{ transform: `rotate(${config.gaze}deg)` }}
          >
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[220%] flex flex-col items-center">
                <div className="w-1 h-10 bg-gradient-to-t from-emerald-500 to-transparent rounded-full opacity-60"></div>
                <div className="w-2.5 h-2.5 bg-emerald-400 rounded-full -mt-2 shadow-[0_0_12px_rgba(52,211,153,0.8)] border border-emerald-200/20"></div>
             </div>
          </div>
          <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-black/60 px-2 py-0.5 rounded-lg border border-white/5 text-[8px] font-black uppercase text-white/60 tracking-widest whitespace-nowrap">
            ACTOR {id.toUpperCase()}
          </div>
        </div>
      </div>
    );
  };

  const renderCamera = (cam: CameraConfig, index: number) => {
    const left = `${((cam.x + 100) / 200) * 100}%`;
    const top = `${100 - cam.y}%`;
    const isActive = activeCameraIndex === index;
    const fov = getFovAngle(cam.lens);

    return (
      <div 
        key={cam.id}
        style={{ left, top }}
        onMouseDown={startDrag('camera', index)}
        onTouchStart={startDrag('camera', index)}
        className={`absolute -translate-x-1/2 -translate-y-1/2 select-none group cursor-grab active:cursor-grabbing touch-none ${isActive ? 'z-40' : 'z-20'}`}
      >
        <div 
          className="absolute top-1/2 left-1/2 pointer-events-none transition-all duration-300 flex items-center justify-center"
          style={{ 
            transform: `translate(-50%, -50%) rotate(${cam.rotation}deg)`, 
            opacity: isActive ? 0.4 : 0.1,
            width: '1200px',
            height: '1200px'
          }}
        >
          <svg viewBox="0 0 1200 1200" className="w-full h-full overflow-visible">
             <path 
                d={`M 600 600 L ${600 - Math.tan((fov / 2) * Math.PI / 180) * 600} 0 L ${600 + Math.tan((fov / 2) * Math.PI / 180) * 600} 0 Z`} 
                fill="url(#fovGradientLarge)"
              />
          </svg>
        </div>

        <div className={`relative p-3.5 rounded-2xl border transition-all duration-300 ${isActive ? 'bg-indigo-600 border-indigo-300 shadow-2xl scale-125' : 'bg-[#111] border-white/10 hover:border-white/30 opacity-60'}`}>
          <div className="transition-transform duration-200" style={{ transform: `rotate(${cam.rotation}deg)` }}>
            <Camera className="w-5 h-5 text-white" />
          </div>
          <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 bg-[#0d0d0d] px-2 py-0.5 rounded-lg text-[9px] font-black text-white/60 uppercase whitespace-nowrap tracking-widest border border-white/5">
            NODE {index + 1}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="w-full h-full relative flex flex-col">
      <div className="flex items-center justify-between mb-4 px-2">
        <h2 className="text-[11px] font-black uppercase tracking-[0.3em] text-white/40">Studio Floor Plan</h2>
        <div className="flex gap-4 text-[9px] font-black text-white/20 uppercase tracking-widest">
          <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-indigo-500"></div> Stage Active</span>
          <span className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div> Gaze Vectors Live</span>
        </div>
      </div>

      <div 
        ref={containerRef}
        className="flex-1 bg-[#050505] rounded-[3rem] border border-white/5 overflow-hidden shadow-[inset_0_0_100px_rgba(0,0,0,0.9)] cursor-crosshair relative select-none"
      >
        <svg className="absolute w-0 h-0">
          <defs>
            <linearGradient id="fovGradientLarge" x1="0.5" y1="1" x2="0.5" y2="0">
              <stop offset="0%" stopColor="#818cf8" stopOpacity="0.8" />
              <stop offset="100%" stopColor="#6366f1" stopOpacity="0" />
            </linearGradient>
          </defs>
        </svg>

        {/* Visual Zones */}
        <div className="absolute top-0 left-0 right-0 h-1/4 bg-indigo-500/[0.03] border-b border-white/5 pointer-events-none"></div>
        <div className="absolute top-1/4 left-0 right-0 h-1/4 bg-indigo-500/[0.01] border-b border-white/5 pointer-events-none"></div>

        {/* Deep Background Visual Guide */}
        <div className="absolute inset-0 opacity-[0.03]" style={{ backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', backgroundSize: '40px 40px' }}></div>
        <div className="absolute inset-0 pointer-events-none bg-gradient-to-t from-indigo-500/[0.02] to-transparent"></div>

        {/* Depth Markers */}
        <div className="absolute left-6 inset-y-0 flex flex-col justify-between py-10 pointer-events-none opacity-20">
           <span className="text-[7px] font-black text-white uppercase tracking-widest -rotate-90">Deep Background (100)</span>
           <span className="text-[7px] font-black text-white uppercase tracking-widest -rotate-90">Midground (50)</span>
           <span className="text-[7px] font-black text-white uppercase tracking-widest -rotate-90">Forestage (0)</span>
        </div>

        {renderSubject('a', subjectA)}
        {activeCount === 2 && renderSubject('b', subjectB)}
        {cameras.map((cam, idx) => renderCamera(cam, idx))}
      </div>
    </div>
  );
};

export default FloorPlanner;

import { GoogleGenAI, Type } from "@google/genai";
import { StudioState, CameraConfig, SubjectConfig } from "../types";
import { LIGHT_POSITIONS } from "../constants";

/**
 * Robustly downscales images to stay within Gemini API payload limits
 */
async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.3): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;

      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));

      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);

      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Image load failed"));
    img.src = dataUrl;
  });
}

const getShotScaleInstructions = (scale: string) => {
  if (scale.includes("Close Up")) return "Tight Framing: Focus on facial features and head. Shallow bokeh.";
  if (scale.includes("Medium Shot")) return "Standard Framing: Waist-up composition.";
  if (scale.includes("Long Shot")) return "Establishing Framing: Full body visible, environment establishes context.";
  if (scale.includes("Wide Shot")) return "Environmental Framing: Subject is a small figure in a large space.";
  return "";
};

/**
 * Calculates absolute body orientation relative to the camera view
 */
const getOrientationInstruction = (subj: SubjectConfig, camera: CameraConfig, label: string) => {
  const camRot = (camera.rotation + 360) % 360;
  const subjRot = (subj.rotation + 360) % 360;

  // 180 means facing camera, 0 means back to camera
  const relativeAngle = (subjRot - camRot + 540) % 360;

  if (relativeAngle > 160 && relativeAngle < 200) return `STRICT BODY POSTURE: ${label} is facing DIRECTLY FRONT-ON towards the camera. Both shoulders are visible and square to the lens.`;
  if (relativeAngle >= 200 && relativeAngle < 250) return `STRICT BODY POSTURE: ${label} is in a THREE-QUARTER profile, turned towards the RIGHT of the frame.`;
  if (relativeAngle >= 250 && relativeAngle < 290) return `STRICT BODY POSTURE: ${label} is in a TOTAL SIDE-PROFILE, facing the RIGHT edge of the frame. Only one shoulder is visible to the camera.`;
  if (relativeAngle >= 290 && relativeAngle < 340) return `STRICT BODY POSTURE: ${label} is turned away, showing their back-right shoulder to the camera.`;
  if (relativeAngle >= 340 || relativeAngle < 20) return `STRICT BODY POSTURE: ${label} is facing COMPLETELY AWAY from the camera (Back-to-Lens). The camera sees only their back and the back of their head.`;
  if (relativeAngle >= 20 && relativeAngle < 70) return `STRICT BODY POSTURE: ${label} is turned away, showing their back-left shoulder to the camera.`;
  if (relativeAngle >= 70 && relativeAngle < 110) return `STRICT BODY POSTURE: ${label} is in a TOTAL SIDE-PROFILE, facing the LEFT edge of the frame. Only one shoulder is visible to the camera.`;
  return `STRICT BODY POSTURE: ${label} is in a THREE-QUARTER profile, turned towards the LEFT of the frame.`;
};

/**
 * Calculates gaze direction and provides explicit screen-space and relative-to-body instructions
 */
const getGazeInstruction = (subj: SubjectConfig, other: SubjectConfig | null, camera: CameraConfig, label: string) => {
  const getAngleTo = (tx: number, ty: number) => {
    const dx = tx - subj.x;
    const dy = ty - subj.y;
    return (Math.atan2(dx, dy) * 180 / Math.PI + 360) % 360;
  };

  const angleToCam = getAngleTo(camera.x, camera.y);
  const camDiff = Math.min(Math.abs(subj.gaze - angleToCam), 360 - Math.abs(subj.gaze - angleToCam));

  // Check if looking at camera
  if (camDiff < 20) return `CRITICAL GAZE: ${label}'s eyes are locked ON THE CAMERA LENS. Absolute eye contact with the viewer.`;

  // Check if looking at partner
  if (other) {
    const angleToPartner = getAngleTo(other.x, other.y);
    const partnerDiff = Math.min(Math.abs(subj.gaze - angleToPartner), 360 - Math.abs(subj.gaze - angleToPartner));
    if (partnerDiff < 25) return `CRITICAL GAZE: ${label} is looking INTENSELY AT THEIR PARTNER. Eyes are focused on the other character's face.`;
  }

  // Calculate screen-space gaze
  const relGazeToCam = (subj.gaze - camera.rotation + 540) % 360 - 180;
  if (relGazeToCam < -20) return `CRITICAL GAZE: ${label} is looking significantly towards the LEFT side of the image frame. Their head and eyes are turned away from the lens.`;
  if (relGazeToCam > 20) return `CRITICAL GAZE: ${label} is looking significantly towards the RIGHT side of the image frame. Their head and eyes are turned away from the lens.`;

  return `CRITICAL GAZE: ${label} is looking into the distance, past the camera.`;
};

const getSpatialComposition = (state: StudioState, camera: CameraConfig) => {
  const getRelativePosition = (subj: SubjectConfig) => {
    const dx = subj.x - camera.x;
    const dy = subj.y - camera.y;
    const distance = Math.sqrt(dx*dx + dy*dy);
    const angleToSub = (Math.atan2(dx, dy) * 180 / Math.PI + 360) % 360;
    const relAngle = (angleToSub - camera.rotation + 540) % 360 - 180;

    const depthDesc = subj.y > 85 ? "the deepest background near the far wall" : subj.y > 55 ? "the mid-ground" : subj.y > 25 ? "the foreground" : "the extreme foreground, very close to the lens";
    const screenSide = relAngle < -15 ? "the left side of the frame" : relAngle > 15 ? "the right side of the frame" : "the dead center of the frame";

    return { depthDesc, screenSide, distance };
  };

  const aComp = getRelativePosition(state.subjects.a);
  const bComp = state.subjects.activeCount === 2 ? getRelativePosition(state.subjects.b) : null;

  let composition = `BLOCKING: Subject A is positioned in ${aComp.depthDesc}, specifically on ${aComp.screenSide}. `;
  if (bComp) {
    composition += `Subject B is positioned in ${bComp.depthDesc}, specifically on ${bComp.screenSide}. `;
  }

  return composition;
};

export const generateDraftPrompt = async (state: StudioState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  for (const slotId of Object.keys(state.references)) {
    const ref = state.references[slotId as keyof typeof state.references];
    if (ref.dataUrl && (state.subjects.activeCount === 2 || !slotId.includes('_b'))) {
      try {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 240, 0.2);
        parts.push({ text: `REFERENCE_IMAGE_${slotId.toUpperCase()}:` });
        parts.push({ inlineData: { data, mimeType } });
      } catch (e) {
        console.warn(`Failed to process reference ${slotId}:`, e);
      }
    }
  }

  const composition = getSpatialComposition(state, activeCamera);
  const orientA = getOrientationInstruction(state.subjects.a, activeCamera, "Subject A");
  const orientB = state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "Subject B") : "";
  const gazeA = getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "Subject A");
  const gazeB = state.subjects.activeCount === 2 ? getGazeInstruction(state.subjects.b, state.subjects.a, activeCamera, "Subject B") : "";

  const systemInstruction = `You are a Technical Cinematographer. Your job is to describe a scene where the spatial geometry is PARAMOUNT.

  MANDATORY RULES:
  1. IGNORE REFERENCE ORIENTATION: If a pose reference shows someone facing the camera, but the TECHNICAL DATA says "Profile", you MUST describe them in Profile.
  2. NO COLLAGE: This is one single 3D scene.
  3. GAZE IS LAW: Eye direction MUST follow the technical data. Do not default to characters looking at the camera unless explicitly requested.

  OUTPUT: JSON
  {
    "script": "A single technical description. Emphasize body-to-camera orientation (shoulders) and head-to-camera gaze. Force the environment to match the specific camera node perspective.",
    "technical_summary": "Notes on mapping coordinates."
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `TECHNICAL STAGE DATA:
          Viewpoint: Node ${state.activeCameraIndex + 1} (${activeCamera.model})
          Cam Rotation: ${activeCamera.rotation}°, Lens: ${activeCamera.lens}, Tilt: ${activeCamera.verticalAngle}

          ${composition}

          SUBJECT A:
          - ${orientA}
          - ${gazeA}

          SUBJECT B:
          - ${orientB}
          - ${gazeB}

          LIGHTING: ${state.lighting.positions.map((on, i) => on ? LIGHT_POSITIONS[i].label : null).filter(Boolean).join(', ') || 'Global'}` }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json"
    }
  });

  return response.text || "";
};

export const generateStudioImage = async (state: StudioState, draftJsonString: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  let script = "";

  try {
    const parsed = JSON.parse(draftJsonString);
    script = parsed.script || draftJsonString;
  } catch(e) {
    script = draftJsonString;
  }

  const parts: any[] = [];

  const addRef = async (id: string, description: string) => {
    const ref = state.references[id as keyof typeof state.references];
    if (ref && ref.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
      parts.push({ text: `[ASSET: ${id.toUpperCase()} - ROLE: ${description}]` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  await addRef('background', 'ENVIRONMENT TEXTURE AND STYLE ONLY. DISREGARD ORIGINAL CAMERA ANGLE.');
  await addRef('char_a', 'Visual ID for Subject A');
  await addRef('pose_a', 'SKELETAL POSE REFERENCE FOR SUBJECT A. IGNORE HEAD/EYE DIRECTION IN THIS IMAGE.');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Visual ID for Subject B');
    await addRef('pose_b', 'SKELETAL POSE REFERENCE FOR SUBJECT B. IGNORE HEAD/EYE DIRECTION IN THIS IMAGE.');
  }
  await addRef('prop', 'Object details');

  const composition = getSpatialComposition(state, activeCamera);
  const orientA = getOrientationInstruction(state.subjects.a, activeCamera, "Subject A");
  const orientB = state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "Subject B") : "";
  const gazeA = getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "Subject A");
  const gazeB = state.subjects.activeCount === 2 ? getGazeInstruction(state.subjects.b, state.subjects.a, activeCamera, "Subject B") : "";

  // The Atomic Prompt: Short, punchy, capitalized overrides to beat the "camera-facing" bias.
  const atomicPrompt = `
  ### MANDATORY SPATIAL DIRECTIVES - OVERRIDE ALL REFERENCE POSES ###

  1. CAMERA POV: Viewpoint is at stage coordinate (${activeCamera.x}, ${activeCamera.y}) looking at ${activeCamera.rotation}°.
  2. COMPOSITION: ${composition}

  3. SUBJECT A PHYSICALITY:
     - SHOULDERS/BODY: ${orientA}
     - HEAD/EYES: ${gazeA} (IMPORTANT: Do NOT look at camera unless instructed)

  4. SUBJECT B PHYSICALITY:
     - SHOULDERS/BODY: ${orientB}
     - HEAD/EYES: ${gazeB} (IMPORTANT: Do NOT look at camera unless instructed)

  5. ENVIRONMENT: Re-project the background texture to match the ${activeCamera.rotation}° camera rotation.

  6. OPTICS: Shot using ${activeCamera.model} with ${activeCamera.lens}. ${getShotScaleInstructions(activeCamera.shotScale)}

  7. SCRIPT: ${script}

  FINAL STYLE: Ultra-detailed cinematic photography, volumetric atmosphere, photorealistic skin textures, 8k resolution.`;

  parts.push({ text: atomicPrompt });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Image Generation Failed. Check spatial constraints.");
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

export type ReferenceType = 
  | 'background' 
  | 'char_a' | 'pose_a' 
  | 'char_b' | 'pose_b' 
  | 'prop';

export interface ReferenceImage {
  id: ReferenceType;
  label: string;
  dataUrl?: string;
  mimeType?: string;
}

export interface SubjectConfig {
  x: number; // -200 to 200 (Expanded)
  y: number; // 0 to 200 (Expanded)
  rotation: number; // Body rotation 0-360
  gaze: number; // Head/Eye rotation 0-360
}

export interface CameraConfig {
  id: string;
  x: number;
  y: number;
  rotation: number;
  model: string;
  lens: string;
  verticalAngle: string;
}

export interface StudioState {
  references: Record<ReferenceType, ReferenceImage>;
  lighting: {
    positions: boolean[];
  };
  subjects: {
    a: SubjectConfig;
    b: SubjectConfig;
    activeCount: 1 | 2;
  };
  cameras: CameraConfig[];
  activeCameraIndex: number;
  isGenerating: boolean;
  isGeneratingPrompt: boolean;
  isReviewingPrompt: boolean;
  draftPrompt: string;
  generatedImage?: string;
  plannerZoom: number; // Zoom level for the stage
}

import { ReferenceType } from './types';

export const REFERENCE_SLOTS: { id: ReferenceType; label: string; group: string }[] = [
  { id: 'background', label: 'Environment', group: 'Global' },
  { id: 'prop', label: 'Scene Prop', group: 'Global' },
  { id: 'char_a', label: 'Subject A', group: 'Subject A' },
  { id: 'pose_a', label: 'Pose A', group: 'Subject A' },
  { id: 'char_b', label: 'Subject B', group: 'Subject B' },
  { id: 'pose_b', label: 'Pose B', group: 'Subject B' },
];

export const CAMERA_MODELS = [
  "Arri Alexa 35",
  "Sony A7R V",
  "RED V-RAPTOR XL",
  "Blackmagic URSA Mini"
];

export const LENSES = [
  { label: "24mm f/1.4 (Wide)", mm: 24 },
  { label: "35mm f/1.4 (Storyteller)", mm: 35 },
  { label: "50mm f/1.2 (Natural)", mm: 50 },
  { label: "85mm f/1.4 (Portrait)", mm: 85 }
];

export const VERTICAL_ANGLES = [
  "Low Angle (Worm's Eye)",
  "Eye Level",
  "High Angle",
  "Bird's Eye (Top-Down)"
];

export const LIGHT_POSITIONS = [
  { label: 'Front', angle: 0 },
  { label: 'Front-Right', angle: 45 },
  { label: 'Right', angle: 90 },
  { label: 'Back-Right', angle: 135 },
  { label: 'Back', angle: 180 },
  { label: 'Back-Left', angle: 225 },
  { label: 'Left', angle: 270 },
  { label: 'Front-Left', angle: 315 },
];

import React, { useState, useMemo } from 'react';
import { Camera, Layers, Sun, Trash2, Wand2, Loader2, Settings2, Copy, Check, X, RotateCw, UserPlus, UserMinus, Compass, Eye, Plus, Maximize2, ExternalLink, ZoomIn, ZoomOut } from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage, SubjectConfig, CameraConfig } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, LIGHT_POSITIONS, VERTICAL_ANGLES } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import LightRig from './components/LightRig';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import { generateDraftPrompt, generateStudioImage } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    subjects: {
      a: { x: -30, y: 50, rotation: 180, gaze: 180 },
      b: { x: 40, y: 80, rotation: 180, gaze: 180 },
      activeCount: 1,
    },
    cameras: [
      {
        id: 'cam-1',
        x: 0,
        y: 10,
        rotation: 0,
        model: CAMERA_MODELS[0],
        lens: LENSES[1].label,
        verticalAngle: VERTICAL_ANGLES[1],
      }
    ],
    activeCameraIndex: 0,
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    draftPrompt: '',
    plannerZoom: 1.0,
  });

  const activeCamera = state.cameras[state.activeCameraIndex];
  const [promptView, setPromptView] = useState<'text' | 'json'>('text');
  const [isCopied, setIsCopied] = useState(false);

  // Inferred Shot Scale based on physics
  const inferredShotScale = useMemo(() => {
    const mm = LENSES.find(l => l.label === activeCamera.lens)?.mm || 50;
    const dx = state.subjects.a.x - activeCamera.x;
    const dy = state.subjects.a.y - activeCamera.y;
    const dist = Math.sqrt(dx * dx + dy * dy);

    // Simple heuristic: framing factor
    const factor = (dist * 10) / mm;
    if (factor < 5) return "Extreme Close Up (ECU)";
    if (factor < 12) return "Close Up (CU)";
    if (factor < 25) return "Medium Shot (MS)";
    if (factor < 45) return "Long Shot (LS)";
    return "Wide Shot (WS)";
  }, [activeCamera, state.subjects.a]);

  const handleUpload = (type: ReferenceType, dataUrl: string, mimeType: string) => {
    setState(prev => ({
      ...prev,
      references: { ...prev.references, [type]: { ...prev.references[type], dataUrl, mimeType } }
    }));
  };

  const updateSubject = (id: 'a' | 'b', updates: Partial<SubjectConfig>) => {
    setState(prev => ({
      ...prev,
      subjects: {
        ...prev.subjects,
        [id]: { ...prev.subjects[id], ...updates }
      }
    }));
  };

  const updateCamera = (index: number, updates: Partial<CameraConfig>) => {
    setState(prev => {
      const newCameras = [...prev.cameras];
      newCameras[index] = { ...newCameras[index], ...updates };
      return { ...prev, cameras: newCameras };
    });
  };

  const addCamera = () => {
    if (state.cameras.length >= 4) return;
    const newCam: CameraConfig = {
      ...activeCamera,
      id: `cam-${Date.now()}`,
      x: activeCamera.x + 40,
      y: activeCamera.y
    };
    setState(prev => ({
      ...prev,
      cameras: [...prev.cameras, newCam],
      activeCameraIndex: prev.cameras.length
    }));
  };

  const handleGeneratePrompt = async () => {
    setState(prev => ({ ...prev, isGeneratingPrompt: true }));
    try {
      const prompt = await generateDraftPrompt({ ...state, inferredShotScale });
      setState(prev => ({ ...prev, draftPrompt: prompt, isGeneratingPrompt: false, isReviewingPrompt: true }));
    } catch (err: any) {
      console.error(err);
      setState(prev => ({ ...prev, isGeneratingPrompt: false }));
    }
  };

  const handleFinalRender = async () => {
    setState(prev => ({ ...prev, isGenerating: true, isReviewingPrompt: false }));
    try {
      const result = await generateStudioImage({ ...state, inferredShotScale }, state.draftPrompt);
      setState(prev => ({ ...prev, generatedImage: result, isGenerating: false }));
    } catch (err: any) {
      console.error(err);
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const getJsonPrompt = () => {
    try {
      const aiResponse = JSON.parse(state.draftPrompt);
      const fullState = {
        scene_config: {
          subjects: state.subjects,
          active_camera: activeCamera,
          shot_scale: inferredShotScale,
          lighting: state.lighting.positions.map((on, i) => on ? LIGHT_POSITIONS[i].label : null).filter(Boolean),
        },
        ai_script: aiResponse
      };
      return JSON.stringify(fullState, null, 2);
    } catch (e) {
      return JSON.stringify({ error: "Invalid JSON structure", raw: state.draftPrompt }, null, 2);
    }
  };

  const getDisplayText = () => {
    try {
      const parsed = JSON.parse(state.draftPrompt);
      return parsed.script || state.draftPrompt;
    } catch (e) {
      return state.draftPrompt;
    }
  };

  const openImageInNewWindow = () => {
    if (!state.generatedImage) return;
    const newWindow = window.open();
    if (newWindow) {
      newWindow.document.write(`
        <body style="margin:0; background:#000; display:flex; align-items:center; justify-content:center;">
          <img src="${state.generatedImage}" style="max-width:100%; max-height:100%; border:1px solid #333;" />
        </body>
      `);
    }
  };

  return (
    <div className="min-h-screen bg-[#080808] flex flex-col overflow-hidden text-white">
      <header className="border-b border-white/5 p-3 bg-[#0a0a0a]/95 backdrop-blur-md flex items-center justify-between sticky top-0 z-[100]">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600/20 p-2 rounded-xl border border-indigo-500/20">
            <Camera className="w-5 h-5 text-indigo-400" />
          </div>
          <div className="hidden sm:block">
            <h1 className="text-sm font-black tracking-tight text-white uppercase">Studio Console V2</h1>
            <p className="text-[9px] text-white/30 uppercase tracking-[0.3em] font-bold">Physics-Based Production</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {!state.isReviewingPrompt && !state.generatedImage && (
            <button
              onClick={handleGeneratePrompt}
              disabled={state.isGeneratingPrompt}
              className="flex items-center gap-2 px-6 py-2 rounded-xl text-xs font-black bg-indigo-600 hover:bg-indigo-500 transition-all shadow-lg shadow-indigo-600/20 disabled:opacity-50 uppercase tracking-widest"
            >
              {state.isGeneratingPrompt ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Wand2 className="w-3.5 h-3.5" />}
              <span>{state.isGeneratingPrompt ? 'Calculated Framing...' : 'Prepare Render'}</span>
            </button>
          )}

          {state.isReviewingPrompt && (
            <button onClick={handleFinalRender} className="flex items-center gap-2 px-6 py-2 rounded-xl text-xs font-black bg-emerald-600 hover:bg-emerald-500 shadow-lg shadow-emerald-500/20 animate-pulse uppercase tracking-widest">
              <Check className="w-3.5 h-3.5" />
              <span>Initiate Render</span>
            </button>
          )}

          {state.generatedImage && (
            <button onClick={() => setState(prev => ({ ...prev, generatedImage: undefined, isReviewingPrompt: false }))} className="flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-black bg-white/5 hover:bg-white/10 uppercase tracking-widest border border-white/5">
              <RotateCw className="w-3.5 h-3.5" />
              <span>Reset Scene</span>
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 flex overflow-hidden">
        <aside className="w-72 bg-[#0a0a0a] border-r border-white/5 flex flex-col shrink-0 custom-scrollbar overflow-y-auto">
          <div className="p-4 space-y-8">
            <section>
              <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
                <Layers className="w-3.5 h-3.5 text-indigo-400" />
                <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40">Assets</h2>
              </div>
              <div className="grid grid-cols-2 gap-2">
                {(REFERENCE_SLOTS.filter(s => state.subjects.activeCount === 2 || !s.id.includes('_b'))).map((slot) => (
                  <ReferenceUploader
                    key={slot.id}
                    slot={slot}
                    dataUrl={state.references[slot.id].dataUrl}
                    onUpload={(data, mime) => handleUpload(slot.id, data, mime)}
                    onRemove={() => setState(prev => ({ ...prev, references: { ...prev.references, [slot.id]: { ...prev.references[slot.id], dataUrl: undefined } } }))}
                  />
                ))}
              </div>
            </section>

            <section>
              <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
                <Sun className="w-3.5 h-3.5 text-amber-400" />
                <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40">Light Rig</h2>
              </div>
              <div className="bg-black/20 rounded-2xl p-4 border border-white/5">
                <LightRig 
                  activePositions={state.lighting.positions}
                  onToggle={(i) => setState(prev => {
                    const next = [...prev.lighting.positions];
                    next[i] = !next[i];
                    return { ...prev, lighting: { positions: next } };
                  })}
                  orientation={state.subjects.a.rotation} 
                />
              </div>
            </section>
          </div>
        </aside>

        <section className="flex-1 bg-black relative flex flex-col overflow-hidden">
          {/* Zoom Controls */}
          <div className="absolute top-6 left-6 z-[160] flex flex-col gap-2">
             <button onClick={() => setState(p => ({...p, plannerZoom: Math.min(3, p.plannerZoom + 0.2)}))} className="p-2 bg-[#0d0d0d] border border-white/10 rounded-xl text-white/40 hover:text-white hover:bg-white/5 transition-all">
               <ZoomIn className="w-4 h-4" />
             </button>
             <button onClick={() => setState(p => ({...p, plannerZoom: Math.max(0.5, p.plannerZoom - 0.2)}))} className="p-2 bg-[#0d0d0d] border border-white/10 rounded-xl text-white/40 hover:text-white hover:bg-white/5 transition-all">
               <ZoomOut className="w-4 h-4" />
             </button>
             <div className="bg-indigo-500/10 border border-indigo-500/20 px-2 py-1 rounded-lg text-[8px] font-black text-indigo-400 text-center uppercase tracking-widest">
                {Math.round(state.plannerZoom * 100)}%
             </div>
          </div>

          <div className="flex-1 relative flex items-center justify-center p-8">
             <FloorPlanner 
                state={state}
                onUpdateSubject={updateSubject}
                onUpdateCamera={updateCamera}
                onSelectCamera={(idx) => setState(prev => ({ ...prev, activeCameraIndex: idx }))}
             />

             {/* Dynamic Shot Info Overlay */}
             <div className="absolute top-6 left-1/2 -translate-x-1/2 bg-[#0d0d0d]/80 backdrop-blur-xl border border-white/10 px-6 py-2.5 rounded-2xl shadow-2xl flex items-center gap-4 animate-in slide-in-from-top-4 duration-500">
                <div className="flex flex-col">
                   <span className="text-[8px] font-black text-white/30 uppercase tracking-[0.2em]">Inferred Scale</span>
                   <span className="text-xs font-black text-white uppercase tracking-widest">{inferredShotScale}</span>
                </div>
                <div className="w-px h-8 bg-white/5"></div>
                <div className="flex flex-col">
                   <span className="text-[8px] font-black text-white/30 uppercase tracking-[0.2em]">Optics</span>
                   <span className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest">{activeCamera.lens}</span>
                </div>
             </div>

             {/* UI Overlays */}
             {(state.isGenerating || state.isGeneratingPrompt) && (
                <div className="absolute inset-0 bg-black/60 backdrop-blur-sm z-[200] flex flex-col items-center justify-center gap-6">
                  <div className="relative">
                    <div className="w-20 h-20 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin"></div>
                    <div className="absolute inset-0 flex items-center justify-center">
                      <Wand2 className="w-6 h-6 text-indigo-400 animate-pulse" />
                    </div>
                  </div>
                  <p className="text-sm font-black uppercase tracking-[0.3em] text-white">Synthesizing Physics...</p>
                </div>
             )}

             {state.isReviewingPrompt && (
                <div className="absolute inset-0 bg-black/80 backdrop-blur-lg z-[200] flex items-center justify-center p-8">
                  <div className="w-full max-w-4xl bg-[#0d0d0d] border border-white/10 rounded-[2.5rem] p-8 shadow-2xl flex flex-col max-h-[90%] overflow-hidden">
                    <div className="flex items-center justify-between mb-8">
                      <div className="flex gap-2">
                        <button onClick={() => setPromptView('text')} className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${promptView === 'text' ? 'bg-indigo-600' : 'bg-white/5 text-white/40'}`}>Script</button>
                        <button onClick={() => setPromptView('json')} className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${promptView === 'json' ? 'bg-indigo-600' : 'bg-white/5 text-white/40'}`}>Stage Data</button>
                      </div>
                      <button onClick={() => setState(prev => ({ ...prev, isReviewingPrompt: false }))} className="p-2 bg-white/5 rounded-xl text-white/40"><X className="w-5 h-5" /></button>
                    </div>
                    <textarea
                      readOnly={promptView === 'json'}
                      value={promptView === 'text' ? getDisplayText() : getJsonPrompt()}
                      className="flex-1 bg-black/40 rounded-3xl p-8 text-sm font-mono border border-white/5 focus:outline-none resize-none custom-scrollbar"
                    />
                    <button onClick={handleFinalRender} className="mt-8 py-4 bg-indigo-600 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-indigo-500 transition-all">Generate Final Render</button>
                  </div>
                </div>
             )}

             {state.generatedImage && (
                <div className="absolute top-6 right-6 z-[150] animate-in slide-in-from-right duration-500">
                   <div className="relative group">
                      <div className="w-56 aspect-video rounded-2xl overflow-hidden border border-white/10 shadow-2xl cursor-pointer" onClick={openImageInNewWindow}>
                        <img src={state.generatedImage} className="w-full h-full object-cover transition-transform group-hover:scale-105" />
                        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                           <Maximize2 className="w-6 h-6 text-white" />
                        </div>
                      </div>
                      <button onClick={() => setState(prev => ({ ...prev, generatedImage: undefined }))} className="absolute -top-3 -right-3 p-2 bg-red-600 text-white rounded-lg shadow-xl"><Trash2 className="w-3 h-3" /></button>
                   </div>
                </div>
             )}
          </div>

          {/* Bottom Controls */}
          <div className="p-8 grid grid-cols-2 gap-8 pointer-events-none relative z-[100]">
             <div className="bg-[#0a0a0a]/80 backdrop-blur-xl p-6 rounded-[2rem] border border-white/5 pointer-events-auto">
                <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
                   <Compass className="w-4 h-4 text-indigo-400" />
                   <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40">Body Rotation</h2>
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <OrientationSlider config={state.subjects.a} activeCamera={activeCamera} onChange={(val) => updateSubject('a', { rotation: val })} />
                   {state.subjects.activeCount === 2 ? (
                      <OrientationSlider config={state.subjects.b} activeCamera={activeCamera} onChange={(val) => updateSubject('b', { rotation: val })} />
                   ) : <div className="flex items-center justify-center text-[8px] text-white/10 italic">Sub B Offline</div>}
                </div>
             </div>

             <div className="bg-[#0a0a0a]/80 backdrop-blur-xl p-6 rounded-[2rem] border border-white/5 pointer-events-auto">
                <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
                   <Eye className="w-4 h-4 text-emerald-400" />
                   <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40">Gaze Vectoring</h2>
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <GazeSelector subjectId="a" config={state.subjects.a} activeCamera={activeCamera} onChange={(val) => updateSubject('a', { gaze: val })} />
                   {state.subjects.activeCount === 2 ? (
                      <GazeSelector subjectId="b" config={state.subjects.b} activeCamera={activeCamera} otherSubject={state.subjects.a} onChange={(val) => updateSubject('b', { gaze: val })} />
                   ) : <div className="flex items-center justify-center text-[8px] text-white/10 italic">Sub B Offline</div>}
                </div>
             </div>
          </div>
        </section>

        <aside className="w-80 bg-[#0a0a0a] border-l border-white/5 flex flex-col shrink-0 custom-scrollbar overflow-y-auto">
          <div className="p-4 space-y-8">
            <section className="space-y-4">
              <div className="flex items-center justify-between border-b border-white/5 pb-2">
                <div className="flex items-center gap-2">
                  <Camera className="w-3.5 h-3.5 text-indigo-400" />
                  <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40">Cameras</h2>
                </div>
                <button onClick={addCamera} disabled={state.cameras.length >= 4} className="p-1.5 bg-indigo-500/10 rounded-lg text-indigo-400"><Plus className="w-3.5 h-3.5" /></button>
              </div>
              <div className="grid grid-cols-2 gap-2">
                {state.cameras.map((cam, idx) => (
                  <button key={cam.id} onClick={() => setState(prev => ({ ...prev, activeCameraIndex: idx }))} className={`px-3 py-2 rounded-xl text-[10px] font-black border transition-all ${state.activeCameraIndex === idx ? 'bg-indigo-600 border-indigo-400' : 'bg-white/5 border-white/10 text-white/30'}`}>CAM {idx + 1}</button>
                ))}
              </div>
            </section>

            <section className="space-y-6">
              <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
                <Settings2 className="w-3.5 h-3.5 text-indigo-400" />
                <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40">Lens & Body</h2>
              </div>

              <div className="space-y-4">
                <div className="space-y-2">
                   <label className="text-[9px] font-black text-white/30 uppercase tracking-widest ml-1">Focal Length</label>
                   <select value={activeCamera.lens} onChange={(e) => updateCamera(state.activeCameraIndex, { lens: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs text-white/60 appearance-none">
                     {LENSES.map(l => <option key={l.label} value={l.label} className="bg-[#0d0d0d]">{l.label}</option>)}
                   </select>
                </div>
                <div className="space-y-2">
                   <label className="text-[9px] font-black text-white/30 uppercase tracking-widest ml-1">Verticality</label>
                   <select value={activeCamera.verticalAngle} onChange={(e) => updateCamera(state.activeCameraIndex, { verticalAngle: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs text-white/60 appearance-none">
                     {VERTICAL_ANGLES.map(a => <option key={a} value={a} className="bg-[#0d0d0d]">{a}</option>)}
                   </select>
                </div>
              </div>

              <div className="p-4 bg-white/5 rounded-2xl border border-white/5 space-y-4">
                <label className="text-[9px] text-white/30 uppercase tracking-widest font-black">Subject Count</label>
                <div className="flex gap-2 p-1 bg-black rounded-xl">
                  <button onClick={() => setState(prev => ({ ...prev, subjects: { ...prev.subjects, activeCount: 1 } }))} className={`flex-1 py-2 rounded-lg text-[9px] font-black transition-all ${state.subjects.activeCount === 1 ? 'bg-indigo-600' : 'text-white/20'}`}>SOLO</button>
                  <button onClick={() => setState(prev => ({ ...prev, subjects: { ...prev.subjects, activeCount: 2 } }))} className={`flex-1 py-2 rounded-lg text-[9px] font-black transition-all ${state.subjects.activeCount === 2 ? 'bg-indigo-600' : 'text-white/20'}`}>DUO</button>
                </div>
              </div>

              <div className="space-y-3">
                <label className="text-[9px] text-white/30 uppercase tracking-widest font-black ml-1">Stage Axis</label>
                <div className="bg-white/5 p-4 rounded-xl border border-white/5 flex items-center gap-4">
                  <input type="range" min="0" max="360" value={activeCamera.rotation} onChange={(e) => updateCamera(state.activeCameraIndex, { rotation: parseInt(e.target.value) })} className="flex-1 h-1 bg-white/10 appearance-none accent-indigo-500" />
                  <span className="text-[10px] font-mono text-indigo-400 font-bold">{activeCamera.rotation}°</span>
                </div>
              </div>
            </section>
          </div>
        </aside>
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Camera, RotateCcw } from 'lucide-react';
import { StudioState, SubjectConfig, CameraConfig } from '../types';

interface FloorPlannerProps {
  state: StudioState;
  onUpdateSubject: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  state,
  onUpdateSubject,
  onUpdateCamera,
  onSelectCamera
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragState, setDragState] = useState<{ 
    type: 'move' | 'rotate-body' | 'rotate-gaze' | 'rotate-cam'; 
    target: 'subject' | 'camera';
    id: any;
  } | null>(null);

  const { subjects, cameras, activeCameraIndex, plannerZoom } = state;
  const handlersRef = useRef({ onUpdateSubject, onUpdateCamera, onSelectCamera });
  useEffect(() => {
    handlersRef.current = { onUpdateSubject, onUpdateCamera, onSelectCamera };
  }, [onUpdateSubject, onUpdateCamera, onSelectCamera]);

  const getFovAngle = (lens: string) => {
    const mm = lens.match(/(\d+)mm/);
    const focalLength = mm ? parseInt(mm[1]) : 50;
    return 2 * Math.atan(18 / focalLength) * (180 / Math.PI);
  };

  const startDrag = (type: any, target: any, id: any) => (e: React.MouseEvent | React.TouchEvent) => {
    if (e.cancelable) e.preventDefault();
    e.stopPropagation();

    if (target === 'camera' && type === 'move') handlersRef.current.onSelectCamera(id as number);
    setDragState({ type, target, id });
  };

  const handleInteraction = useCallback((clientX: number, clientY: number) => {
    if (!dragState || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();

    // Convert client pixels to coordinate space based on zoom
    const centerX = rect.width / 2;
    const centerY = rect.height / 2;
    const pxPerUnit = (rect.width / 400) * plannerZoom; // Coordinate space is -200 to 200 (400 width)

    const mouseRelX = (clientX - rect.left - centerX) / pxPerUnit;
    const mouseRelY = -(clientY - rect.top - centerY) / pxPerUnit; // Y is 0 at center, up is positive in logic? 
    // Let's stick to the existing y=0 at camera baseline, y=200 deep
    // Actual logic: 
    // NormY = 0 to 1 -> CoordY = 200 to 0
    const coordX = (clientX - rect.left - rect.width / 2) / (rect.width / 400 * plannerZoom);
    const coordY = (1 - (clientY - rect.top) / rect.height) * 200 / plannerZoom;

    if (dragState.type === 'move') {
      const boundedX = Math.max(-200, Math.min(200, coordX));
      const boundedY = Math.max(0, Math.min(200, coordY));
      if (dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { x: boundedX, y: boundedY });
      } else {
        handlersRef.current.onUpdateCamera(dragState.id, { x: boundedX, y: boundedY });
      }
    } else {
      // Rotation logic
      const targetObj = dragState.target === 'subject' ? subjects[dragState.id as 'a' | 'b'] : cameras[dragState.id];
      const objScreenX = rect.left + rect.width / 2 + targetObj.x * (rect.width / 400 * plannerZoom);
      const objScreenY = rect.top + (1 - targetObj.y / (200 / plannerZoom)) * rect.height; // approximate

      const dx = clientX - objScreenX;
      const dy = clientY - objScreenY;
      let angle = (Math.atan2(dx, -dy) * 180 / Math.PI + 360) % 360;

      if (dragState.type === 'rotate-body' && dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { rotation: angle });
      } else if (dragState.type === 'rotate-gaze' && dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { gaze: angle });
      } else if (dragState.type === 'rotate-cam' && dragState.target === 'camera') {
        handlersRef.current.onUpdateCamera(dragState.id, { rotation: angle });
      }
    }
  }, [dragState, plannerZoom, subjects, cameras]);

  const onMouseMove = useCallback((e: MouseEvent) => handleInteraction(e.clientX, e.clientY), [handleInteraction]);
  const endDrag = useCallback(() => setDragState(null), []);

  useEffect(() => {
    if (dragState) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', endDrag);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', endDrag);
    };
  }, [dragState, onMouseMove, endDrag]);

  const getStyle = (obj: {x: number, y: number}) => {
    // Mapping -200..200 to 0..100%
    const left = `${((obj.x / plannerZoom + 200) / 400) * 100}%`;
    const top = `${100 - (obj.y / plannerZoom / 200) * 100}%`;
    return { left, top };
  };

  const renderSubject = (id: 'a' | 'b', config: SubjectConfig) => {
    const isDragging = dragState?.target === 'subject' && dragState.id === id;

    return (
      <div 
        key={id}
        style={getStyle(config)}
        className={`absolute -translate-x-1/2 -translate-y-1/2 z-20 group select-none touch-none ${isDragging ? 'z-30' : ''}`}
      >
        <div className="relative w-20 h-20 flex items-center justify-center transition-all">
          {/* Movement Handle */}
          <div onMouseDown={startDrag('move', 'subject', id)} className="absolute inset-4 cursor-grab active:cursor-grabbing rounded-full bg-white/5 border border-white/5 hover:bg-white/10 z-10"></div>

          {/* Body Rotation Handle */}
          <div 
            className="absolute inset-0 transition-transform"
            style={{ transform: `rotate(${config.rotation}deg)` }}
          >
            <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-2xl">
              <ellipse cx="50" cy="50" rx="30" ry="15" fill={id === 'a' ? 'rgba(99, 102, 241, 0.4)' : 'rgba(168, 85, 247, 0.4)'} stroke={id === 'a' ? '#6366f1' : '#a855f7'} strokeWidth="3" />
              <circle cx="50" cy="50" r="12" fill={id === 'a' ? '#6366f1' : '#a855f7'} />
            </svg>
            <div 
              onMouseDown={startDrag('rotate-body', 'subject', id)}
              className="absolute top-2 left-1/2 -translate-x-1/2 w-3 h-3 bg-white rounded-full cursor-alias border-2 border-indigo-500 shadow-xl"
            />
          </div>

          {/* Gaze Handle */}
          <div 
            className="absolute inset-0 pointer-events-none transition-transform"
            style={{ transform: `rotate(${config.gaze}deg)` }}
          >
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[280%] flex flex-col items-center">
                <div className="w-0.5 h-12 bg-gradient-to-t from-emerald-500 to-transparent opacity-60"></div>
                <div 
                  onMouseDown={startDrag('rotate-gaze', 'subject', id)}
                  className="w-4 h-4 bg-emerald-400 rounded-full cursor-alias pointer-events-auto shadow-[0_0_15px_rgba(52,211,153,0.8)] border-2 border-white"
                />
             </div>
          </div>

          <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[7px] font-black uppercase text-white/40 tracking-widest whitespace-nowrap">
            ACTOR {id.toUpperCase()}
          </div>
        </div>
      </div>
    );
  };

  const renderCamera = (cam: CameraConfig, index: number) => {
    const isActive = activeCameraIndex === index;
    const fov = getFovAngle(cam.lens);

    return (
      <div 
        key={cam.id}
        style={getStyle(cam)}
        className={`absolute -translate-x-1/2 -translate-y-1/2 select-none group touch-none ${isActive ? 'z-40' : 'z-20'}`}
      >
        <div 
          className="absolute top-1/2 left-1/2 pointer-events-none transition-all duration-300"
          style={{ 
            transform: `translate(-50%, -50%) rotate(${cam.rotation}deg)`, 
            opacity: isActive ? 0.3 : 0.05,
            width: '1200px',
            height: '1200px'
          }}
        >
          <svg viewBox="0 0 1200 1200" className="w-full h-full overflow-visible">
             <path d={`M 600 600 L ${600 - Math.tan((fov / 2) * Math.PI / 180) * 800} 0 L ${600 + Math.tan((fov / 2) * Math.PI / 180) * 800} 0 Z`} fill="url(#fovGradientPlanner)" />
          </defs>
          </svg>
        </div>

        <div className={`relative p-3 rounded-2xl border transition-all ${isActive ? 'bg-indigo-600 border-indigo-300 scale-125' : 'bg-[#111] border-white/10 opacity-50'}`}>
          <div onMouseDown={startDrag('move', 'camera', index)} className="absolute inset-0 cursor-grab active:cursor-grabbing z-0"></div>
          <div className="relative z-10 transition-transform pointer-events-none" style={{ transform: `rotate(${cam.rotation}deg)` }}>
            <Camera className="w-5 h-5 text-white" />
            <div 
              onMouseDown={startDrag('rotate-cam', 'camera', index)}
              className="absolute top-[-10px] left-1/2 -translate-x-1/2 w-3 h-3 bg-white rounded-full cursor-alias pointer-events-auto border-2 border-indigo-400"
            />
          </div>
          <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 text-[8px] font-black text-white/40 uppercase whitespace-nowrap tracking-widest">
            NODE {index + 1}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-[#050505] rounded-[3rem] border border-white/5 overflow-hidden shadow-[inset_0_0_150px_rgba(0,0,0,0.8)] cursor-crosshair relative select-none"
    >
      <svg className="absolute w-0 h-0">
        <defs>
          <linearGradient id="fovGradientPlanner" x1="0.5" y1="1" x2="0.5" y2="0">
            <stop offset="0%" stopColor="#818cf8" stopOpacity="0.8" />
            <stop offset="100%" stopColor="#6366f1" stopOpacity="0" />
          </linearGradient>
        </defs>
      </svg>

      {/* Expanded Grid System */}
      <div className="absolute inset-0 opacity-[0.03]" style={{ 
        backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', 
        backgroundSize: `${40 * plannerZoom}px ${40 * plannerZoom}px`,
        backgroundPosition: 'center center'
      }}></div>

      {/* Depth Markers */}
      <div className="absolute left-10 inset-y-0 flex flex-col justify-between py-12 pointer-events-none opacity-20">
         <span className="text-[7px] font-black text-white uppercase tracking-[0.4em] -rotate-90">Deep Void (200)</span>
         <span className="text-[7px] font-black text-white uppercase tracking-[0.4em] -rotate-90">Mid Stage (100)</span>
         <span className="text-[7px] font-black text-white uppercase tracking-[0.4em] -rotate-90">Proscenium (0)</span>
      </div>

      {renderSubject('a', subjects.a)}
      {subjects.activeCount === 2 && renderSubject('b', subjects.b)}
      {cameras.map((cam, idx) => renderCamera(cam, idx))}

      {/* Visual Axis Indicator */}
      <div className="absolute bottom-6 right-6 flex items-center gap-4 text-[8px] font-black text-white/10 uppercase tracking-widest">
         <span>Drag edges to rotate</span>
         <div className="w-px h-3 bg-white/5"></div>
         <span>Drag center to move</span>
      </div>
    </div>
  );
};

