import { GoogleGenAI } from "@google/genai";
import { StudioState, CameraConfig, SubjectConfig } from "../types";
import { LIGHT_POSITIONS } from "../constants";

async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.3): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Image load failed"));
    img.src = dataUrl;
  });
}

const getOrientationInstruction = (subj: SubjectConfig, camera: CameraConfig, label: string) => {
  const camRot = (camera.rotation + 360) % 360;
  const subjRot = (subj.rotation + 360) % 360;
  const relativeAngle = (subjRot - camRot + 540) % 360;

  if (relativeAngle > 165 && relativeAngle < 195) return `POSTURE: ${label} faces DIRECTLY AT the camera lens (Frontal).`;
  if (relativeAngle >= 195 && relativeAngle < 255) return `POSTURE: ${label} is in a 3/4 profile, angled towards the frame RIGHT.`;
  if (relativeAngle >= 255 && relativeAngle < 285) return `POSTURE: ${label} is in a pure side profile, facing RIGHT.`;
  if (relativeAngle >= 285 && relativeAngle < 345) return `POSTURE: ${label} is angled away, showing their back-right.`;
  if (relativeAngle >= 345 || relativeAngle < 15) return `POSTURE: ${label} is facing COMPLETELY AWAY from the camera (Back to Lens).`;
  if (relativeAngle >= 15 && relativeAngle < 75) return `POSTURE: ${label} is angled away, showing their back-left.`;
  if (relativeAngle >= 75 && relativeAngle < 105) return `POSTURE: ${label} is in a pure side profile, facing LEFT.`;
  return `POSTURE: ${label} is in a 3/4 profile, angled towards the frame LEFT.`;
};

const getGazeInstruction = (subj: SubjectConfig, other: SubjectConfig | null, camera: CameraConfig, label: string) => {
  const getAngleTo = (tx: number, ty: number) => {
    const dx = tx - subj.x;
    const dy = ty - subj.y;
    return (Math.atan2(dx, dy) * 180 / Math.PI + 360) % 360;
  };

  const angleToCam = getAngleTo(camera.x, camera.y);
  const camDiff = Math.min(Math.abs(subj.gaze - angleToCam), 360 - Math.abs(subj.gaze - angleToCam));

  if (camDiff < 20) return `GAZE: ${label} is looking STRAIGHT INTO THE CAMERA.`;

  if (other) {
    const angleToPartner = getAngleTo(other.x, other.y);
    const partnerDiff = Math.min(Math.abs(subj.gaze - angleToPartner), 360 - Math.abs(subj.gaze - angleToPartner));
    if (partnerDiff < 30) return `GAZE: ${label} is looking directly at the other subject.`;
  }

  const relGazeToCam = (subj.gaze - camera.rotation + 540) % 360 - 180;
  if (relGazeToCam < -20) return `GAZE: ${label} is looking away from the lens towards the LEFT of the frame.`;
  if (relGazeToCam > 20) return `GAZE: ${label} is looking away from the lens towards the RIGHT of the frame.`;
  return `GAZE: ${label} is looking into the distance, away from the camera.`;
};

export const generateDraftPrompt = async (state: any): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  for (const slotId of Object.keys(state.references)) {
    const ref = state.references[slotId];
    if (ref.dataUrl && (state.subjects.activeCount === 2 || !slotId.includes('_b'))) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 200, 0.2);
      parts.push({ text: `REF_${slotId.toUpperCase()}:` });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const systemInstruction = `You are a Technical Cinematographer.
  CRITICAL: You MUST use the Stage Data to define the shot.
  - Body orientation (Shoulders) MUST match the "POSTURE" data.
  - Eye/Head gaze MUST match the "GAZE" data.
  - Ignore the poses in reference images if they conflict with technical data.

  OUTPUT: JSON
  {
    "script": "A cinematic technical script describing the composition, lighting, and character interaction based on the 3D layout.",
    "analysis": "Brief technical explanation of the framing choice."
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `STAGE DATA:
          Shot Scale: ${state.inferredShotScale}
          Optics: ${activeCamera.lens}, ${activeCamera.verticalAngle}
          Camera Stage Coord: (${activeCamera.x}, ${activeCamera.y}), World Rotation: ${activeCamera.rotation}°

          Subject A:
          - ${getOrientationInstruction(state.subjects.a, activeCamera, "Subject A")}
          - ${getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "Subject A")}

          Subject B:
          - ${state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "Subject B") : ""}
          - ${state.subjects.activeCount === 2 ? getGazeInstruction(state.subjects.b, state.subjects.a, activeCamera, "Subject B") : ""}

          Lighting: ${state.lighting.positions.map((on, i) => on ? LIGHT_POSITIONS[i].label : null).filter(Boolean).join(', ') || 'Ambient'}` }
      ] 
    },
    config: { systemInstruction, responseMimeType: "application/json" }
  });
  return response.text || "";
};

export const generateStudioImage = async (state: any, draftJson: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  let script = "";
  try { script = JSON.parse(draftJson).script; } catch(e) { script = draftJson; }

  const parts: any[] = [];
  const addRef = async (id: string, role: string) => {
    const ref = state.references[id];
    if (ref?.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
      parts.push({ text: `[ASSET: ${id.toUpperCase()} - ROLE: ${role}]` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  await addRef('background', 'ENVIRONMENT STYLE ONLY.');
  await addRef('char_a', 'Visual Identity A');
  await addRef('pose_a', 'SKELETAL POSE FOR A (IGNORE DIRECTION)');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Visual Identity B');
    await addRef('pose_b', 'SKELETAL POSE FOR B (IGNORE DIRECTION)');
  }

  const directive = `### MANDATORY PRODUCTION DIRECTIVE ###
  - FRAMING: ${state.inferredShotScale}
  - OPTICS: Shot on ${activeCamera.model} with ${activeCamera.lens}.
  - SUBJECT A: ${getOrientationInstruction(state.subjects.a, activeCamera, "A")} | ${getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "A")}
  - SUBJECT B: ${state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "B") : "N/A"} | ${state.subjects.activeCount === 2 ? getGazeInstruction(state.subjects.b, state.subjects.a, activeCamera, "B") : "N/A"}
  - SCRIPT: ${script}
  - INTEGRATION: Every element must be unified in one 3D space with matching lighting. No collaging.`;

  parts.push({ text: directive });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Image Render Failed.");
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

