/**
 * COORDINATE SYSTEM STANDARD:
 * World X: -200 (Stage Left) to 200 (Stage Right)
 * World Y: 0 (Front/Camera Baseline) to 200 (Deep Background)
 * Rotation: 0° is North (facing Deep Stage), 90° is East (facing Stage Right), 
 *           180° is South (facing Camera), 270° is West (facing Stage Left).
 */

async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.3): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Image load failed"));
    img.src = dataUrl;
  });
}

/**
 * Calculates if a subject is facing the camera, profile, or away relative to the camera's view vector.
 */
const getOrientationInstruction = (subj: SubjectConfig, camera: CameraConfig, label: string) => {
  const subjRot = (subj.rotation + 360) % 360;
  const camRot = (camera.rotation + 360) % 360;

  // Angle of the subject relative to the camera's look direction.
  // 180 means the subject is facing exactly opposite to the camera (Directly Facing Camera)
  // 0 means the subject is facing the same way as the camera (Back to Camera)
  const relativeAngle = (subjRot - camRot + 360) % 360;

  if (relativeAngle > 160 && relativeAngle < 200) return `POSTURE: ${label} is facing DIRECTLY FRONT-ON to the camera lens.`;
  if (relativeAngle >= 200 && relativeAngle < 255) return `POSTURE: ${label} is in a three-quarter view, angled towards the LEFT side of the frame.`;
  if (relativeAngle >= 255 && relativeAngle < 285) return `POSTURE: ${label} is in a PURE PROFILE, facing the LEFT of the frame.`;
  if (relativeAngle >= 285 && relativeAngle < 345) return `POSTURE: ${label} is turned away, angled towards the back-left.`;
  if (relativeAngle >= 345 || relativeAngle < 15) return `POSTURE: ${label} is facing COMPLETELY AWAY from the camera (Back to Lens).`;
  if (relativeAngle >= 15 && relativeAngle < 75) return `POSTURE: ${label} is turned away, angled towards the back-right.`;
  if (relativeAngle >= 75 && relativeAngle < 105) return `POSTURE: ${label} is in a PURE PROFILE, facing the RIGHT of the frame.`;
  return `POSTURE: ${label} is in a three-quarter view, angled towards the RIGHT side of the frame.`;
};

const getGazeInstruction = (subj: SubjectConfig, other: SubjectConfig | null, camera: CameraConfig, label: string) => {
  const getAngleTo = (tx: number, ty: number) => {
    const dx = tx - subj.x;
    const dy = ty - subj.y;
    // World coordinates: atan2(dx, dy) where dy+ is North/Deep
    return (Math.atan2(dx, dy) * 180 / Math.PI + 360) % 360;
  };

  const angleToCam = getAngleTo(camera.x, camera.y);
  const camDiff = Math.min(Math.abs(subj.gaze - angleToCam), 360 - Math.abs(subj.gaze - angleToCam));

  if (camDiff < 15) return `GAZE: ${label} is making direct, intense EYE CONTACT with the camera lens.`;

  if (other) {
    const angleToPartner = getAngleTo(other.x, other.y);
    const partnerDiff = Math.min(Math.abs(subj.gaze - angleToPartner), 360 - Math.abs(subj.gaze - angleToPartner));
    if (partnerDiff < 25) return `GAZE: ${label} is looking directly at the other character.`;
  }

  // Calculate if head is turned left or right relative to body
  const bodyGazeDiff = (subj.gaze - subj.rotation + 540) % 360 - 180;
  if (Math.abs(bodyGazeDiff) < 15) return `GAZE: ${label} is looking straight ahead relative to their body posture.`;
  if (bodyGazeDiff > 0) return `GAZE: ${label} has their head turned towards their LEFT shoulder.`;
  return `GAZE: ${label} has their head turned towards their RIGHT shoulder.`;
};

export const generateDraftPrompt = async (state: any): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  for (const slotId of Object.keys(state.references)) {
    const ref = state.references[slotId];
    if (ref.dataUrl && (state.subjects.activeCount === 2 || !slotId.includes('_b'))) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 240, 0.2);
      parts.push({ text: `REF_${slotId.toUpperCase()}:` });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const systemInstruction = `You are a Technical Cinematographer.
  STAGE COORDINATES: 
  - Proscenium/Front is Y=0.
  - Deep Stage/Back is Y=200.
  - Stage Left is X=-200, Stage Right is X=200.

  MANDATORY: 
  1. IGNORE reference poses if they conflict with technical posture data.
  2. ADHERE to the specified gaze and body orientation.
  3. DESCRIBE the shot based on inferred scale: ${state.inferredShotScale}.

  OUTPUT: JSON
  {
    "script": "Technical description of the scene.",
    "analysis": "Framing logic."
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `STAGE SPECIFICATIONS:
          Framing: ${state.inferredShotScale}
          Optics: ${activeCamera.lens}, ${activeCamera.verticalAngle}
          Camera World Rotation: ${activeCamera.rotation}° (0° faces Deep Stage)

          Subject A:
          - ${getOrientationInstruction(state.subjects.a, activeCamera, "Subject A")}
          - ${getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "Subject A")}

          Subject B:
          - ${state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "Subject B") : "Not present"}
          - ${state.subjects.activeCount === 2 ? getGazeInstruction(state.subjects.b, state.subjects.a, activeCamera, "Subject B") : ""}

          World Positions:
          Subject A is at X:${state.subjects.a.x}, Y:${state.subjects.a.y}.
          Camera is at X:${activeCamera.x}, Y:${activeCamera.y}.` }
      ] 
    },
    config: { systemInstruction, responseMimeType: "application/json" }
  });
  return response.text || "";
};

export const generateStudioImage = async (state: any, draftJson: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  let script = "";
  try { script = JSON.parse(draftJson).script; } catch(e) { script = draftJson; }

  const parts: any[] = [];
  const addRef = async (id: string, role: string) => {
    const ref = state.references[id];
    if (ref?.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.4);
      parts.push({ text: `### [ASSET: ${id.toUpperCase()} - ROLE: ${role}] ###` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  await addRef('background', 'ENVIRONMENT CONTEXT.');
  await addRef('char_a', 'Visual Identity A');
  await addRef('pose_a', 'POSE REFERENCE (IGNORE FACING)');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Visual Identity B');
    await addRef('pose_b', 'POSE REFERENCE B (IGNORE FACING)');
  }

  const directive = `### FINAL PRODUCTION DIRECTIVE ###
  - SCENE SCRIPT: ${script}
  - SHOT SCALE: ${state.inferredShotScale}
  - CAMERA OPTICS: ${activeCamera.model}, ${activeCamera.lens}
  - SUBJECT A: ${getOrientationInstruction(state.subjects.a, activeCamera, "A")} | ${getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "A")}
  - SUBJECT B: ${state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "B") : "N/A"}
  - PERSPECTIVE: Re-render background to match camera view from Y=${activeCamera.y} looking North.
  - STYLE: High-end professional cinematic photography. 8k. Unified world lighting.`;

  parts.push({ text: directive });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Renderer Failure.");
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

import React, { useRef, useState, useEffect, useCallback } from 'react';
import { Camera } from 'lucide-react';
import { StudioState, SubjectConfig, CameraConfig } from '../types';

interface FloorPlannerProps {
  state: StudioState;
  onUpdateSubject: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  state,
  onUpdateSubject,
  onUpdateCamera,
  onSelectCamera
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragState, setDragState] = useState<{ 
    type: 'move' | 'rotate-body' | 'rotate-gaze' | 'rotate-cam'; 
    target: 'subject' | 'camera';
    id: any;
  } | null>(null);

  const { subjects, cameras, activeCameraIndex, plannerZoom } = state;
  const handlersRef = useRef({ onUpdateSubject, onUpdateCamera, onSelectCamera });

  useEffect(() => {
    handlersRef.current = { onUpdateSubject, onUpdateCamera, onSelectCamera };
  }, [onUpdateSubject, onUpdateCamera, onSelectCamera]);

  const getFovAngle = (lens: string) => {
    const mm = lens.match(/(\d+)mm/);
    const focalLength = mm ? parseInt(mm[1]) : 50;
    return 2 * Math.atan(18 / focalLength) * (180 / Math.PI);
  };

  const startDrag = (type: any, target: any, id: any) => (e: React.MouseEvent | React.TouchEvent) => {
    if (e.cancelable) e.preventDefault();
    e.stopPropagation();
    if (target === 'camera' && type === 'move') handlersRef.current.onSelectCamera(id as number);
    setDragState({ type, target, id });
  };

  const handleInteraction = useCallback((clientX: number, clientY: number) => {
    if (!dragState || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const effectiveDepthRange = 200 / plannerZoom;
    const effectiveWidthRange = 400 / plannerZoom;

    // Movement Mapping
    if (dragState.type === 'move') {
      const coordX = ((clientX - rect.left) / rect.width - 0.5) * effectiveWidthRange;
      const coordY = (1 - (clientY - rect.top) / rect.height) * effectiveDepthRange;

      const boundedX = Math.max(-200, Math.min(200, coordX));
      const boundedY = Math.max(0, Math.min(200, coordY));

      if (dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { x: boundedX, y: boundedY });
      } else {
        handlersRef.current.onUpdateCamera(dragState.id, { x: boundedX, y: boundedY });
      }
    } else {
      // Rotation Mapping (0 deg is North/Top, clockwise increases)
      const targetObj = dragState.target === 'subject' ? subjects[dragState.id as 'a' | 'b'] : cameras[dragState.id];
      const objScreenX = rect.left + rect.width * (0.5 + targetObj.x / effectiveWidthRange);
      const objScreenY = rect.top + rect.height * (1 - targetObj.y / effectiveDepthRange);

      const dx = clientX - objScreenX;
      const dy = clientY - objScreenY;
      // Standard clockwise rotation where 0 is Up: atan2(dx, -dy)
      let angle = (Math.atan2(dx, -dy) * 180 / Math.PI + 360) % 360;

      if (dragState.type === 'rotate-body' && dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { rotation: angle });
      } else if (dragState.type === 'rotate-gaze' && dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { gaze: angle });
      } else if (dragState.type === 'rotate-cam' && dragState.target === 'camera') {
        handlersRef.current.onUpdateCamera(dragState.id, { rotation: angle });
      }
    }
  }, [dragState, plannerZoom, subjects, cameras]);

  const onMouseMove = useCallback((e: MouseEvent) => handleInteraction(e.clientX, e.clientY), [handleInteraction]);
  const endDrag = useCallback(() => setDragState(null), []);

  useEffect(() => {
    if (dragState) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', endDrag);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', endDrag);
    };
  }, [dragState, onMouseMove, endDrag]);

  const getStyle = (obj: {x: number, y: number}) => {
    const effectiveDepthRange = 200 / plannerZoom;
    const effectiveWidthRange = 400 / plannerZoom;
    const left = `${((obj.x / effectiveWidthRange) + 0.5) * 100}%`;
    const top = `${(1 - (obj.y / effectiveDepthRange)) * 100}%`;
    return { left, top };
  };

  const renderSubject = (id: 'a' | 'b', config: SubjectConfig) => {
    const isDragging = dragState?.target === 'subject' && dragState.id === id;

    return (
      <div 
        key={id}
        style={getStyle(config)}
        className={`absolute -translate-x-1/2 -translate-y-1/2 z-20 group select-none ${isDragging ? 'z-30 scale-110' : ''}`}
      >
        <div className="relative w-24 h-24 flex items-center justify-center transition-all">
          <div onMouseDown={startDrag('move', 'subject', id)} className="absolute inset-6 cursor-grab active:cursor-grabbing rounded-full bg-white/5 border border-white/5 hover:bg-white/10 z-10"></div>

          {/* Body */}
          <div className="absolute inset-0 transition-transform duration-75" style={{ transform: `rotate(${config.rotation}deg)` }}>
            <svg viewBox="0 0 100 100" className="w-full h-full">
              <ellipse cx="50" cy="50" rx="32" ry="16" fill={id === 'a' ? 'rgba(99, 102, 241, 0.4)' : 'rgba(168, 85, 247, 0.4)'} stroke={id === 'a' ? '#6366f1' : '#a855f7'} strokeWidth="3" />
              <circle cx="50" cy="50" r="14" fill={id === 'a' ? '#6366f1' : '#a855f7'} />
            </svg>
            <div onMouseDown={startDrag('rotate-body', 'subject', id)} className="absolute top-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-white rounded-full cursor-alias border-2 border-indigo-500 shadow-xl hover:scale-125 transition-transform" />
          </div>

          {/* Gaze */}
          <div className="absolute inset-0 pointer-events-none transition-transform duration-75" style={{ transform: `rotate(${config.gaze}deg)` }}>
             <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-[320%] flex flex-col items-center">
                <div className="w-0.5 h-14 bg-gradient-to-t from-emerald-500 to-transparent opacity-60"></div>
                <div onMouseDown={startDrag('rotate-gaze', 'subject', id)} className="w-5 h-5 bg-emerald-400 rounded-full cursor-alias pointer-events-auto shadow-[0_0_15px_rgba(52,211,153,0.8)] border-2 border-white hover:scale-125 transition-transform" />
             </div>
          </div>

          <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 text-[7px] font-black uppercase text-white/40 tracking-widest whitespace-nowrap bg-black/40 px-2 rounded">
            {id === 'a' ? 'ACTOR A' : 'ACTOR B'}
          </div>
        </div>
      </div>
    );
  };

  const renderCamera = (cam: CameraConfig, index: number) => {
    const isActive = activeCameraIndex === index;
    const fov = getFovAngle(cam.lens);

    return (
      <div key={cam.id} style={getStyle(cam)} className={`absolute -translate-x-1/2 -translate-y-1/2 select-none touch-none ${isActive ? 'z-40' : 'z-20'}`}>
        <div 
          className="absolute top-1/2 left-1/2 pointer-events-none transition-all duration-300"
          style={{ 
            transform: `translate(-50%, -50%) rotate(${cam.rotation}deg)`, 
            opacity: isActive ? 0.3 : 0.05,
            width: '1200px',
            height: '1200px'
          }}
        >
          <svg viewBox="0 0 1200 1200" className="w-full h-full">
             <path d={`M 600 600 L ${600 - Math.tan((fov / 2) * Math.PI / 180) * 800} 0 L ${600 + Math.tan((fov / 2) * Math.PI / 180) * 800} 0 Z`} fill="url(#fovGradientPlanner)" />
          </svg>
        </div>

        <div className={`relative p-3.5 rounded-2xl border transition-all ${isActive ? 'bg-indigo-600 border-indigo-300 scale-125 shadow-2xl' : 'bg-[#111] border-white/10 opacity-50 hover:opacity-100'}`}>
          <div onMouseDown={startDrag('move', 'camera', index)} className="absolute inset-0 cursor-grab active:cursor-grabbing z-0"></div>
          <div className="relative z-10 transition-transform pointer-events-none" style={{ transform: `rotate(${cam.rotation}deg)` }}>
            <Camera className="w-5 h-5 text-white" />
            <div onMouseDown={startDrag('rotate-cam', 'camera', index)} className="absolute top-[-14px] left-1/2 -translate-x-1/2 w-4 h-4 bg-white rounded-full cursor-alias pointer-events-auto border-2 border-indigo-400 shadow-xl hover:scale-125 transition-transform" />
          </div>
          <div className="absolute -bottom-8 left-1/2 -translate-x-1/2 text-[8px] font-black text-white/40 uppercase whitespace-nowrap tracking-widest bg-black/40 px-2 rounded">
            LENS {index + 1}
          </div>
        </div>
      </div>
    );
  };

  return (
    <div 
      ref={containerRef}
      className="w-full h-full bg-[#030303] rounded-[3rem] border border-white/5 overflow-hidden shadow-[inset_0_0_200px_rgba(0,0,0,0.9)] cursor-crosshair relative select-none"
    >
      <svg className="absolute w-0 h-0">
        <defs>
          <linearGradient id="fovGradientPlanner" x1="0.5" y1="1" x2="0.5" y2="0">
            <stop offset="0%" stopColor="#818cf8" stopOpacity="0.8" />
            <stop offset="100%" stopColor="#6366f1" stopOpacity="0" />
          </linearGradient>
        </defs>
      </svg>

      {/* Depth and Stage Reference Lines */}
      <div className="absolute inset-0 opacity-[0.04]" style={{ 
        backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', 
        backgroundSize: `${40 * plannerZoom}px ${40 * plannerZoom}px`,
        backgroundPosition: 'center bottom'
      }}></div>

      <div className="absolute left-10 inset-y-0 flex flex-col justify-between py-12 pointer-events-none border-l border-white/5">
         <span className="text-[8px] font-black text-white/20 uppercase tracking-[0.5em] -rotate-90">Deep Stage (Y 200)</span>
         <span className="text-[8px] font-black text-indigo-500/40 uppercase tracking-[0.5em] -rotate-90">Camera Baseline (Y 0)</span>
      </div>

      <div className="absolute inset-x-0 bottom-0 h-px bg-indigo-500/20 shadow-[0_0_20px_rgba(99,102,241,0.2)]"></div>

      {renderSubject('a', subjects.a)}
      {subjects.activeCount === 2 && renderSubject('b', subjects.b)}
      {cameras.map((cam, idx) => renderCamera(cam, idx))}

      <div className="absolute bottom-6 right-8 flex flex-col items-end gap-1 pointer-events-none opacity-40">
         <span className="text-[8px] font-black text-white uppercase tracking-widest">Physics Stage Interface</span>
         <span className="text-[7px] font-bold text-white/30 uppercase tracking-[0.2em]">Coordinates: Standard XYZ</span>
      </div>
    </div>
  );
};

export default FloorPlanner;

export type ReferenceType = 
  | 'background' 
  | 'char_a' | 'pose_a' 
  | 'char_b' | 'pose_b' 
  | 'prop';

export interface ReferenceImage {
  id: ReferenceType;
  label: string;
  dataUrl?: string;
  mimeType?: string;
}

export interface SubjectConfig {
  x: number; // Stage Left (-) to Stage Right (+)
  z: number; // Proscenium (0) to Deep Stage (+)
  rotation: number; // 0-360
  gaze: number; // 0-360
}

export interface CameraConfig {
  id: string;
  x: number;
  z: number;
  rotation: number;
  model: string;
  lens: string;
  verticalAngle: string;
}

export interface StudioState {
  references: Record<ReferenceType, ReferenceImage>;
  lighting: {
    positions: boolean[];
  };
  subjects: {
    a: SubjectConfig;
    b: SubjectConfig;
    activeCount: 1 | 2;
  };
  cameras: CameraConfig[];
  activeCameraIndex: number;
  isGenerating: boolean;
  isGeneratingPrompt: boolean;
  isReviewingPrompt: boolean;
  draftPrompt: string;
  generatedImage?: string;
  plannerZoom: number;
}

import React, { useState, useMemo } from 'react';
import { Camera, Layers, Sun, Trash2, Wand2, Loader2, Settings2, Copy, Check, X, RotateCw, UserPlus, UserMinus, Compass, Eye, Plus, Maximize2, ExternalLink, ZoomIn, ZoomOut } from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage, SubjectConfig, CameraConfig } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, LIGHT_POSITIONS, VERTICAL_ANGLES } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import LightRig from './components/LightRig';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import { generateDraftPrompt, generateStudioImage } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    subjects: {
      a: { x: -30, z: 50, rotation: 180, gaze: 180 },
      b: { x: 40, z: 120, rotation: 180, gaze: 180 },
      activeCount: 1,
    },
    cameras: [
      {
        id: 'cam-1',
        x: 0,
        z: 5,
        rotation: 0,
        model: CAMERA_MODELS[0],
        lens: LENSES[1].label,
        verticalAngle: VERTICAL_ANGLES[1],
      }
