import { GoogleGenAI } from "@google/genai";
import { StudioState, CameraConfig, SubjectConfig } from "../types";
import { LIGHT_POSITIONS } from "../constants";

/**
 * PRODUCTION COORDINATE STANDARD:
 * World X: -Left to +Right (Stage-centric)
 * World Z: 0 (Front) to +Depth (Infinity)
 * Rotation: 0 is North (Facing Depth), 180 is South (Facing Camera).
 *           90 is East (Facing Stage Right), 270 is West (Facing Stage Left).
 */

async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.3): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Image load failed"));
    img.src = dataUrl;
  });
}

const getOrientationInstruction = (subj: SubjectConfig, camera: CameraConfig, label: string) => {
  const subjRot = (subj.rotation + 360) % 360;
  const camRot = (camera.rotation + 360) % 360;

  // Angle relative to camera: 180 is facing camera, 0 is back to camera.
  const relAngle = (subjRot - camRot + 360) % 360;

  if (relAngle > 160 && relAngle < 200) return `POSTURE: ${label} is facing DIRECTLY AT the camera lens.`;
  if (relAngle >= 200 && relAngle < 255) return `POSTURE: ${label} is angled towards the frame LEFT (three-quarter view).`;
  if (relAngle >= 255 && relAngle < 285) return `POSTURE: ${label} is in PURE PROFILE, facing the frame LEFT.`;
  if (relAngle >= 285 && relAngle < 345) return `POSTURE: ${label} is angled away, showing their back-left.`;
  if (relAngle >= 345 || relAngle < 15) return `POSTURE: ${label} is facing COMPLETELY AWAY from the camera (Back to Lens).`;
  if (relAngle >= 15 && relAngle < 75) return `POSTURE: ${label} is angled away, showing their back-right.`;
  if (relAngle >= 75 && relAngle < 105) return `POSTURE: ${label} is in PURE PROFILE, facing the frame RIGHT.`;
  return `POSTURE: ${label} is angled towards the frame RIGHT (three-quarter view).`;
};

const getGazeInstruction = (subj: SubjectConfig, other: SubjectConfig | null, camera: CameraConfig, label: string) => {
  const dx = camera.x - subj.x;
  const dz = camera.z - subj.z;
  const angleToCam = (Math.atan2(dx, dz) * 180 / Math.PI + 360) % 360;
  const camDiff = Math.min(Math.abs(subj.gaze - angleToCam), 360 - Math.abs(subj.gaze - angleToCam));

  if (camDiff < 15) return `GAZE: ${label} is looking STRAIGHT into the camera lens with absolute eye contact.`;

  if (other) {
    const pdx = other.x - subj.x;
    const pdz = other.z - subj.z;
    const angleToPartner = (Math.atan2(pdx, pdz) * 180 / Math.PI + 360) % 360;
    const partnerDiff = Math.min(Math.abs(subj.gaze - angleToPartner), 360 - Math.abs(subj.gaze - angleToPartner));
    if (partnerDiff < 25) return `GAZE: ${label} is looking directly at the other subject.`;
  }

  const relGaze = (subj.gaze - camera.rotation + 540) % 360 - 180;
  if (relGaze < -20) return `GAZE: ${label} is looking towards the frame LEFT.`;
  if (relGaze > 20) return `GAZE: ${label} is looking towards the frame RIGHT.`;
  return `GAZE: ${label} is looking into the distance, past the camera.`;
};

