      const { data, mimeType } = await downscaleImage(ref.dataUrl, 200, 0.2);
      parts.push({ text: `REF_${slotId.toUpperCase()}:` });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const systemInstruction = `You are a Cinematographer analyzing a 3D Floor Plan.

  MANDATORY SCALE ANALYSIS:
  1. Examine the 'BACKGROUND' reference first.
  2. If the background shows an EXTREME WIDE SHOT (mountains, ocean, desert, city skyline), interpret the Z-depth units as larger (meters/km). If characters are at Z > 100, describe them as small silhouettes or distant figures.
