  COORDINATE RULES:
  - Z is Depth (0 = Front, Higher = Deeper).
  - X is Left (-) to Right (+).
  - Rotation 0 = Facing Depth, 180 = Facing Camera.

  OUTPUT: JSON
  {
    "script": "Technical cinematic description including lighting and spatial composition.",
    "scale_determination": "e.g. Extreme Wide Shot (High Scale) or Interior (Low Scale)."
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `STAGE SPECIFICATIONS:
          Framing Hint: ${state.inferredShotScale}
          Optics: ${activeCamera.lens}, ${activeCamera.verticalAngle}
          Camera Location: X=${activeCamera.x}, Z=${activeCamera.z}

          Subject A:
          - X=${state.subjects.a.x}, Z=${state.subjects.a.z}
          - ${getOrientationInstruction(state.subjects.a, activeCamera, "Subject A")}
          - ${getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "Subject A")}

          Subject B:
          - ${state.subjects.activeCount === 2 ? `X=${state.subjects.b.x}, Z=${state.subjects.b.z}` : "N/A"}
          - ${state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "Subject B") : ""}
          - ${state.subjects.activeCount === 2 ? getGazeInstruction(state.subjects.b, state.subjects.a, activeCamera, "Subject B") : ""}

          Light Nodes Active: ${state.lighting.positions.map((on, i) => on ? LIGHT_POSITIONS[i].label : null).filter(Boolean).join(', ')}` }
      ] 
