    config: { systemInstruction, responseMimeType: "application/json" }
  });
  return response.text || "";
};

export const generateStudioImage = async (state: any, draftJson: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  let script = "";
  try { script = JSON.parse(draftJson).script; } catch(e) { script = draftJson; }

  const parts: any[] = [];
  const addRef = async (id: string, role: string) => {
    const ref = state.references[id];
    if (ref?.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.5);
      parts.push({ text: `[ASSET: ${id.toUpperCase()} - ROLE: ${role}]` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  await addRef('background', 'ENVIRONMENT CONTEXT AND WORLD SCALE.');
  await addRef('char_a', 'Subject A Identity');
  await addRef('pose_a', 'Pose reference (Disregard orientation)');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Subject B Identity');
    await addRef('pose_b', 'Pose B reference');
  }

  const finalDirective = `### CINEMATIC DIRECTIVE - NO COLLAGE ###
  1. BASE SCRIPT: ${script}
  2. VIEWPOINT: Re-render background from Camera X=${activeCamera.x}, Z=${activeCamera.z} looking North.
  3. CHARACTER A: ${getOrientationInstruction(state.subjects.a, activeCamera, "A")} | ${getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "A")}
  4. CHARACTER B: ${state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "B") : "NOT PRESENT"}
  5. STYLE: Ultra-detailed cinematic photography. Professional lighting match. 8k. Perfect spatial integration.`;

  parts.push({ text: finalDirective });

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts },
    config: { imageConfig: { aspectRatio: "16:9" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Renderer Failure.");
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

