import React from 'react';
import { Camera, RotateCw } from 'lucide-react';
import { SubjectConfig, CameraConfig } from '../types';

interface OrientationSliderProps {
  config: SubjectConfig;
  activeCamera: CameraConfig;
  onChange: (val: number) => void;
}

const OrientationSlider: React.FC<OrientationSliderProps> = ({ config, activeCamera, onChange }) => {
  const value = config.rotation;

  // Calculate the angle from subject to camera in 2D space (X-Z plane)
  const calculateFaceCameraAngle = () => {
    const dx = activeCamera.x - config.x;
    // Fix: Using 'z' coordinate instead of 'y' to match type definitions
    const dz = activeCamera.z - config.z;
    let angleRad = Math.atan2(dx, dz);
    let angleDeg = (angleRad * 180) / Math.PI;
    if (angleDeg < 0) angleDeg += 360;
    return Math.round(angleDeg);
  };

  const handleFaceCamera = () => {
    onChange(calculateFaceCameraAngle());
  };

  return (
    <div className="flex flex-col items-center gap-3 lg:gap-4">
      <div className="relative w-24 h-24 lg:w-32 lg:h-32 rounded-full border border-white/10 flex items-center justify-center overflow-hidden bg-black/40">
        {/* Compass Marks */}
        <div className="absolute inset-1.5 lg:inset-2 border border-white/5 rounded-full pointer-events-none"></div>
        <div className="absolute h-full w-px bg-white/5 left-1/2 -translate-x-1/2"></div>
        <div className="absolute w-full h-px bg-white/5 top-1/2 -translate-y-1/2"></div>

        {/* Human Top View Icon */}
        <div 
          className="absolute w-12 h-12 lg:w-16 lg:h-16 flex items-center justify-center transition-transform duration-200"
          style={{ transform: `rotate(${value}deg)` }}
        >
          <svg viewBox="0 0 100 100" className="w-full h-full drop-shadow-[0_0_8px_rgba(99,102,241,0.4)]">
            <ellipse cx="50" cy="50" rx="35" ry="18" fill="rgba(99, 102, 241, 0.3)" stroke="rgba(99, 102, 241, 0.8)" strokeWidth="2" />
            <circle cx="50" cy="50" r="14" fill="#6366f1" />
            <path d="M44 42 L50 32 L56 42 Z" fill="#818cf8" />
          </svg>
        </div>

        {/* Visual Camera Marker */}
        <div 
          className="absolute inset-0 pointer-events-none opacity-40"
          style={{ transform: `rotate(${calculateFaceCameraAngle()}deg)` }}
        >
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-4 h-4 flex items-center justify-center">
             <Camera className="w-2.5 h-2.5 text-indigo-400 rotate-180" />
          </div>
        </div>

        <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent pointer-events-none"></div>
      </div>

      <div className="w-full space-y-3">
        <button 
          onClick={handleFaceCamera}
          className="w-full flex items-center justify-center gap-2 py-1.5 rounded-lg bg-indigo-500/10 hover:bg-indigo-500/20 text-[8px] font-bold text-indigo-400 uppercase tracking-widest border border-indigo-500/20 transition-all"
        >
          <Camera className="w-3 h-3" /> Face Lens
        </button>

        <div className="space-y-1">
          <div className="flex justify-between items-center text-[9px] text-white/40 uppercase tracking-widest px-1">
            <span>Body Rotation</span>
            <span className="text-indigo-400 font-mono font-bold">{value}°</span>
          </div>
          <input 
            type="range" 
            min="0" 
            max="360" 
            value={value} 
            onChange={(e) => onChange(parseInt(e.target.value))}
            className="w-full h-1.5 bg-white/10 rounded-lg appearance-none cursor-pointer accent-indigo-500"
          />
        </div>
      </div>
    </div>
  );
};

export default OrientationSlider;

import React from 'react';
import { Eye, Monitor, Users, MoveRight, MoveLeft, Target } from 'lucide-react';
import { SubjectConfig, CameraConfig } from '../types';

interface GazeSelectorProps {
  subjectId: 'a' | 'b';
  config: SubjectConfig;
  activeCamera: CameraConfig;
  otherSubject?: SubjectConfig;
  onChange: (val: number) => void;
}

const GazeSelector: React.FC<GazeSelectorProps> = ({ subjectId, config, activeCamera, otherSubject, onChange }) => {

  // Fix: renamed parameter ty to tz and using config.z instead of config.y
  const getAngleTo = (tx: number, tz: number) => {
    const dx = tx - config.x;
    const dz = tz - config.z;
    let angleRad = Math.atan2(dx, dz);
    let angleDeg = (angleRad * 180) / Math.PI;
    if (angleDeg < 0) angleDeg += 360;
    return Math.round(angleDeg);
  };

  // Fix: Using activeCamera.z instead of activeCamera.y
  const setGazeToCamera = () => onChange(getAngleTo(activeCamera.x, activeCamera.z));

  const setGazeToPartner = () => {
    if (!otherSubject) return;
    // Fix: Using otherSubject.z instead of otherSubject.y
    onChange(getAngleTo(otherSubject.x, otherSubject.z));
  };

  const PRESETS = [
    { label: 'Into Lens', icon: <Target className="w-3 h-3" />, action: setGazeToCamera },
    { label: 'Partner', icon: <Users className="w-3 h-3" />, action: setGazeToPartner, disabled: !otherSubject },
    { label: 'Left Field', icon: <MoveLeft className="w-3 h-3" />, action: () => onChange(270) },
    { label: 'Right Field', icon: <MoveRight className="w-3 h-3" />, action: () => onChange(90) },
  ];

  return (
    <div className="bg-black/40 p-3 lg:p-4 rounded-2xl border border-white/5 space-y-4">
      <div className="flex justify-between items-center px-0.5">
        <p className="text-[8px] font-bold text-white/30 uppercase">Subject {subjectId.toUpperCase()}</p>
        <div className="flex items-center gap-1.5">
           {/* Fix: Using activeCamera.z instead of activeCamera.y */}
           {Math.abs(config.gaze - getAngleTo(activeCamera.x, activeCamera.z)) < 5 && (
             <span className="text-[7px] font-black text-emerald-400 bg-emerald-500/20 px-1 rounded animate-pulse">FIXED ON LENS</span>
           )}
           <span className="text-[8px] font-mono font-bold text-emerald-400 bg-emerald-500/10 px-1.5 py-0.5 rounded">
            {config.gaze}°
          </span>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-1.5">
        {PRESETS.map((p, i) => (
          <button
            key={i}
            onClick={p.action}
            disabled={p.disabled}
            className="flex items-center gap-2 px-2 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 text-[9px] font-bold text-white/40 hover:text-white/60 transition-all disabled:opacity-20 disabled:pointer-events-none"
          >
            {p.icon}
            {p.label}
          </button>
        ))}
      </div>

      <div className="relative h-1 bg-white/10 rounded-full mt-2">
        <input 
          type="range" 
          min="0" 
          max="360" 
          value={config.gaze} 
          onChange={(e) => onChange(parseInt(e.target.value))}
          className="absolute inset-0 w-full h-full appearance-none bg-transparent cursor-pointer accent-emerald-500"
        />
      </div>
      <p className="text-[7px] text-white/20 uppercase tracking-widest text-center">Relative Gaze Angle</p>
    </div>
  );
};

