import { GoogleGenAI } from "@google/genai";
import { StudioState, CameraConfig, SubjectConfig } from "../types";
import { LIGHT_POSITIONS } from "../constants";

/**
 * CINEMATIC PHYSICAL COORDINATE SYSTEM:
 * 1 Unit = 1 Foot (Standard height of human subject: 5.5 - 6.0 units)
 * World X: Stage Left (-) to Stage Right (+)
 * World Z: Distance from Camera Baseline (0) to Infinite Depth (+)
 * Rotation: 0° is North (Toward Deep Stage), 180° is South (Facing Camera)
 */

async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.3): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Image load failed"));
    img.src = dataUrl;
  });
}

const getOrientationInstruction = (subj: SubjectConfig, camera: CameraConfig, label: string) => {
  const subjRot = (subj.rotation + 360) % 360;
  const camRot = (camera.rotation + 360) % 360;
  const relAngle = (subjRot - camRot + 360) % 360;

  if (relAngle > 165 && relAngle < 195) return `POSTURE: ${label} is facing DIRECTLY AT the camera lens.`;
  if (relAngle >= 195 && relAngle < 255) return `POSTURE: ${label} is in a 3/4 view, facing frame LEFT.`;
  if (relAngle >= 255 && relAngle < 285) return `POSTURE: ${label} is in PURE PROFILE, facing frame LEFT.`;
  if (relAngle >= 285 && relAngle < 345) return `POSTURE: ${label} is turned away (showing back-left).`;
  if (relAngle >= 345 || relAngle < 15) return `POSTURE: ${label} is facing COMPLETELY AWAY from camera.`;
  if (relAngle >= 15 && relAngle < 75) return `POSTURE: ${label} is turned away (showing back-right).`;
  if (relAngle >= 75 && relAngle < 105) return `POSTURE: ${label} is in PURE PROFILE, facing frame RIGHT.`;
  return `POSTURE: ${label} is in a 3/4 view, facing frame RIGHT.`;
};

const getGazeInstruction = (subj: SubjectConfig, other: SubjectConfig | null, camera: CameraConfig, label: string) => {
  const dx = camera.x - subj.x;
  const dz = camera.z - subj.z;
  const angleToCam = (Math.atan2(dx, dz) * 180 / Math.PI + 360) % 360;
  const camDiff = Math.min(Math.abs(subj.gaze - angleToCam), 360 - Math.abs(subj.gaze - angleToCam));

  if (camDiff < 15) return `GAZE: ${label} is making direct eye contact with the lens.`;

  if (other) {
    const pdx = other.x - subj.x;
    const pdz = other.z - subj.z;
    const angleToPartner = (Math.atan2(pdx, pdz) * 180 / Math.PI + 360) % 360;
    const partnerDiff = Math.min(Math.abs(subj.gaze - angleToPartner), 360 - Math.abs(subj.gaze - angleToPartner));
    if (partnerDiff < 25) return `GAZE: ${label} is looking at the other subject.`;
  }
  return `GAZE: ${label} is looking into the distance, away from camera.`;
};

export const generateDraftPrompt = async (state: any): Promise<string> => {
  // Create instance right before call to ensure latest API key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  // 1. Process Background
  const bgRef = state.references['background'];
  if (bgRef?.dataUrl) {
    const { data, mimeType } = await downscaleImage(bgRef.dataUrl, 512, 0.4);
    parts.push({ text: "### ENVIRONMENT REFERENCE ###" });
    parts.push({ inlineData: { data, mimeType } });
  }

  // 2. Process Subject Identities
  const charARef = state.references['char_a'];
  if (charARef?.dataUrl) {
    const { data, mimeType } = await downscaleImage(charARef.dataUrl, 512, 0.4);
    parts.push({ text: "### SUBJECT A IDENTITY REFERENCE ###" });
    parts.push({ inlineData: { data, mimeType } });
  }

  if (state.subjects.activeCount === 2) {
    const charBRef = state.references['char_b'];
    if (charBRef?.dataUrl) {
      const { data, mimeType } = await downscaleImage(charBRef.dataUrl, 512, 0.4);
      parts.push({ text: "### SUBJECT B IDENTITY REFERENCE ###" });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const systemInstruction = `You are a Cinematographer and Physical Stage Analyst.

  BENCHMARK: 1 unit = 1 foot. Standard human height is 5.5 to 6.0 feet.

  MANDATORY TASK:
  1. ANALYZE CHARACTER IMAGES: Carefully look at the provided images for Subject A (and B). Extract their gender, age, ethnicity, hair style/color, and clothing details.
  2. ANALYZE THE BACKGROUND: Determine the Z-axis scale of the environment.
  3. INTEGRATE: Create a script that describes the characters visually using the details extracted. Do not just say "Subject A," say "Subject A, a [description], ..."
  4. PHYSICS: Adhere to the provided X/Z coordinates.

  OUTPUT: JSON
  {
    "script": "A detailed cinematic script including visual character descriptions and technical stage placement.",
    "character_descriptions": {
      "A": "Short text summary of Subject A's appearance based on the image.",
      "B": "Short text summary of Subject B's appearance (if applicable)."
    },
    "scale_analysis": "Notes on the world depth."
  }`;

  // Using gemini-3-pro-preview for complex reasoning task as per requirements
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `STAGE TECHNICAL DATA:
          Framing: ${state.inferredShotScale}
          Optics: ${activeCamera.lens}, ${activeCamera.verticalAngle}
          Camera: X=${activeCamera.x}ft, Z=${activeCamera.z}ft

          SUBJECT A:
          - Location: X=${state.subjects.a.x}ft, Z=${state.subjects.a.z}ft
          - ${getOrientationInstruction(state.subjects.a, activeCamera, "A")}
          - ${getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "A")}

          SUBJECT B:
          - Location: ${state.subjects.activeCount === 2 ? `X=${state.subjects.b.x}ft, Z=${state.subjects.b.z}ft` : "N/A"}
          - ${state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "B") : ""}` }
      ] 
    },
    config: { systemInstruction, responseMimeType: "application/json" }
  });
  return response.text || "";
};

export const generateStudioImage = async (state: any, draftJson: string): Promise<string> => {
  // Create instance right before call to ensure latest API key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  let script = "";
  try { 
    const parsed = JSON.parse(draftJson);
    script = parsed.script; 
  } catch(e) { 
    script = draftJson; 
  }

  const parts: any[] = [];
  const addRef = async (id: string, role: string) => {
    const ref = state.references[id];
    if (ref?.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 1024, 0.5);
      parts.push({ text: `### [ASSET: ${id.toUpperCase()}] ROLE: ${role} ###` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  await addRef('background', 'WORLD SCALE AND ENVIRONMENT PLATE.');
  await addRef('char_a', 'Visual Identity A');
  await addRef('pose_a', 'Reference Pose');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Visual Identity B');
    await addRef('pose_b', 'Reference Pose B');
  }

  const directive = `### FINAL PRODUCTION DIRECTIVE - PHYSICAL RENDER ###
  1. CORE SCRIPT (USE THESE VISUAL DESCRIPTIONS): ${script}
  2. PHYSICAL DEPTH: Subject A is at Z=${state.subjects.a.z} feet. 
  3. SCALE MATCH: If Z is large, subjects must appear small.
  4. PERSPECTIVE: Render from Camera X=${activeCamera.x}ft, Z=${activeCamera.z}ft looking toward ${activeCamera.rotation}°.
  5. INTEGRATION: Perfect 3D unified lighting based on the Lighting Rig.`;

  parts.push({ text: directive });

  // Using gemini-3-pro-image-preview for high-quality professional cinematic renders
  // This model requires a paid project API key.
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { 
      imageConfig: { 
        aspectRatio: "16:9",
        imageSize: "1K"
      } 
    }
  });

  // Find the image part as per guidelines
  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Renderer Failure: No image data returned.");
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

import React, { useState, useMemo, useEffect } from 'react';
import { Camera, Layers, Sun, Trash2, Wand2, Loader2, Settings2, RotateCw, ZoomIn, ZoomOut, Plus, X, Check, Maximize2, Compass, Eye, Key, AlertCircle } from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage, SubjectConfig, CameraConfig } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, LIGHT_POSITIONS, VERTICAL_ANGLES } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import LightRig from './components/LightRig';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import { generateDraftPrompt, generateStudioImage } from './services/geminiService';

// Define or extend the AIStudio interface and use it for the window object
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    // Fixed: Removed 'readonly' modifier to ensure consistency with environment declarations
    aistudio: AIStudio;
  }
}

const App: React.FC = () => {
  // State to track if an API key has been selected - Mandatory for gemini-3-pro-image-preview
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [quotaError, setQuotaError] = useState<string | null>(null);
  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    subjects: {
      a: { x: 0, z: 12, rotation: 180, gaze: 180 },
      b: { x: 10, z: 25, rotation: 180, gaze: 180 },
      activeCount: 1,
    },
    cameras: [
      {
        id: 'cam-1',
        x: 0,
        z: 0,
        rotation: 0,
        model: CAMERA_MODELS[0],
        lens: LENSES[2].label, // 50mm
        verticalAngle: VERTICAL_ANGLES[1],
      }
    ],
    activeCameraIndex: 0,
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    draftPrompt: '',
    plannerZoom: 1.0,
  });

  // Check for API key selection on mount
  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(hasKey);
      } else {
        setHasApiKey(true);
      }
    };
    checkKey();
  }, []);

  // Handle opening the API key selection dialog
  const handleOpenSelectKey = async () => {
    if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
      await window.aistudio.openSelectKey();
      setQuotaError(null);
      // Assume selection was successful and proceed to clear errors
      setHasApiKey(true);
    }
  };

  const activeCamera = state.cameras[state.activeCameraIndex];
  const [promptView, setPromptView] = useState<'text' | 'json'>('text');

  // PHYSICAL SHOT SCALE CALCULATION
  const inferredShotScale = useMemo(() => {
    const mm = LENSES.find(l => l.label === activeCamera.lens)?.mm || 50;
    const dx = state.subjects.a.x - activeCamera.x;
    const dz = state.subjects.a.z - activeCamera.z;
    const distInFeet = Math.sqrt(dx * dx + dz * dz);
    const distInMm = distInFeet * 304.8;

    const frameHeightInMm = (24 * distInMm) / mm;
    const frameHeightInFeet = frameHeightInMm / 304.8;

    if (frameHeightInFeet < 1.5) return "Extreme Close Up (ECU)";
    if (frameHeightInFeet < 4) return "Close Up (CU)";
    if (frameHeightInFeet < 9) return "Medium Shot (MS)";
    if (frameHeightInFeet < 25) return "Long Shot (LS)";
    return "Wide Shot (WS)";
  }, [activeCamera, state.subjects.a]);

  const handleUpload = (type: ReferenceType, dataUrl: string, mimeType: string) => {
    setState(prev => ({
      ...prev,
      references: { ...prev.references, [type]: { ...prev.references[type], dataUrl, mimeType } }
    }));
  };

  const updateSubject = (id: 'a' | 'b', updates: Partial<SubjectConfig>) => {
    setState(prev => ({
      ...prev,
      subjects: {
        ...prev.subjects,
        [id]: { ...prev.subjects[id], ...updates }
      }
    }));
  };

  const updateCamera = (index: number, updates: Partial<CameraConfig>) => {
    setState(prev => {
      const newCameras = [...prev.cameras];
      newCameras[index] = { ...newCameras[index], ...updates };
      return { ...prev, cameras: newCameras };
    });
  };

  const addCamera = () => {
    if (state.cameras.length >= 4) return;
    const newCam: CameraConfig = {
      ...activeCamera,
      id: `cam-${Date.now()}`,
      x: activeCamera.x + 10,
      z: activeCamera.z
    };
    setState(prev => ({
      ...prev,
      cameras: [...prev.cameras, newCam],
      activeCameraIndex: prev.cameras.length
    }));
  };

  const checkErrorAndReset = (err: any) => {
    const errMsg = err?.message || JSON.stringify(err) || "";
    console.error("API Error Trace:", err);

    // Check for specific error patterns requiring re-authentication or paid project
    const isQuotaError = errMsg.includes("RESOURCE_EXHAUSTED") || errMsg.includes("limit: 0") || errMsg.includes("quota");
    const isKeyError = errMsg.includes("API key expired") || errMsg.includes("INVALID_ARGUMENT") || errMsg.includes("API_KEY_INVALID");
    const isNotFoundError = errMsg.includes("Requested entity was not found.");

    if (isQuotaError || isKeyError || isNotFoundError) {
      setHasApiKey(false);
      setQuotaError(isQuotaError 
        ? "The current project has no quota for these advanced models. You MUST use an API key from a PAID Google Cloud Project." 
        : "Your API key has expired or is invalid. Please select a valid key to continue."
      );
      return true;
    }
    return false;
  };

  const handleGeneratePrompt = async () => {
    setState(prev => ({ ...prev, isGeneratingPrompt: true }));
    try {
      const prompt = await generateDraftPrompt({ ...state, inferredShotScale });
      setState(prev => ({ ...prev, draftPrompt: prompt, isGeneratingPrompt: false, isReviewingPrompt: true }));
    } catch (err: any) {
      if (!checkErrorAndReset(err)) {
        alert("An unexpected error occurred during prompt generation. Please check the console.");
      }
      setState(prev => ({ ...prev, isGeneratingPrompt: false }));
    }
  };

  const handleFinalRender = async () => {
    setState(prev => ({ ...prev, isGenerating: true, isReviewingPrompt: false }));
    try {
      const result = await generateStudioImage({ ...state, inferredShotScale }, state.draftPrompt);
      setState(prev => ({ ...prev, generatedImage: result, isGenerating: false }));
    } catch (err: any) {
      if (!checkErrorAndReset(err)) {
        alert("An unexpected error occurred during rendering. Please check the console.");
      }
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const openImageInNewWindow = () => {
    if (!state.generatedImage) return;
    const newWindow = window.open();
    if (newWindow) {
      newWindow.document.write(`
        <body style="margin:0; background:#000; display:flex; align-items:center; justify-content:center;">
          <img src="${state.generatedImage}" style="max-width:100%; max-height:100%;" />
        </body>
      `);
    }
  };

  // Mandatory API key selection screen before accessing the main application
  if (!hasApiKey || quotaError) {
    return (
      <div className="min-h-screen bg-[#080808] flex items-center justify-center p-6 text-white">
        <div className="max-w-md w-full bg-[#0a0a0a] border border-white/10 rounded-[2.5rem] p-10 text-center space-y-8 shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 via-purple-500 to-indigo-500"></div>

          <div className="bg-indigo-600/20 w-20 h-20 rounded-3xl flex items-center justify-center mx-auto border border-indigo-500/20">
            {quotaError ? <AlertCircle className="w-10 h-10 text-red-400" /> : <Key className="w-10 h-10 text-indigo-400" />}
          </div>

          <div className="space-y-2">
            <h1 className="text-2xl font-black uppercase tracking-tight">
              {quotaError ? "Project Access Error" : "Studio Access"}
            </h1>
            <p className="text-white/40 text-sm leading-relaxed">
              {quotaError || "To use professional cinematic image generation, you must select an API key from a Google Cloud project with the Gemini API enabled."}
            </p>
          </div>

          <button 
            onClick={handleOpenSelectKey}
            className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 rounded-2xl font-black text-sm uppercase tracking-widest transition-all shadow-lg shadow-indigo-600/20 flex items-center justify-center gap-2"
          >
            <Key className="w-4 h-4" />
            {quotaError ? "Switch to Paid Project" : "Select API Key"}
          </button>

          <div className="pt-4 border-t border-white/5">
            <p className="text-[10px] text-white/20 uppercase tracking-widest leading-relaxed">
              Professional Gemini models require a project with a <strong>Pay-As-You-Go</strong> billing account. 
              <br /><br />
              <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" rel="noreferrer" className="text-indigo-400 hover:underline">View Billing Guide</a>
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#080808] flex flex-col overflow-hidden text-white">
      <header className="border-b border-white/5 p-3 bg-[#0a0a0a]/95 backdrop-blur-md flex items-center justify-between sticky top-0 z-[100]">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600/20 p-2 rounded-xl border border-indigo-500/20">
            <Camera className="w-5 h-5 text-indigo-400" />
          </div>
          <div>
            <h1 className="text-sm font-black tracking-tight text-white uppercase">Cinematic Studio AI</h1>
            <p className="text-[9px] text-white/30 uppercase tracking-[0.3em] font-bold">Physical Production Mode</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {!state.isReviewingPrompt && !state.generatedImage && (
            <button
              onClick={handleGeneratePrompt}
              disabled={state.isGeneratingPrompt}
              className="flex items-center gap-2 px-6 py-2 rounded-xl text-xs font-black bg-indigo-600 hover:bg-indigo-500 transition-all shadow-lg shadow-indigo-600/20 disabled:opacity-50 uppercase tracking-widest"
