            <button 
              onClick={(e) => { e.stopPropagation(); onRemove(); }}
              className="bg-red-500/80 hover:bg-red-500 text-white p-1 rounded-full transition-colors"
            >
              <X className="w-2.5 h-2.5 lg:w-3.5 lg:h-3.5" />
