    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = (e) => reject(new Error("Image load failed: " + e));
    img.src = dataUrl;
  });
}

const getOrientationInstruction = (subj: SubjectConfig, camera: CameraConfig, label: string) => {
  const subjRot = (subj.rotation + 360) % 360;
  const camRot = (camera.rotation + 360) % 360;
  const relAngle = (subjRot - camRot + 360) % 360;

  if (relAngle > 165 && relAngle < 195) return `POSTURE: ${label} is facing DIRECTLY AT the camera lens.`;
  if (relAngle >= 195 && relAngle < 255) return `POSTURE: ${label} is in a 3/4 view, facing frame LEFT.`;
  if (relAngle >= 255 && relAngle < 285) return `POSTURE: ${label} is in PURE PROFILE, facing frame LEFT.`;
  if (relAngle >= 285 && relAngle < 345) return `POSTURE: ${label} is turned away (showing back-left).`;
  if (relAngle >= 345 || relAngle < 15) return `POSTURE: ${label} is facing COMPLETELY AWAY from camera.`;
  if (relAngle >= 15 && relAngle < 75) return `POSTURE: ${label} is turned away (showing back-right).`;
  if (relAngle >= 75 && relAngle < 105) return `POSTURE: ${label} is in PURE PROFILE, facing frame RIGHT.`;
  return `POSTURE: ${label} is in a 3/4 view, facing frame RIGHT.`;
};

const getGazeInstruction = (subj: SubjectConfig, other: SubjectConfig | null, camera: CameraConfig, label: string) => {
  const dx = camera.x - subj.x;
  const dz = camera.z - subj.z;
  const angleToCam = (Math.atan2(dx, dz) * 180 / Math.PI + 360) % 360;
  const camDiff = Math.min(Math.abs(subj.gaze - angleToCam), 360 - Math.abs(subj.gaze - angleToCam));

  if (camDiff < 15) return `GAZE: ${label} is making direct eye contact with the lens.`;

  if (other) {
    const pdx = other.x - subj.x;
    const pdz = other.z - subj.z;
    const angleToPartner = (Math.atan2(pdx, pdz) * 180 / Math.PI + 360) % 360;
    const partnerDiff = Math.min(Math.abs(subj.gaze - angleToPartner), 360 - Math.abs(subj.gaze - angleToPartner));
    if (partnerDiff < 25) return `GAZE: ${label} is looking at the other subject.`;
  }
  return `GAZE: ${label} is looking into the distance, away from camera.`;
};

export const generateDraftPrompt = async (state: StudioState | any): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  // Environment
  const bgRef = state.references['background'];
  if (bgRef?.dataUrl) {
    const { data, mimeType } = await downscaleImage(bgRef.dataUrl, 512, 0.4);
    parts.push({ text: "### ENVIRONMENT REFERENCE ###" });
    parts.push({ inlineData: { data, mimeType } });
  }

  // Subject A
  const charARef = state.references['char_a'];
  if (charARef?.dataUrl) {
    const { data, mimeType } = await downscaleImage(charARef.dataUrl, 512, 0.4);
    parts.push({ text: "### SUBJECT A IDENTITY REFERENCE ###" });
    parts.push({ inlineData: { data, mimeType } });
  }
  const poseARef = state.references['pose_a'];
  if (poseARef?.dataUrl) {
    const { data, mimeType } = await downscaleImage(poseARef.dataUrl, 512, 0.4);
    parts.push({ text: "### SUBJECT A POSE REFERENCE ###" });
    parts.push({ inlineData: { data, mimeType } });
  }

  // Subject B
  if (state.subjects.activeCount === 2) {
    const charBRef = state.references['char_b'];
    if (charBRef?.dataUrl) {
      const { data, mimeType } = await downscaleImage(charBRef.dataUrl, 512, 0.4);
      parts.push({ text: "### SUBJECT B IDENTITY REFERENCE ###" });
      parts.push({ inlineData: { data, mimeType } });
    }
    const poseBRef = state.references['pose_b'];
    if (poseBRef?.dataUrl) {
      const { data, mimeType } = await downscaleImage(poseBRef.dataUrl, 512, 0.4);
      parts.push({ text: "### SUBJECT B POSE REFERENCE ###" });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  // Props
  const propRef = state.references['prop'];
  if (propRef?.dataUrl) {
    const { data, mimeType } = await downscaleImage(propRef.dataUrl, 512, 0.4);
    parts.push({ text: "### SCENE PROP REFERENCE ###" });
    parts.push({ inlineData: { data, mimeType } });
  }

  const systemInstruction = `You are a Cinematographer and Physical Stage Analyst.

  BENCHMARK: 1 unit = 1 foot. Standard human height is 5.5 to 6.0 feet.

  MANDATORY TASK:
  1. ANALYZE CHARACTER IMAGES: Extract identity and appearance.
  2. ANALYZE POSE IMAGES: Extract physical stance/action.
  3. ANALYZE PROP IMAGES: Describe prop usage.
  4. ANALYZE THE BACKGROUND: Determine world depth.
  5. INTEGRATE: Create a script that describes the characters visually, matching poses and identity.
  6. PHYSICS: Adhere to coordinates.

  OUTPUT: JSON ONLY. DO NOT INCLUDE MARKDOWN CODE BLOCKS.
  {
    "script": "Detailed cinematic script...",
    "character_descriptions": { "A": "...", "B": "..." },
    "scale_analysis": "..."
  }`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `STAGE TECHNICAL DATA:
          Framing: ${state.inferredShotScale}
          Optics: ${activeCamera.lens}, ${activeCamera.verticalAngle}
          Camera: X=${activeCamera.x}ft, Z=${activeCamera.z}ft

          SUBJECT A:
          - Location: X=${state.subjects.a.x}ft, Z=${state.subjects.a.z}ft
          - ${getOrientationInstruction(state.subjects.a, activeCamera, "A")}
          - ${getGazeInstruction(state.subjects.a, state.subjects.activeCount === 2 ? state.subjects.b : null, activeCamera, "A")}

          SUBJECT B:
          - Location: ${state.subjects.activeCount === 2 ? `X=${state.subjects.b.x}ft, Z=${state.subjects.b.z}ft` : "N/A"}
          - ${state.subjects.activeCount === 2 ? getOrientationInstruction(state.subjects.b, activeCamera, "B") : ""}` }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 32768 } 
    }
  });

  let text = response.text || "";
  // Strip markdown formatting if any
  text = text.replace(/```json/g, "").replace(/```/g, "").trim();
  if (!text) {
    return JSON.stringify({ 
      script: "A cinematic scene featuring the provided references.", 
      character_descriptions: { A: "Subject A", B: "Subject B" },
      scale_analysis: "Standard depth."
    });
  }
  return text;
};

export const generateStudioImage = async (state: StudioState | any, draftJson: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  let script = "";
  try { 
    const cleanJson = draftJson.replace(/```json/g, "").replace(/```/g, "").trim();
    const parsed = JSON.parse(cleanJson);
    script = parsed.script || draftJson; 
  } catch(e) { 
    script = draftJson; 
  }

  const parts: any[] = [];
  const addRef = async (id: string, role: string) => {
    const ref = state.references[id];
    if (ref?.dataUrl) {
      const { data, mimeType } = await downscaleImage(ref.dataUrl, 1024, 0.4);
      parts.push({ text: `### [ASSET: ${id.toUpperCase()}] ROLE: ${role} ###` });
      parts.push({ inlineData: { data, mimeType } });
    }
  };

  await addRef('background', 'Environment Plate');
  await addRef('char_a', 'Subject A Identity');
  await addRef('pose_a', 'Subject A Pose');
  if (state.subjects.activeCount === 2) {
    await addRef('char_b', 'Subject B Identity');
    await addRef('pose_b', 'Subject B Pose');
  }
  await addRef('prop', 'Scene Prop');

  const directive = `### PRODUCTION DIRECTIVE ###
  SCRIPT: ${script}
  LOCATION: Subject A at Z=${state.subjects.a.z}ft.
  PERSPECTIVE: Cam X=${activeCamera.x}ft, Z=${activeCamera.z}ft, Rot=${activeCamera.rotation}°.
  LENS: ${activeCamera.lens}.
  FIDELITY: Match identity and pose references precisely.`;

  parts.push({ text: directive });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { 
      imageConfig: { 
        aspectRatio: "16:9",
        imageSize: "1K"
      } 
    }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Image Generation Failed: No pixel data returned from engine.");
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

export const generateStudioVideo = async (
  state: StudioState, 
  script: string, 
  baseImage: string, 
  onStatusChange: (status: string) => void
): Promise<string> => {
  // Use a fresh instance right before the call
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  onStatusChange("Initializing Video Pipeline...");

  const base64Data = baseImage.split(',')[1];

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Cinematic animation of this scene: ${script}. Maintain perfect frame consistency with the provided image.`,
    image: {
      imageBytes: base64Data,
      mimeType: 'image/png',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '16:9'
    }
  });

  const loadingMessages = [
    "Stabilizing camera motion...",
    "Simulating physics and light...",
    "Applying consistency filters...",
    "Rendering dynamic performance...",
    "Finalizing motion pass...",
    "Processing production export..."
  ];

  let msgIndex = 0;
  while (!operation.done) {
    onStatusChange(loadingMessages[msgIndex % loadingMessages.length]);
    msgIndex++;
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  onStatusChange("Downloading production export...");
  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video pipeline failure: Result URI missing.");

  const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  if (!videoResponse.ok) {
    throw new Error(`Failed to download video result. Server responded with ${videoResponse.status}`);
  }

  const videoBlob = await videoResponse.blob();
  return URL.createObjectURL(videoBlob);
};

import { Camera, Eye, RotateCw } from 'lucide-react';
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { CameraConfig, StudioState, SubjectConfig } from '../types';

interface FloorPlannerProps {
  state: StudioState;
  onUpdateSubject: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  state,
  onUpdateSubject,
  onUpdateCamera,
  onSelectCamera
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragState, setDragState] = useState<{ 
    type: 'move' | 'rotate-body' | 'rotate-gaze' | 'rotate-cam'; 
    target: 'subject' | 'camera';
    id: any;
  } | null>(null);

  const { subjects, cameras, activeCameraIndex, plannerZoom } = state;
  const handlersRef = useRef({ onUpdateSubject, onUpdateCamera, onSelectCamera });

  useEffect(() => {
    handlersRef.current = { onUpdateSubject, onUpdateCamera, onSelectCamera };
  }, [onUpdateSubject, onUpdateCamera, onSelectCamera]);

  const getFovAngle = (lens: string) => {
    const mm = lens.match(/(\d+)mm/);
    const focalLength = mm ? parseInt(mm[1]) : 50;
    return 2 * Math.atan(18 / focalLength) * (180 / Math.PI);
  };

  const startDrag = (type: 'move' | 'rotate-body' | 'rotate-gaze' | 'rotate-cam', target: 'subject' | 'camera', id: any) => (e: React.MouseEvent | React.TouchEvent) => {
    e.stopPropagation();
    if (target === 'camera' && type === 'move') {
      handlersRef.current.onSelectCamera(id as number);
    }
    setDragState({ type, target, id });
  };

  const handleInteraction = useCallback((clientX: number, clientY: number) => {
    if (!dragState || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const range = 50 / plannerZoom;

    if (dragState.type === 'move') {
      const coordX = ((clientX - rect.left) / rect.width - 0.5) * (range * 2);
      const coordZ = (1 - (clientY - rect.top) / rect.height) * (range * 2);

      const boundedX = coordX; 
      const boundedZ = Math.max(0, coordZ); 

      if (dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { x: boundedX, z: boundedZ });
      } else {
        handlersRef.current.onUpdateCamera(dragState.id, { x: boundedX, z: boundedZ });
      }
    } else {
      const targetObj = dragState.target === 'subject' ? subjects[dragState.id as 'a' | 'b'] : cameras[dragState.id];
      const objScreenX = rect.left + rect.width * (0.5 + targetObj.x / (range * 2));
      const objScreenY = rect.top + rect.height * (1 - targetObj.z / (range * 2));

      const dx = clientX - objScreenX;
      const dy = clientY - objScreenY;
      let angle = (Math.atan2(dx, -dy) * 180 / Math.PI + 360) % 360;

      if (dragState.type === 'rotate-body' && dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { rotation: angle });
      } else if (dragState.type === 'rotate-gaze' && dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { gaze: angle });
      } else if (dragState.type === 'rotate-cam' && dragState.target === 'camera') {
        handlersRef.current.onUpdateCamera(dragState.id, { rotation: angle });
      }
    }
  }, [dragState, subjects, cameras, plannerZoom]);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => handleInteraction(e.clientX, e.clientY);
    const onTouchMove = (e: TouchEvent) => {
      if (e.touches[0]) handleInteraction(e.touches[0].clientX, e.touches[0].clientY);
    };
    const onEnd = () => setDragState(null);

    if (dragState) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('touchmove', onTouchMove, { passive: false });
      window.addEventListener('mouseup', onEnd);
      window.addEventListener('touchend', onEnd);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('mouseup', onEnd);
      window.removeEventListener('touchend', onEnd);
    };
  }, [dragState, handleInteraction]);

  const renderSubject = (id: 'a' | 'b', config: SubjectConfig) => {
    const range = 50 / plannerZoom;
    const left = (0.5 + config.x / (range * 2)) * 100;
    const bottom = (config.z / (range * 2)) * 100;

    return (
      <div 
        key={id}
        className="absolute w-12 h-12 -ml-6 -mb-6 z-20 group"
        style={{ left: `${left}%`, bottom: `${bottom}%` }}
      >
        {/* Connection to Gaze */}
        <div 
          className="absolute top-1/2 left-1/2 w-px h-16 bg-gradient-to-t from-emerald-500/40 to-transparent origin-bottom pointer-events-none"
          style={{ transform: `translateX(-50%) translateY(-100%) rotate(${config.gaze}deg)` }}
        />

        {/* Move Handle (Icon) */}
        <div 
          onMouseDown={startDrag('move', 'subject', id)}
          onTouchStart={startDrag('move', 'subject', id)}
          className={`w-full h-full rounded-full border-2 flex items-center justify-center cursor-move transition-all ${
            id === 'a' ? 'bg-indigo-600/20 border-indigo-500' : 'bg-purple-600/20 border-purple-500'
          } shadow-[0_0_15px_rgba(0,0,0,0.5)]`}
        >
          <div className="text-[10px] font-black text-white">{id.toUpperCase()}</div>

          {/* Rotation Handle */}
          <div 
            onMouseDown={startDrag('rotate-body', 'subject', id)}
            onTouchStart={startDrag('rotate-body', 'subject', id)}
            className="absolute -top-3 left-1/2 -translate-x-1/2 w-4 h-4 bg-white rounded-full flex items-center justify-center cursor-alias hover:scale-125 transition-transform border border-black shadow-lg"
            style={{ transform: `rotate(${config.rotation}deg) translateY(-24px)` }}
          >
            <RotateCw className="w-2.5 h-2.5 text-black" />
          </div>

          {/* Gaze Handle */}
          <div 
            onMouseDown={startDrag('rotate-gaze', 'subject', id)}
            onTouchStart={startDrag('rotate-gaze', 'subject', id)}
            className="absolute -top-3 left-1/2 -translate-x-1/2 w-4 h-4 bg-emerald-500 rounded-full flex items-center justify-center cursor-alias hover:scale-125 transition-transform border border-black shadow-lg"
            style={{ transform: `rotate(${config.gaze}deg) translateY(-40px)` }}
          >
            <Eye className="w-2.5 h-2.5 text-white" />
          </div>
        </div>
      </div>
    );
  };

  const renderCamera = (cam: CameraConfig, index: number) => {
    const range = 50 / plannerZoom;
    const left = (0.5 + cam.x / (range * 2)) * 100;
    const bottom = (cam.z / (range * 2)) * 100;
    const fov = getFovAngle(cam.lens);
    const isActive = index === activeCameraIndex;

    return (
      <div 
        key={cam.id}
        className={`absolute w-10 h-10 -ml-5 -mb-5 z-30 transition-shadow ${isActive ? 'z-40' : ''}`}
        style={{ left: `${left}%`, bottom: `${bottom}%` }}
      >
        {/* FOV Cone */}
        <div 
          className={`absolute top-1/2 left-1/2 w-64 h-64 -ml-32 -mt-32 pointer-events-none transition-opacity ${isActive ? 'opacity-30' : 'opacity-5'}`}
          style={{ 
            transform: `rotate(${cam.rotation}deg)`,
            background: `conic-gradient(from ${180 - fov/2}deg, transparent 0deg, rgba(99, 102, 241, 0.5) ${fov/2}deg, rgba(99, 102, 241, 0.5) ${fov}deg, transparent ${fov}deg)`
          }}
        />

        {/* Move Handle (Icon) */}
        <div 
          onMouseDown={startDrag('move', 'camera', index)}
          onTouchStart={startDrag('move', 'camera', index)}
          className={`w-full h-full rounded-xl border-2 flex items-center justify-center cursor-move transition-all ${
            isActive ? 'bg-indigo-600 border-indigo-400 scale-110 shadow-[0_0_20px_rgba(99,102,241,0.5)]' : 'bg-zinc-800 border-zinc-600'
          }`}
        >
          <Camera className={`w-5 h-5 ${isActive ? 'text-white' : 'text-zinc-400'}`} />

          {/* Rotation Handle (Front of Camera) */}
          <div 
            onMouseDown={startDrag('rotate-cam', 'camera', index)}
            onTouchStart={startDrag('rotate-cam', 'camera', index)}
            className="absolute -top-2 left-1/2 -translate-x-1/2 w-3 h-3 bg-indigo-400 rounded-full cursor-alias hover:scale-150 transition-transform shadow-lg"
            style={{ transform: `rotate(${cam.rotation}deg) translateY(-20px)` }}
          />
        </div>
        <div className="absolute top-full left-1/2 -translate-x-1/2 mt-1 px-1.5 py-0.5 bg-black/80 rounded text-[8px] font-black text-white/50 border border-white/5">CAM {index + 1}</div>
      </div>
    );
  };

  return (
    <div 
      ref={containerRef}
      className="relative w-full aspect-square max-w-[600px] bg-[#0d0d0d] border border-white/5 overflow-hidden rounded-[2rem] shadow-2xl touch-none"
      style={{ backgroundImage: 'radial-gradient(circle at center, #1a1a1a 1px, transparent 1px)', backgroundSize: `${20 * plannerZoom}px ${20 * plannerZoom}px` }}
    >
      {/* Distance Markers */}
      <div className="absolute inset-0 border border-white/5 pointer-events-none" />
      <div className="absolute bottom-4 left-1/2 -translate-x-1/2 px-3 py-1 bg-black/50 backdrop-blur-md rounded-full border border-white/5 text-[10px] font-black text-white/20 uppercase tracking-widest z-50">
        Stage Floor Plan
      </div>

      {/* Origin Marker */}
      <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-1 h-8 bg-gradient-to-t from-indigo-500 to-transparent opacity-50" />

      {/* Render Entities */}
      {renderSubject('a', subjects.a)}
      {state.subjects.activeCount === 2 && renderSubject('b', subjects.b)}
      {cameras.map((cam, i) => renderCamera(cam, i))}
    </div>
  );
};

