  return (
    <div className="fixed inset-0 bg-[#080808] flex flex-col text-white overflow-hidden">
      <header className="border-b border-white/5 p-3 bg-[#0a0a0a]/95 backdrop-blur-md flex items-center justify-between z-[100]">
        <div className="flex items-center gap-3">
