          <h1 className="text-sm font-black uppercase tracking-tight">Studio AI</h1>
        </div>
        <div className="flex items-center gap-3">
          {!state.isReviewingPrompt && !state.isReviewingVideoPrompt && !state.generatedImage && (
            <button onClick={handleGeneratePrompt} disabled={state.isGeneratingPrompt} className="px-4 py-2 bg-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
              {state.isGeneratingPrompt ? <Loader2 className="w-3 h-3 animate-spin" /> : <Wand2 className="w-3 h-3" />} Analyze & Render
            </button>
          )}
          {state.isReviewingPrompt && (
            <button onClick={handleFinalRender} className="px-4 py-2 bg-emerald-600 rounded-lg text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
              <Check className="w-3 h-3" /> Start Render
            </button>
          )}
          {(state.generatedImage || state.generatedVideo) && (
            <button onClick={() => setState(prev => ({ ...prev, generatedImage: undefined, generatedVideo: undefined, isReviewingPrompt: false, isReviewingVideoPrompt: false }))} className="px-4 py-2 bg-white/5 border border-white/10 rounded-lg text-[10px] font-black uppercase tracking-widest">
              <RotateCw className="w-3 h-3" />
