          <button onClick={() => setActiveMobileTab('optics')} className={`flex flex-col items-center gap-1 ${activeMobileTab === 'optics' ? 'text-indigo-400' : 'text-white/20'}`}><SlidersHorizontal className="w-5 h-5" /><span className="text-[8px] font-black uppercase">Optics</span></button>
