import { GoogleGenAI } from "@google/genai";
import { StudioState, CameraConfig, SubjectConfig } from "../types";

async function downscaleImage(dataUrl: string, maxWidth = 256, quality = 0.3): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failed"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = (e) => reject(new Error("Image load failed"));
    img.src = dataUrl;
  });
}

const getOrientationInstruction = (subj: SubjectConfig, camera: CameraConfig, label: string) => {
  const relAngle = (subj.rotation - camera.rotation + 360) % 360;
  if (relAngle > 165 && relAngle < 195) return `${label} is facing camera.`;
  if (relAngle >= 255 && relAngle < 285) return `${label} is facing left profile.`;
  if (relAngle >= 75 && relAngle < 105) return `${label} is facing right profile.`;
  return `${label} orientation: ${relAngle} degrees.`;
};

export const generateDraftPrompt = async (state: StudioState | any): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  for (const [key, ref] of Object.entries(state.references)) {
    if ((ref as any).dataUrl) {
      const { data, mimeType } = await downscaleImage((ref as any).dataUrl, 512, 0.4);
      parts.push({ text: `### REFERENCE: ${key.toUpperCase()} ###` });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const systemInstruction = `You are a Studio Cinematographer. Analyze images and stage data. Output JSON with a "script" describing characters, poses, and props in the environment. Coordinates: A(X:${state.subjects.a.x}, Z:${state.subjects.a.z}). Cam(X:${activeCamera.x}, Z:${activeCamera.z}).`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: [...parts, { text: `TECHNICAL: Framing ${state.inferredShotScale}. Lens ${activeCamera.lens}.` }] },
    config: { systemInstruction, responseMimeType: "application/json", thinkingConfig: { thinkingBudget: 24000 } }
  });

  return response.text || "";
};

export const generateStudioImage = async (state: StudioState | any, draftJson: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  let script = draftJson;
  try {
    const clean = draftJson.replace(/```json/g, "").replace(/```/g, "").trim();
    const p = JSON.parse(clean);
    script = p.script || draftJson;
  } catch (e) {}

  const parts: any[] = [];
  for (const [key, ref] of Object.entries(state.references)) {
    if ((ref as any).dataUrl) {
      const { data, mimeType } = await downscaleImage((ref as any).dataUrl, 1024, 0.5);
      parts.push({ text: `ASSET ${key}:` });
      parts.push({ inlineData: { data, mimeType } });
    }
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts: [...parts, { text: `PRODUCTION SCRIPT: ${script}. CAMERA: X=${activeCamera.x}ft, Z=${activeCamera.z}ft. FIDELITY: Maintain pose and identity.` }] },
    config: { imageConfig: { aspectRatio: "16:9", imageSize: "1K" } }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Renderer Failure");
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

export const generateStudioVideo = async (state: StudioState, script: string, baseImage: string, onStatusChange: (s: string) => void): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  onStatusChange("Preparing Pipeline...");
  const base64Data = baseImage.split(',')[1];

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Animate: ${script}. Consistent with image.`,
    image: { imageBytes: base64Data, mimeType: 'image/png' },
    config: { numberOfVideos: 1, resolution: '720p', aspectRatio: '16:9' }
  });

  while (!operation.done) {
    onStatusChange("Rendering Motion...");
    await new Promise(r => setTimeout(r, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video missing");

  const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  if (!videoResponse.ok) throw new Error("Download failed");
  const blob = await videoResponse.blob();
  return URL.createObjectURL(blob);
};

