export const generateStudioImage = async (state: StudioState | any, draftJson: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  let script = "";
  try {
    const clean = draftJson.replace(/```json/g, "").replace(/```/g, "").trim();
    const p = JSON.parse(clean);
    script = p.script || draftJson;
  } catch (e) {
    script = draftJson;
  }

  const parts: any[] = [];
  // Send references at higher res for the image model, but keep count reasonable
  const relevantRefs = ['background', 'char_a', 'pose_a', 'prop'];
  if (state.subjects.activeCount === 2) {
    relevantRefs.push('char_b', 'pose_b');
  }

  for (const key of relevantRefs) {
    const ref = state.references[key];
    if (ref?.dataUrl) {
      try {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 768, 0.5);
        parts.push({ text: `VISUAL_ASSET_${key.toUpperCase()}:` });
        parts.push({ inlineData: { data, mimeType } });
      } catch (e) {
        console.warn(`Processing failed for ${key}`, e);
      }
    }
  }

  const directive = `RENDER_DIRECTIVE:
1. SCENE_SCRIPT: ${script}
2. PHYSICS: Render from Camera(X=${activeCamera.x}, Z=${activeCamera.z}) with ${activeCamera.lens}.
3. CHARACTER_A: Ensure visual identity matches CHAR_A and physical posture matches POSE_A.
4. ENVIRONMENT: Integrate seamlessly into the world from BACKGROUND ref.`;

  parts.push({ text: directive });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { 
      imageConfig: { 
        aspectRatio: "16:9", 
        imageSize: "1K" 
      } 
    }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) {
    throw new Error("The image generation model returned no pixel data. Check your prompt or project quota.");
  }
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

export const generateStudioVideo = async (
  state: StudioState, 
  script: string, 
  baseImage: string, 
  onStatusChange: (s: string) => void
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  onStatusChange("Initializing Production Pipeline...");
  const base64Data = baseImage.split(',')[1];

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Cinematic animation of this production: ${script}. Maintain total consistency with the lighting and characters in the provided frame.`,
    image: { imageBytes: base64Data, mimeType: 'image/png' },
