import { Camera, RotateCw, Eye } from 'lucide-react';
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { CameraConfig, StudioState, SubjectConfig } from '../types';

interface FloorPlannerProps {
  state: StudioState;
  onUpdateSubject: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  state,
  onUpdateSubject,
  onUpdateCamera,
  onSelectCamera
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragState, setDragState] = useState<{ 
    type: 'move' | 'rotate-body' | 'rotate-gaze' | 'rotate-cam'; 
    target: 'subject' | 'camera';
    id: any;
  } | null>(null);

  const { subjects, cameras, activeCameraIndex, plannerZoom } = state;
  const handlersRef = useRef({ onUpdateSubject, onUpdateCamera, onSelectCamera });

  useEffect(() => {
    handlersRef.current = { onUpdateSubject, onUpdateCamera, onSelectCamera };
  }, [onUpdateSubject, onUpdateCamera, onSelectCamera]);

  const getFovAngle = (lens: string) => {
    const mm = lens.match(/(\d+)mm/);
    const focalLength = mm ? parseInt(mm[1]) : 50;
    return 2 * Math.atan(18 / focalLength) * (180 / Math.PI);
  };

  const startDrag = (type: 'move' | 'rotate-body' | 'rotate-gaze' | 'rotate-cam', target: 'subject' | 'camera', id: any) => (e: React.MouseEvent | React.TouchEvent) => {
    e.stopPropagation();
    if (target === 'camera' && type === 'move') {
      handlersRef.current.onSelectCamera(id as number);
    }
    setDragState({ type, target, id });
  };

  const handleInteraction = useCallback((clientX: number, clientY: number) => {
    if (!dragState || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const range = 50 / plannerZoom;

    if (dragState.type === 'move') {
      const coordX = ((clientX - rect.left) / rect.width - 0.5) * (range * 2);
      const coordZ = (1 - (clientY - rect.top) / rect.height) * (range * 2);

      const boundedX = coordX; 
      const boundedZ = Math.max(0, coordZ); 

      if (dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { x: boundedX, z: boundedZ });
      } else {
        handlersRef.current.onUpdateCamera(dragState.id, { x: boundedX, z: boundedZ });
      }
    } else {
      const targetObj = dragState.target === 'subject' ? subjects[dragState.id as 'a' | 'b'] : cameras[dragState.id];
      const objScreenX = rect.left + rect.width * (0.5 + targetObj.x / (range * 2));
      const objScreenY = rect.top + rect.height * (1 - targetObj.z / (range * 2));

      const dx = clientX - objScreenX;
      const dy = clientY - objScreenY;
      let angle = (Math.atan2(dx, -dy) * 180 / Math.PI + 360) % 360;

      if (dragState.type === 'rotate-body' && dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { rotation: angle });
      } else if (dragState.type === 'rotate-gaze' && dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { gaze: angle });
      } else if (dragState.type === 'rotate-cam' && dragState.target === 'camera') {
        handlersRef.current.onUpdateCamera(dragState.id, { rotation: angle });
      }
    }
  }, [dragState, plannerZoom, subjects, cameras]);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => handleInteraction(e.clientX, e.clientY);
    const onTouchMove = (e: TouchEvent) => {
      if (e.touches[0]) handleInteraction(e.touches[0].clientX, e.touches[0].clientY);
    };
    const onEnd = () => setDragState(null);

    if (dragState) {
      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('touchmove', onTouchMove, { passive: false });
      window.addEventListener('mouseup', onEnd);
      window.addEventListener('touchend', onEnd);
    }
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('mouseup', onEnd);
      window.removeEventListener('touchend', onEnd);
    };
  }, [dragState, handleInteraction]);

  const getPositionStyle = (obj: {x: number, z: number}) => {
    const range = 50 / plannerZoom;
    const left = `${((obj.x / (range * 2)) + 0.5) * 100}%`;
    const bottom = `${(obj.z / (range * 2)) * 100}%`;
    return { left, bottom };
  };

  const renderSubject = (id: 'a' | 'b', config: SubjectConfig) => {
    const style = getPositionStyle(config);
    return (
      <div 
        key={id}
        style={style}
        className="absolute -translate-x-1/2 translate-y-1/2 z-20 group touch-none"
      >
        <div className="relative w-24 h-24 flex items-center justify-center">
          {/* Main Hit Area for Move */}
          <div 
            onMouseDown={startDrag('move', 'subject', id)} 
            onTouchStart={startDrag('move', 'subject', id)}
            className="absolute inset-6 rounded-full bg-white/5 border border-white/10 hover:bg-white/20 transition-colors cursor-move z-10"
          />

          {/* Visual Rotation Indicators */}
          <div className="absolute inset-0 transition-transform duration-75" style={{ transform: `rotate(${config.rotation}deg)` }}>
            <svg viewBox="0 0 100 100" className="w-full h-full">
              <ellipse cx="50" cy="50" rx="30" ry="15" fill={id === 'a' ? 'rgba(99, 102, 241, 0.3)' : 'rgba(168, 85, 247, 0.3)'} stroke={id === 'a' ? '#6366f1' : '#a855f7'} strokeWidth="2" />
              <circle cx="50" cy="50" r="10" fill={id === 'a' ? '#6366f1' : '#a855f7'} />
            </svg>
            <div 
              onMouseDown={startDrag('rotate-body', 'subject', id)} 
              onTouchStart={startDrag('rotate-body', 'subject', id)}
              className="absolute top-2 left-1/2 -translate-x-1/2 w-6 h-6 bg-white rounded-full flex items-center justify-center cursor-alias shadow-lg border border-black/20 hover:scale-110 transition-transform"
            >
              <RotateCw className="w-3.5 h-3.5 text-black" />
            </div>
          </div>

          {/* Gaze Rotation Handle */}
          <div className="absolute inset-0 pointer-events-none" style={{ transform: `rotate(${config.gaze}deg)` }}>
             <div 
               onMouseDown={startDrag('rotate-gaze', 'subject', id)} 
               onTouchStart={startDrag('rotate-gaze', 'subject', id)}
               className="absolute -top-4 left-1/2 -translate-x-1/2 w-6 h-6 bg-emerald-500 rounded-full flex items-center justify-center cursor-alias shadow-lg border border-black/20 pointer-events-auto hover:scale-110 transition-transform"
             >
                <Eye className="w-3.5 h-3.5 text-white" />
             </div>
          </div>
          <div className="absolute top-full mt-2 px-2 py-0.5 bg-black/80 rounded text-[9px] font-black uppercase tracking-widest text-white/50 border border-white/5">{id}</div>
        </div>
      </div>
    );
  };

  const renderCamera = (cam: CameraConfig, index: number) => {
    const style = getPositionStyle(cam);
    const isActive = index === activeCameraIndex;
    const fov = getFovAngle(cam.lens);

    return (
      <div 
        key={cam.id}
        style={style}
        className={`absolute -translate-x-1/2 translate-y-1/2 z-30 transition-all ${isActive ? 'scale-110 z-40' : 'opacity-40 hover:opacity-60'}`}
      >
        <div className="relative w-20 h-20 flex items-center justify-center">
          {/* FOV Cone */}
          <div 
            className="absolute top-1/2 left-1/2 w-48 h-48 -translate-x-1/2 -translate-y-1/2 pointer-events-none transition-opacity"
            style={{ 
              opacity: isActive ? 0.2 : 0.05,
              transform: `rotate(${cam.rotation}deg)`,
              background: `conic-gradient(from ${180 - fov/2}deg, transparent 0deg, #6366f1 ${fov/2}deg, #6366f1 ${fov}deg, transparent ${fov}deg)`
            }}
          />
          {/* Main Hit Area for Move */}
          <div 
            onMouseDown={startDrag('move', 'camera', index)}
            onTouchStart={startDrag('move', 'camera', index)}
            className={`absolute inset-4 rounded-xl border-2 flex items-center justify-center cursor-move transition-all ${isActive ? 'bg-indigo-600 border-indigo-400 text-white shadow-xl shadow-indigo-600/20' : 'bg-zinc-800 border-zinc-600 text-zinc-400'}`}
          >
            <Camera className="w-6 h-6" />
            {/* Camera Rotation Handle */}
            <div 
              onMouseDown={startDrag('rotate-cam', 'camera', index)}
              onTouchStart={startDrag('rotate-cam', 'camera', index)}
              className="absolute -top-3 left-1/2 -translate-x-1/2 w-6 h-6 bg-indigo-400 rounded-full flex items-center justify-center cursor-alias shadow-lg border border-black/20 hover:scale-110 transition-transform"
              style={{ transform: `rotate(${cam.rotation}deg) translateY(-24px)` }}
            >
              <RotateCw className="w-3.5 h-3.5 text-black" />
            </div>
          </div>
          <div className="absolute top-full mt-1 px-1.5 py-0.5 bg-black/80 rounded text-[8px] font-black uppercase tracking-widest text-white/40 border border-white/5">CAM {index + 1}</div>
        </div>
      </div>
    );
  };

  return (
    <div 
      ref={containerRef}
      className="relative w-full aspect-square bg-[#0d0d0d] border border-white/5 overflow-hidden rounded-[2.5rem] shadow-2xl touch-none"
      style={{ backgroundImage: 'radial-gradient(circle at center, #1a1a1a 1.5px, transparent 1.5px)', backgroundSize: `${30 * plannerZoom}px ${30 * plannerZoom}px` }}
    >
      <div className="absolute inset-0 pointer-events-none border border-white/5 opacity-20" />
      <div className="absolute bottom-4 left-1/2 -translate-x-1/2 px-3 py-1 bg-black/50 backdrop-blur-md rounded-full border border-white/10 text-[8px] font-black text-white/20 uppercase tracking-[0.4em] z-50">Stage Deck</div>

      {renderSubject('a', subjects.a)}
      {subjects.activeCount === 2 && renderSubject('b', subjects.b)}
      {cameras.map((cam, i) => renderCamera(cam, i))}
    </div>
  );
};

