import { GoogleGenAI } from "@google/genai";
import { StudioState, CameraConfig, SubjectConfig } from "../types";

/**
 * Image processing with safe defaults for Gemini payloads
 */
async function downscaleImage(dataUrl: string, maxWidth = 512, quality = 0.5): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failure"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Reference image load failed"));
    img.src = dataUrl;
  });
}

export const generateDraftPrompt = async (state: StudioState | any): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];

  // Use a smaller size for the analysis phase to avoid 500 errors and long processing
  for (const [key, ref] of Object.entries(state.references)) {
    if ((ref as any).dataUrl) {
      try {
        const { data, mimeType } = await downscaleImage((ref as any).dataUrl, 512, 0.4);
        parts.push({ text: `REFERENCE_${key.toUpperCase()}:` });
        parts.push({ inlineData: { data, mimeType } });
      } catch (e) {
        console.warn(`Skipping reference ${key} due to processing error`, e);
      }
    }
  }

  const systemInstruction = `You are a Professional Cinematographer and Stage Manager. 
Analyze the provided visual references (identity, environment, pose) and stage technical data.
Task: Create a unified cinematic "script" that integrates these elements perfectly.
Coordinates: Subject A is at X:${state.subjects.a.x}, Z:${state.subjects.a.z}.
Camera is at X:${activeCamera.x}, Z:${activeCamera.z}.
Format your response as valid JSON with a "script" field. Ensure the script is descriptive and vivid.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `TECHNICAL_SPECS: Framing=${state.inferredShotScale}, Lens=${activeCamera.lens}, VerticalAngle=${activeCamera.verticalAngle}.` }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 16000 } // Allocate thinking for stable reasoning
    }
  });

  return response.text || "";
};

export const generateStudioImage = async (state: StudioState | any, draftJson: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  let script = "";
  try {
    const clean = draftJson.replace(/```json/g, "").replace(/```/g, "").trim();
    const p = JSON.parse(clean);
    script = p.script || draftJson;
  } catch (e) {
    script = draftJson;
  }

  const parts: any[] = [];
  // For the final image model, we can go slightly higher res but still stay within safe limits
  const relevantRefs = ['background', 'char_a', 'pose_a', 'prop'];
  if (state.subjects.activeCount === 2) {
    relevantRefs.push('char_b', 'pose_b');
  }

  for (const key of relevantRefs) {
    const ref = state.references[key];
    if (ref?.dataUrl) {
      try {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 768, 0.5);
        parts.push({ text: `VISUAL_ASSET_${key.toUpperCase()}:` });
        parts.push({ inlineData: { data, mimeType } });
      } catch (e) {
        console.warn(`Processing failed for ${key}`, e);
      }
    }
  }

  const directive = `RENDER_DIRECTIVE:
1. SCENE_SCRIPT: ${script}
2. PHYSICS: Render from Camera(X=${activeCamera.x}ft, Z=${activeCamera.z}ft) with lens ${activeCamera.lens}.
3. FIDELITY: Maintain strict character identity from CHAR_A/B and physical posture from POSE_A/B.
4. WORLD: Integrate seamlessly into the world defined by BACKGROUND.`;

  parts.push({ text: directive });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { 
      imageConfig: { 
        aspectRatio: "16:9", 
        imageSize: "1K" 
      } 
    }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) {
    throw new Error("The image generation model returned no pixel data. The prompt may be too complex or blocked.");
  }
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

