import React, { useState, useMemo, useEffect } from 'react';
import { Camera, Layers, Sun, Trash2, Wand2, Loader2, Settings2, RotateCw, ZoomIn, ZoomOut, Plus, X, Check, Maximize2, Compass, Eye, Key, AlertCircle, Play, Download, LayoutGrid, SlidersHorizontal } from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage, SubjectConfig, CameraConfig } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, VERTICAL_ANGLES } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import LightRig from './components/LightRig';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import { generateDraftPrompt, generateStudioImage, generateStudioVideo } from './services/geminiService';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [quotaError, setQuotaError] = useState<string | null>(null);
  const [activeMobileTab, setActiveMobileTab] = useState<'stage' | 'assets' | 'optics'>('stage');
  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    subjects: {
      a: { x: 0, z: 12, rotation: 180, gaze: 180 },
      b: { x: 10, z: 25, rotation: 180, gaze: 180 },
      activeCount: 1,
    },
    cameras: [
      {
        id: 'cam-1',
        x: 0,
        z: 0,
        rotation: 0,
        model: CAMERA_MODELS[0],
        lens: LENSES[2].label,
        verticalAngle: VERTICAL_ANGLES[1],
      }
    ],
    activeCameraIndex: 0,
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    isReviewingVideoPrompt: false,
    isGeneratingVideo: false,
    draftPrompt: '',
    plannerZoom: 1.0,
  });

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(hasKey);
      } else {
        setHasApiKey(true);
      }
    };
    checkKey();
  }, []);

  const handleOpenSelectKey = async () => {
    if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
      await window.aistudio.openSelectKey();
      setQuotaError(null);
      setHasApiKey(true);
    }
  };

  const activeCamera = state.cameras[state.activeCameraIndex];
  const [promptView, setPromptView] = useState<'text' | 'json'>('text');

  const inferredShotScale = useMemo(() => {
    const mm = LENSES.find(l => l.label === activeCamera.lens)?.mm || 50;
    const dx = state.subjects.a.x - activeCamera.x;
    const dz = state.subjects.a.z - activeCamera.z;
    const distInFeet = Math.sqrt(dx * dx + dz * dz);
    const distInMm = distInFeet * 304.8;
    const frameHeightInMm = (24 * distInMm) / mm;
    const frameHeightInFeet = frameHeightInMm / 304.8;

    if (frameHeightInFeet < 1.5) return "Extreme Close Up (ECU)";
    if (frameHeightInFeet < 4) return "Close Up (CU)";
    if (frameHeightInFeet < 9) return "Medium Shot (MS)";
    if (frameHeightInFeet < 25) return "Long Shot (LS)";
    return "Wide Shot (WS)";
  }, [activeCamera, state.subjects.a]);

  const handleUpload = (type: ReferenceType, dataUrl: string, mimeType: string) => {
    setState(prev => ({
      ...prev,
      references: { ...prev.references, [type]: { ...prev.references[type], dataUrl, mimeType } }
    }));
  };

  const updateSubject = (id: 'a' | 'b', updates: Partial<SubjectConfig>) => {
    setState(prev => ({
      ...prev,
      subjects: {
        ...prev.subjects,
        [id]: { ...prev.subjects[id], ...updates }
      }
    }));
  };

  const updateCamera = (index: number, updates: Partial<CameraConfig>) => {
    setState(prev => {
      const newCameras = [...prev.cameras];
      newCameras[index] = { ...newCameras[index], ...updates };
      return { ...prev, cameras: newCameras };
    });
  };

  const addCamera = () => {
    if (state.cameras.length >= 4) return;
    const newCam: CameraConfig = {
      ...activeCamera,
      id: `cam-${Date.now()}`,
      x: activeCamera.x + 10,
      z: activeCamera.z
    };
    setState(prev => ({
      ...prev,
      cameras: [...prev.cameras, newCam],
      activeCameraIndex: prev.cameras.length
    }));
  };

  const checkErrorAndReset = (err: any) => {
    console.error("Studio AI - System Error:", err);
    let errMsg = "";
    if (typeof err === 'string') errMsg = err;
    else if (err instanceof Error) errMsg = err.message;
    else { try { errMsg = JSON.stringify(err); } catch (e) { errMsg = "Unknown error"; } }

    const isQuotaError = /RESOURCE_EXHAUSTED|limit: 0|quota/i.test(errMsg);
    const isKeyError = /expired|API_KEY_INVALID|INVALID_ARGUMENT|400|401/i.test(errMsg);
    const isNotFoundError = /Requested entity was not found/i.test(errMsg);
    const is500Error = /500|internal/i.test(errMsg);

    if (isQuotaError || isKeyError || isNotFoundError) {
      setHasApiKey(false);
      setQuotaError(isQuotaError ? "API Quota exceeded." : "Invalid API Key.");
      return true;
    }

    if (is500Error) {
      alert("The Studio system encountered a temporary model failure. Please try reducing your image count or resizing your references.");
      return false;
    }

    return false;
  };

  const handleGeneratePrompt = async () => {
    setState(prev => ({ ...prev, isGeneratingPrompt: true }));
    try {
      const prompt = await generateDraftPrompt({ ...state, inferredShotScale });
      setState(prev => ({ ...prev, draftPrompt: prompt, isGeneratingPrompt: false, isReviewingPrompt: true }));
    } catch (err: any) {
      if (!checkErrorAndReset(err)) {
        // Only alert if checkErrorAndReset didn't handle the modal/state
        if (!/500|internal/i.test(String(err))) alert("Analysis failed.");
      }
      setState(prev => ({ ...prev, isGeneratingPrompt: false }));
    }
  };

  const handleFinalRender = async () => {
    setState(prev => ({ ...prev, isGenerating: true, isReviewingPrompt: false }));
    try {
      const result = await generateStudioImage({ ...state, inferredShotScale }, state.draftPrompt);
      setState(prev => ({ ...prev, generatedImage: result, isGenerating: false }));
    } catch (err: any) {
      if (!checkErrorAndReset(err)) alert("Render failed.");
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const handleInitiateVideoReview = () => {
    setPromptView('json');
    setState(prev => ({ ...prev, isReviewingVideoPrompt: true }));
  };

  const handleGenerateVideo = async () => {
    if (!state.generatedImage) return;
    setState(prev => ({ ...prev, isGeneratingVideo: true, isReviewingVideoPrompt: false, videoStatus: "Initializing Production..." }));
    try {
      let script = state.draftPrompt;
      try { 
        const clean = state.draftPrompt.replace(/```json/g, "").replace(/```/g, "").trim();
        const parsed = JSON.parse(clean); 
        script = parsed.script || state.draftPrompt; 
      } catch (e) {}
      const videoUrl = await generateStudioVideo(state, script, state.generatedImage, (status) => setState(prev => ({ ...prev, videoStatus: status })));
      setState(prev => ({ ...prev, generatedVideo: videoUrl, isGeneratingVideo: false, videoStatus: undefined }));
    } catch (err: any) {
      if (!checkErrorAndReset(err)) alert("Animation failed.");
      setState(prev => ({ ...prev, isGeneratingVideo: false, videoStatus: undefined }));
    }
  };

  const openImageInNewWindow = () => {
    if (!state.generatedImage) return;
    const newWindow = window.open();
    if (newWindow) {
      newWindow.document.write(`<body style="margin:0; background:#000; display:flex; align-items:center; justify-content:center;"><img src="${state.generatedImage}" style="max-width:100%; max-height:100%;" /></body>`);
    }
  };

  const renderOptics = () => (
    <section className="space-y-6">
      <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
        <Settings2 className="w-3.5 h-3.5 text-indigo-400" />
        <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40">Optics</h2>
      </div>
      <div className="space-y-4">
        <div className="space-y-2">
           <label className="text-[9px] font-black text-white/30 uppercase tracking-widest ml-1">Focal Length</label>
           <select value={activeCamera.lens} onChange={(e) => updateCamera(state.activeCameraIndex, { lens: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs text-white/60 appearance-none">
             {LENSES.map(l => <option key={l.label} value={l.label} className="bg-[#0d0d0d]">{l.label}</option>)}
           </select>
        </div>
        <div className="space-y-2">
           <label className="text-[9px] font-black text-white/30 uppercase tracking-widest ml-1">Angle</label>
           <select value={activeCamera.verticalAngle} onChange={(e) => updateCamera(state.activeCameraIndex, { verticalAngle: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs text-white/60 appearance-none">
             {VERTICAL_ANGLES.map(a => <option key={a} value={a} className="bg-[#0d0d0d]">{a}</option>)}
           </select>
        </div>
      </div>
    </section>
  );

  if (!hasApiKey || quotaError) {
    return (
      <div className="min-h-screen bg-[#080808] flex items-center justify-center p-6 text-white text-center">
        <div className="max-w-md bg-[#0a0a0a] border border-white/10 p-10 rounded-[2.5rem] space-y-8 shadow-2xl">
          <Key className="w-12 h-12 text-indigo-400 mx-auto" />
          <div className="space-y-2">
            <h1 className="text-xl font-black uppercase tracking-tight">{quotaError ? "System Offline" : "Access Key Required"}</h1>
            <p className="text-white/40 text-sm leading-relaxed">{quotaError || "A paid API key is required to access professional cinematic production models."}</p>
          </div>
          <button onClick={handleOpenSelectKey} className="w-full py-4 bg-indigo-600 rounded-2xl font-black text-xs uppercase tracking-widest">Select API Key</button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 bg-[#080808] flex flex-col text-white overflow-hidden">
      <header className="border-b border-white/5 p-3 bg-[#0a0a0a]/95 backdrop-blur-md flex items-center justify-between sticky top-0 z-[100] shrink-0">
        <div className="flex items-center gap-3">
          <Camera className="w-5 h-5 text-indigo-400" />
          <h1 className="text-sm font-black uppercase tracking-tight">Studio AI</h1>
        </div>
        <div className="flex items-center gap-3">
          {!state.isReviewingPrompt && !state.isReviewingVideoPrompt && !state.generatedImage && (
            <button onClick={handleGeneratePrompt} disabled={state.isGeneratingPrompt} className="px-5 py-2.5 bg-indigo-600 hover:bg-indigo-500 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2">
              {state.isGeneratingPrompt ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Wand2 className="w-3.5 h-3.5" />} Analyze & Render
            </button>
          )}
          {state.isReviewingPrompt && (
            <button onClick={handleFinalRender} className="px-5 py-2.5 bg-emerald-600 hover:bg-emerald-500 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2">
              <Check className="w-3.5 h-3.5" /> Execute Render
            </button>
          )}
          {(state.generatedImage || state.generatedVideo) && (
            <button onClick={() => setState(prev => ({ ...prev, generatedImage: undefined, generatedVideo: undefined, isReviewingPrompt: false, isReviewingVideoPrompt: false }))} className="p-2.5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl transition-all">
              <RotateCw className="w-4 h-4" />
            </button>
          )}
        </div>
      </header>

      <main className="flex-1 flex flex-col lg:flex-row overflow-hidden relative">
        <aside className="hidden lg:flex w-72 bg-[#0a0a0a] border-r border-white/5 flex-col overflow-y-auto p-4 space-y-8">
          <section>
            <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
              <Layers className="w-3.5 h-3.5 text-indigo-400" />
              <h2 className="text-[10px] font-black uppercase tracking-widest text-white/40">Assets</h2>
            </div>
            <div className="grid grid-cols-2 gap-2">
              {REFERENCE_SLOTS.filter(s => state.subjects.activeCount === 2 || !s.id.includes('_b')).map(slot => (
                <ReferenceUploader
                  key={slot.id}
                  slot={slot}
                  dataUrl={state.references[slot.id].dataUrl}
                  onUpload={(data, mime) => handleUpload(slot.id, data, mime)}
                  onRemove={() => setState(prev => ({ ...prev, references: { ...prev.references, [slot.id]: { ...prev.references[slot.id], dataUrl: undefined } } }))}
                />
              ))}
            </div>
          </section>
          <section>
            <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
              <Sun className="w-3.5 h-3.5 text-amber-400" />
              <h2 className="text-[10px] font-black uppercase tracking-widest text-white/40">Lighting</h2>
            </div>
            <LightRig activePositions={state.lighting.positions} onToggle={(i) => setState(prev => { const next = [...prev.lighting.positions]; next[i] = !next[i]; return { ...prev, lighting: { positions: next } }; })} orientation={state.subjects.a.rotation} />
          </section>
        </aside>

        <section className="flex-1 bg-black relative flex flex-col overflow-hidden min-h-0">
          {(activeMobileTab === 'stage' || window.innerWidth >= 1024) ? (
            <div className="flex-1 flex flex-col p-4 lg:p-8 relative min-h-0">
              <div className="flex-1 flex items-center justify-center overflow-hidden relative">
                <FloorPlanner 
                  state={state} 
                  onUpdateSubject={updateSubject} 
                  onUpdateCamera={updateCamera} 
                  onSelectCamera={(idx) => setState(prev => ({ ...prev, activeCameraIndex: idx }))} 
                />

                <div className="absolute top-4 left-4 z-50 flex flex-col gap-2">
                  <button onClick={() => setState(p => ({...p, plannerZoom: Math.min(5, p.plannerZoom * 1.2)}))} className="p-2 bg-[#0d0d0d] border border-white/10 rounded-xl text-white/40 hover:text-white transition-all"><ZoomIn className="w-4 h-4" /></button>
                  <button onClick={() => setState(p => ({...p, plannerZoom: Math.max(0.1, p.plannerZoom / 1.2)}))} className="p-2 bg-[#0d0d0d] border border-white/10 rounded-xl text-white/40 hover:text-white transition-all"><ZoomOut className="w-4 h-4" /></button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 lg:gap-8 mt-4 lg:mt-8 h-48 shrink-0">
                <div className="bg-[#0a0a0a] border border-white/5 rounded-3xl p-4 overflow-y-auto">
                  <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
                    <Compass className="w-3.5 h-3.5 text-indigo-400" />
                    <h2 className="text-[8px] lg:text-[10px] font-black uppercase tracking-widest text-white/40">Rotation</h2>
                  </div>
                  <OrientationSlider config={state.subjects.a} activeCamera={activeCamera} onChange={(v) => updateSubject('a', { rotation: v })} />
                </div>
                <div className="bg-[#0a0a0a] border border-white/5 rounded-3xl p-4 overflow-y-auto">
                  <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
                    <Eye className="w-3.5 h-3.5 text-emerald-400" />
                    <h2 className="text-[8px] lg:text-[10px] font-black uppercase tracking-widest text-white/40">Gaze</h2>
                  </div>
                  <GazeSelector subjectId="a" config={state.subjects.a} activeCamera={activeCamera} onChange={(v) => updateSubject('a', { gaze: v })} />
                </div>
              </div>

              {(state.isGenerating || state.isGeneratingPrompt || state.isGeneratingVideo) && (
                <div className="absolute inset-0 bg-black/70 backdrop-blur-sm z-[200] flex flex-col items-center justify-center gap-4 text-center p-10">
                  <div className="w-16 h-16 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin"></div>
                  <p className="text-xs font-black uppercase tracking-[0.3em]">{state.videoStatus || 'Synthesizing...'}</p>
                </div>
              )}

              {state.generatedImage && !state.generatedVideo && (
                <div className="absolute top-8 right-8 z-[150] w-64 lg:w-80 aspect-video rounded-[2rem] overflow-hidden border border-white/10 shadow-2xl group cursor-pointer" onClick={openImageInNewWindow}>
                  <img src={state.generatedImage} className="w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                    <button onClick={(e) => { e.stopPropagation(); handleInitiateVideoReview(); }} className="px-4 py-2 bg-indigo-600 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2"><Play className="w-3.5 h-3.5 fill-current" /> Animate</button>
                  </div>
                </div>
              )}

              {state.generatedVideo && (
                <div className="absolute inset-0 bg-black z-[200] flex items-center justify-center">
                   <video src={state.generatedVideo} controls autoPlay loop className="max-w-full max-h-full" />
                   <button onClick={() => setState(prev => ({ ...prev, generatedVideo: undefined }))} className="absolute top-10 right-10 p-3 bg-red-600 rounded-2xl shadow-2xl hover:bg-red-500 transition-all"><Trash2 className="w-6 h-6" /></button>
                </div>
              )}
            </div>
          ) : (
            <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
              {activeMobileTab === 'assets' && (
                <div className="space-y-8">
                  <section className="grid grid-cols-2 gap-2">
                    {REFERENCE_SLOTS.map(slot => (
                      <ReferenceUploader key={slot.id} slot={slot} dataUrl={state.references[slot.id].dataUrl} onUpload={(d, m) => handleUpload(slot.id, d, m)} onRemove={() => {}} />
                    ))}
                  </section>
                  <section className="bg-[#0a0a0a] rounded-3xl p-6 border border-white/5">
                    <LightRig activePositions={state.lighting.positions} onToggle={(i) => {}} orientation={0} />
                  </section>
                </div>
              )}
              {activeMobileTab === 'optics' && (
                <div className="bg-[#0a0a0a] rounded-3xl p-6 border border-white/5 space-y-6">
                  {renderOptics()}
                </div>
              )}
            </div>
          )}
        </section>

        {(state.isReviewingPrompt || state.isReviewingVideoPrompt) && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-xl z-[300] flex items-center justify-center p-6">
            <div className="w-full max-w-2xl bg-[#0d0d0d] border border-white/10 rounded-[2.5rem] p-8 flex flex-col max-h-[85%] relative overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-indigo-500 to-emerald-500"></div>
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-xs font-black uppercase tracking-[0.2em] text-white/40">Studio Production Script</h2>
                <button onClick={() => setState(prev => ({ ...prev, isReviewingPrompt: false, isReviewingVideoPrompt: false }))} className="p-2 bg-white/5 rounded-xl"><X className="w-4 h-4" /></button>
              </div>
              <textarea 
                value={state.draftPrompt} 
                onChange={(e) => setState(prev => ({ ...prev, draftPrompt: e.target.value }))} 
                className="flex-1 bg-black/40 rounded-3xl p-6 font-mono text-xs border border-white/5 focus:outline-none focus:border-indigo-500/30 transition-colors resize-none custom-scrollbar" 
              />
              <div className="mt-8 flex gap-4">
                <button onClick={() => setState(prev => ({ ...prev, isReviewingPrompt: false, isReviewingVideoPrompt: false }))} className="flex-1 py-4 bg-white/5 rounded-2xl text-[10px] font-black uppercase tracking-widest">Cancel</button>
                {state.isReviewingVideoPrompt ? (
                  <button onClick={handleGenerateVideo} className="flex-[2] py-4 bg-indigo-600 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2"><Play className="w-3.5 h-3.5 fill-current" /> Animate Performance</button>
                ) : (
                  <button onClick={handleFinalRender} className="flex-[2] py-4 bg-indigo-600 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2"><Check className="w-3.5 h-3.5" /> Execute Render</button>
                )}
              </div>
            </div>
          </div>
        )}

        <aside className="hidden lg:flex w-80 bg-[#0a0a0a] border-l border-white/5 flex-col overflow-y-auto p-4 space-y-8 shrink-0">
          <section className="space-y-4">
            <div className="flex items-center justify-between border-b border-white/5 pb-2">
              <div className="flex items-center gap-2">
                <Camera className="w-3.5 h-3.5 text-indigo-400" />
                <h2 className="text-[10px] font-black uppercase tracking-widest text-white/40">Cameras</h2>
              </div>
              <button onClick={addCamera} disabled={state.cameras.length >= 4} className="p-1.5 bg-indigo-500/10 rounded-lg text-indigo-400 transition-colors hover:bg-indigo-500/20"><Plus className="w-3.5 h-3.5" /></button>
            </div>
            <div className="grid grid-cols-2 gap-2">
              {state.cameras.map((cam, idx) => (
                <button key={cam.id} onClick={() => setState(prev => ({ ...prev, activeCameraIndex: idx }))} className={`px-3 py-2.5 rounded-xl text-[10px] font-black border transition-all ${state.activeCameraIndex === idx ? 'bg-indigo-600 border-indigo-400 shadow-lg shadow-indigo-600/20' : 'bg-white/5 border-white/10 text-white/30 hover:bg-white/10'}`}>CAM {idx + 1}</button>
              ))}
            </div>
          </section>
          {renderOptics()}
          <div className="p-6 bg-indigo-500/5 rounded-[2rem] border border-indigo-500/10">
            <h3 className="text-[9px] font-black uppercase tracking-widest text-indigo-400 mb-2">Technical Summary</h3>
            <p className="text-[10px] text-white/40 leading-relaxed italic">Subject A positioned {Math.round(state.subjects.a.z)}ft deep at {state.subjects.a.rotation}° orientation. Framing currently analyzed as {inferredShotScale}.</p>
          </div>
        </aside>

        <nav className="lg:hidden flex justify-around bg-[#0a0a0a] border-t border-white/5 py-4 shrink-0 z-[160]">
          <button onClick={() => setActiveMobileTab('stage')} className={`flex flex-col items-center gap-1.5 ${activeMobileTab === 'stage' ? 'text-indigo-400' : 'text-white/20'}`}><LayoutGrid className="w-5 h-5" /><span className="text-[8px] font-black uppercase tracking-widest">Stage</span></button>
          <button onClick={() => setActiveMobileTab('assets')} className={`flex flex-col items-center gap-1.5 ${activeMobileTab === 'assets' ? 'text-indigo-400' : 'text-white/20'}`}><Layers className="w-5 h-5" /><span className="text-[8px] font-black uppercase tracking-widest">Assets</span></button>
          <button onClick={() => setActiveMobileTab('optics')} className={`flex flex-col items-center gap-1.5 ${activeMobileTab === 'optics' ? 'text-indigo-400' : 'text-white/20'}`}><SlidersHorizontal className="w-5 h-5" /><span className="text-[8px] font-black uppercase tracking-widest">Optics</span></button>
        </nav>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Camera, Layers, Sun, Trash2, Wand2, Loader2, Settings2, RotateCw, ZoomIn, ZoomOut, Plus, X, Check, Maximize2, Compass, Eye, Key, AlertCircle, Play, Download, LayoutGrid, SlidersHorizontal, Ruler, Target } from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage, SubjectConfig, CameraConfig } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, VERTICAL_ANGLES } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import LightRig from './components/LightRig';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import { generateDraftPrompt, generateStudioImage, generateStudioVideo } from './services/geminiService';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [quotaError, setQuotaError] = useState<string | null>(null);
  const [activeMobileTab, setActiveMobileTab] = useState<'stage' | 'assets' | 'optics'>('stage');
  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    subjects: {
      a: { x: 0, z: 12, rotation: 180, gaze: 180 },
      b: { x: 10, z: 25, rotation: 180, gaze: 180 },
      activeCount: 1,
    },
    cameras: [
      {
        id: 'cam-1',
        x: 0,
        z: 0,
        rotation: 0,
        model: CAMERA_MODELS[0],
        lens: LENSES[2].label,
        verticalAngle: VERTICAL_ANGLES[1],
      }
    ],
    activeCameraIndex: 0,
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    isReviewingVideoPrompt: false,
    isGeneratingVideo: false,
    draftPrompt: '',
    plannerZoom: 1.0,
  });

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(hasKey);
      } else {
        setHasApiKey(true);
      }
    };
    checkKey();
  }, []);

  const handleOpenSelectKey = async () => {
    if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
      await window.aistudio.openSelectKey();
      setQuotaError(null);
      setHasApiKey(true);
    }
  };

  const activeCamera = state.cameras[state.activeCameraIndex];

  // Real-time Production Metrics
  const shotMetrics = useMemo(() => {
    const mm = LENSES.find(l => l.label === activeCamera.lens)?.mm || 50;
    const dx = state.subjects.a.x - activeCamera.x;
    const dz = state.subjects.a.z - activeCamera.z;
    const distInFeet = Math.sqrt(dx * dx + dz * dz);

    // Physical frame height calculation (Full Frame 35mm sensor assumption)
    const distInMm = distInFeet * 304.8;
    const frameHeightInMm = (24 * distInMm) / mm;
    const frameHeightInFeet = frameHeightInMm / 304.8;

    let scale = "Wide Shot (WS)";
    let color = "text-blue-400";

    if (frameHeightInFeet < 1.5) {
      scale = "Extreme Close Up (ECU)";
      color = "text-rose-400";
    } else if (frameHeightInFeet < 4) {
      scale = "Close Up (CU)";
      color = "text-orange-400";
    } else if (frameHeightInFeet < 9) {
      scale = "Medium Shot (MS)";
      color = "text-emerald-400";
    } else if (frameHeightInFeet < 25) {
      scale = "Long Shot (LS)";
      color = "text-indigo-400";
    }

    return {
      distance: distInFeet,
      scale,
      color,
      frameHeight: frameHeightInFeet
    };
  }, [activeCamera, state.subjects.a]);

  const handleUpload = (type: ReferenceType, dataUrl: string, mimeType: string) => {
    setState(prev => ({
      ...prev,
      references: { ...prev.references, [type]: { ...prev.references[type], dataUrl, mimeType } }
    }));
  };

  const updateSubject = (id: 'a' | 'b', updates: Partial<SubjectConfig>) => {
    setState(prev => ({
      ...prev,
      subjects: {
        ...prev.subjects,
        [id]: { ...prev.subjects[id], ...updates }
      }
    }));
  };

  const updateCamera = (index: number, updates: Partial<CameraConfig>) => {
    setState(prev => {
      const newCameras = [...prev.cameras];
      newCameras[index] = { ...newCameras[index], ...updates };
      return { ...prev, cameras: newCameras };
    });
  };

  const addCamera = () => {
    if (state.cameras.length >= 4) return;
    const newCam: CameraConfig = {
      ...activeCamera,
      id: `cam-${Date.now()}`,
      x: activeCamera.x + 10,
      z: activeCamera.z
    };
    setState(prev => ({
      ...prev,
      cameras: [...prev.cameras, newCam],
      activeCameraIndex: prev.cameras.length
    }));
  };

  const checkErrorAndReset = (err: any) => {
    console.error("Studio AI - System Error:", err);
    let errMsg = "";
    if (typeof err === 'string') errMsg = err;
    else if (err instanceof Error) errMsg = err.message;
    else { try { errMsg = JSON.stringify(err); } catch (e) { errMsg = "Unknown error"; } }

    const isQuotaError = /RESOURCE_EXHAUSTED|limit: 0|quota/i.test(errMsg);
    const isKeyError = /expired|API_KEY_INVALID|INVALID_ARGUMENT|400|401/i.test(errMsg);
    const isNotFoundError = /Requested entity was not found/i.test(errMsg);
    const is500Error = /500|internal/i.test(errMsg);

    if (isQuotaError || isKeyError || isNotFoundError) {
      setHasApiKey(false);
      setQuotaError(isQuotaError ? "API Quota exceeded." : "Invalid API Key.");
      return true;
    }

    if (is500Error) {
      alert("The Studio system encountered a temporary model failure. Please try reducing your image count or resizing your references.");
      return false;
    }

    return false;
  };

  const handleGeneratePrompt = async () => {
    setState(prev => ({ ...prev, isGeneratingPrompt: true }));
    try {
      const prompt = await generateDraftPrompt({ ...state, inferredShotScale: shotMetrics.scale });
      setState(prev => ({ ...prev, draftPrompt: prompt, isGeneratingPrompt: false, isReviewingPrompt: true }));
    } catch (err: any) {
      if (!checkErrorAndReset(err)) {
        if (!/500|internal/i.test(String(err))) alert("Analysis failed.");
      }
      setState(prev => ({ ...prev, isGeneratingPrompt: false }));
    }
  };

  const handleFinalRender = async () => {
    setState(prev => ({ ...prev, isGenerating: true, isReviewingPrompt: false }));
    try {
      const result = await generateStudioImage({ ...state, inferredShotScale: shotMetrics.scale }, state.draftPrompt);
      setState(prev => ({ ...prev, generatedImage: result, isGenerating: false }));
    } catch (err: any) {
      if (!checkErrorAndReset(err)) alert("Render failed.");
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const handleInitiateVideoReview = () => {
    setState(prev => ({ ...prev, isReviewingVideoPrompt: true }));
  };

  const handleGenerateVideo = async () => {
    if (!state.generatedImage) return;
    setState(prev => ({ ...prev, isGeneratingVideo: true, isReviewingVideoPrompt: false, videoStatus: "Initializing Production..." }));
    try {
      let script = state.draftPrompt;
      try { 
        const clean = state.draftPrompt.replace(/```json/g, "").replace(/```/g, "").trim();
        const parsed = JSON.parse(clean); 
        script = parsed.script || state.draftPrompt; 
      } catch (e) {}
      const videoUrl = await generateStudioVideo(state, script, state.generatedImage, (status) => setState(prev => ({ ...prev, videoStatus: status })));
      setState(prev => ({ ...prev, generatedVideo: videoUrl, isGeneratingVideo: false, videoStatus: undefined }));
    } catch (err: any) {
      if (!checkErrorAndReset(err)) alert("Animation failed.");
