          <button onClick={() => setActiveMobileTab('assets')} className={`flex flex-col items-center gap-1.5 ${activeMobileTab === 'assets' ? 'text-indigo-400' : 'text-white/20'}`}><Layers className="w-5 h-5" /><span className="text-[8px] font-black uppercase tracking-widest">Assets</span></button>
          <button onClick={() => setActiveMobileTab('optics')} className={`flex flex-col items-center gap-1.5 ${activeMobileTab === 'optics' ? 'text-indigo-400' : 'text-white/20'}`}><SlidersHorizontal className="w-5 h-5" /><span className="text-[8px] font-black uppercase tracking-widest">Optics</span></button>
