import React, { useMemo } from 'react';
import { Camera, Maximize2 } from 'lucide-react';
import { CameraConfig, SubjectConfig, StudioState } from '../types';
import { LENSES } from '../constants';

interface ViewfinderProps {
  state: StudioState;
}

const CameraViewfinder: React.FC<ViewfinderProps> = ({ state }) => {
  const { cameras, activeCameraIndex, subjects } = state;
  const cam = cameras[activeCameraIndex];

  const composition = useMemo(() => {
    const mm = LENSES.find(l => l.label === cam.lens)?.mm || 50;
    const fov = 2 * Math.atan(18 / mm); // Horizontal FOV in radians

    const projectSubject = (sub: SubjectConfig) => {
      // 1. Relative world position
      const dx = sub.x - cam.x;
      const dz = sub.z - cam.z;

      // 2. Rotate into camera space
      // Camera rotation 0 points to Z+. 
      // Rotation is clockwise in degrees.
      const angleRad = -cam.rotation * (Math.PI / 180);
      const localX = dx * Math.cos(angleRad) - dz * Math.sin(angleRad);
      const localZ = dx * Math.sin(angleRad) + dz * Math.cos(angleRad);

      // If behind camera, don't render
      if (localZ <= 0.1) return null;

      // 3. Project to screen X
      // Horizontal range at distance localZ is localZ * tan(fov/2) * 2
      const halfWidthAtZ = localZ * Math.tan(fov / 2);
      const screenX = 50 + (localX / halfWidthAtZ) * 50;

      // 4. Calculate relative scale (Human average height 5.8ft)
      const dist = Math.sqrt(dx*dx + dz*dz);
      // At 10ft with 50mm lens, a human takes up about 40% of height
      const baseScale = (10 / dist) * (mm / 50);

      // 5. Calculate gaze dot
      // Gaze relative to camera axis
      const relativeGaze = (sub.gaze - cam.rotation + 360) % 360;
      const noseX = Math.sin(relativeGaze * Math.PI / 180) * 12; // Offset in silhouette

      return { 
        x: screenX, 
        scale: Math.min(2.5, Math.max(0.05, baseScale)), 
        visible: screenX > -50 && screenX < 150,
        noseX,
        isFacing: relativeGaze > 270 || relativeGaze < 90
      };
    };

    return {
      subA: projectSubject(subjects.a),
      subB: subjects.activeCount === 2 ? projectSubject(subjects.b) : null
    };
  }, [cam, subjects]);

  const horizonY = useMemo(() => {
    if (cam.verticalAngle.includes("Low")) return "75%";
    if (cam.verticalAngle.includes("High")) return "25%";
    if (cam.verticalAngle.includes("Bird")) return "10%";
    return "50%";
  }, [cam.verticalAngle]);

  const renderSubject = (proj: any, color: string, label: string) => {
    if (!proj || !proj.visible) return null;

    return (
      <div 
        className="absolute bottom-0 transition-all duration-75 flex flex-col items-center"
        style={{ 
          left: `${proj.x}%`, 
          transform: `translateX(-50%) scale(${proj.scale})`,
          transformOrigin: 'bottom center',
          zIndex: Math.round(100 / proj.scale)
        }}
      >
        {/* Head */}
        <div className={`w-12 h-12 rounded-full border-2 ${color} bg-black relative mb-1`}>
            {/* Nose Dot */}
            <div 
              className={`absolute top-1/2 w-2 h-2 rounded-full bg-white transition-all shadow-[0_0_8px_white]`}
              style={{ 
                left: '50%', 
                transform: `translate(-50%, -50%) translateX(${proj.noseX}px)`,
                opacity: proj.isFacing ? 1 : 0.2
              }}
            />
        </div>
        {/* Torso */}
        <div className={`w-20 h-32 rounded-t-3xl border-2 ${color} bg-black/40`} />
        <span className="text-[10px] font-black text-white/40 mt-1 scale-50 uppercase tracking-widest">{label}</span>
      </div>
    );
  };

  return (
    <div className="relative w-full aspect-video bg-[#050505] rounded-3xl border border-white/10 overflow-hidden group shadow-2xl">
      {/* Background Horizon */}
      <div 
        className="absolute w-full h-px bg-white/10 transition-all duration-500" 
        style={{ top: horizonY }}
      />

      {/* Grid Floor */}
      <div 
        className="absolute inset-0 opacity-10"
        style={{ 
          backgroundImage: 'radial-gradient(circle at 2px 2px, white 1px, transparent 0)',
          backgroundSize: '40px 40px',
          transform: `perspective(200px) rotateX(60deg) translateY(100px)`,
          transformOrigin: 'bottom center'
        }}
      />

      {/* Subjects */}
      <div className="absolute inset-0 pt-10 px-4 flex items-end justify-center">
        {renderSubject(composition.subA, 'border-indigo-500', 'Subject A')}
        {renderSubject(composition.subB, 'border-purple-500', 'Subject B')}
      </div>

      {/* Composition Overlays */}
      <div className="absolute inset-0 pointer-events-none opacity-20 transition-opacity group-hover:opacity-40">
        <div className="absolute top-1/3 w-full h-px bg-white/50" />
        <div className="absolute top-2/3 w-full h-px bg-white/50" />
        <div className="absolute left-1/3 h-full w-px bg-white/50" />
        <div className="absolute right-1/3 h-full w-px bg-white/50" />
        {/* Center Crosshair */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center">
          <div className="w-full h-px bg-indigo-500/50" />
          <div className="h-full w-px bg-indigo-500/50 absolute" />
        </div>
      </div>

      {/* HUD Information */}
      <div className="absolute inset-0 p-4 flex flex-col justify-between pointer-events-none">
        <div className="flex justify-between items-start">
          <div className="flex items-center gap-2 bg-black/60 backdrop-blur-md px-2 py-1 rounded-lg border border-white/10">
            <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse" />
            <span className="text-[9px] font-black uppercase tracking-widest text-white/80">Live View</span>
          </div>
          <div className="text-right">
             <p className="text-[9px] font-black text-white/40 uppercase tracking-widest">{cam.model}</p>
             <p className="text-[10px] font-mono font-bold text-white/80">{cam.lens} • {cam.verticalAngle.split('(')[0]}</p>
          </div>
        </div>

        <div className="flex justify-between items-end">
          <div className="flex gap-4">
             <div className="flex flex-col">
                <span className="text-[7px] font-black text-white/20 uppercase">F-Stop</span>
                <span className="text-[10px] font-mono font-bold text-white/60">f/1.2</span>
             </div>
             <div className="flex flex-col">
                <span className="text-[7px] font-black text-white/20 uppercase">Shutter</span>
                <span className="text-[10px] font-mono font-bold text-white/60">1/48</span>
             </div>
          </div>
          <Maximize2 className="w-3.5 h-3.5 text-white/20" />
        </div>
      </div>

      {/* Lens Vignette */}
      <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_100px_rgba(0,0,0,0.8)]" />
    </div>
  );
};

