              <div className="space-y-1">
                <span className="text-[8px] text-white/20 uppercase font-black">Shot Scale</span>
                <p className={`text-[10px] font-black uppercase leading-none tracking-tight ${shotMetrics.color}`}>{shotMetrics.scale.split('(')[1].replace(')', '')}</p>
              </div>
              <div className="space-y-1">
                <span className="text-[8px] text-white/20 uppercase font-black">A Depth (Z)</span>
                <p className="text-xs font-mono font-bold text-white/80 tracking-tight">{state.subjects.a.z.toFixed(1)} FT</p>
              </div>
              <div className="space-y-1">
                <span className="text-[8px] text-white/20 uppercase font-black">Orientation</span>
                <p className="text-xs font-mono font-bold text-white/80 tracking-tight">{state.subjects.a.rotation.toFixed(0)}°</p>
              </div>
            </div>

            <p className="text-[9px] text-white/30 leading-relaxed italic border-t border-white/5 pt-3">
              Production analyzed as <span className={`${shotMetrics.color} font-bold`}>{shotMetrics.scale}</span>. 
              Lens aperture simulated at f/1.2 for focus falloff.
            </p>
