                <p className="text-[10px] font-black text-indigo-400 uppercase leading-none">{state.subjects.activeCount === 1 ? 'Solo' : 'Duo'}</p>
              </div>
              <div className="space-y-1">
                <span className="text-[8px] text-white/20 uppercase font-black">Orientation</span>
                <p className="text-xs font-mono font-bold text-white/80 tracking-tight">{state.subjects.a.rotation.toFixed(0)}°</p>
