import { Camera, RotateCw, Eye, Move } from 'lucide-react';
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { CameraConfig, StudioState, SubjectConfig } from '../types';

interface FloorPlannerProps {
  state: StudioState;
  onUpdateSubject: (id: 'a' | 'b', updates: Partial<SubjectConfig>) => void;
  onUpdateCamera: (index: number, updates: Partial<CameraConfig>) => void;
  onUpdatePlanner: (updates: { zoom?: number; offset?: { x: number; z: number } }) => void;
  onSelectCamera: (index: number) => void;
}

const FloorPlanner: React.FC<FloorPlannerProps> = ({ 
  state,
  onUpdateSubject,
  onUpdateCamera,
  onUpdatePlanner,
  onSelectCamera
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dragState, setDragState] = useState<{ 
    type: 'move' | 'rotate-body' | 'rotate-gaze' | 'rotate-cam' | 'pan'; 
    target: 'subject' | 'camera' | 'background';
    id: any;
    startX?: number;
    startY?: number;
    initialOffset?: { x: number; z: number };
  } | null>(null);

  const [pinchState, setPinchState] = useState<{
    initialDist: number;
    initialZoom: number;
  } | null>(null);

  const { subjects, cameras, activeCameraIndex, plannerZoom, plannerOffset } = state;
  const handlersRef = useRef({ onUpdateSubject, onUpdateCamera, onUpdatePlanner, onSelectCamera });

  useEffect(() => {
    handlersRef.current = { onUpdateSubject, onUpdateCamera, onUpdatePlanner, onSelectCamera };
  }, [onUpdateSubject, onUpdateCamera, onUpdatePlanner, onSelectCamera]);

  const getFovAngle = (lens: string) => {
    const mm = lens.match(/(\d+)mm/);
    const focalLength = mm ? parseInt(mm[1]) : 50;
    return 2 * Math.atan(18 / focalLength) * (180 / Math.PI);
  };

  const startDrag = (type: 'move' | 'rotate-body' | 'rotate-gaze' | 'rotate-cam' | 'pan', target: 'subject' | 'camera' | 'background', id: any) => (e: React.MouseEvent | React.TouchEvent | React.PointerEvent) => {
    e.stopPropagation();

    let clientX = 0;
    let clientY = 0;

    if ('clientX' in e) {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    } else if ('touches' in e && e.touches[0]) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    }

    if (target === 'camera' && type === 'move') {
      handlersRef.current.onSelectCamera(id as number);
    }

    setDragState({ 
      type, 
      target, 
      id, 
      startX: clientX, 
      startY: clientY,
      initialOffset: { ...plannerOffset }
    });
  };

  const handlePointerDown = (e: React.PointerEvent) => {
    if (e.target === e.currentTarget || (e.target as HTMLElement).classList.contains('stage-deck')) {
      startDrag('pan', 'background', null)(e);
    }
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    if (e.touches.length === 2) {
      const dist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY
      );
      setPinchState({ initialDist: dist, initialZoom: plannerZoom });
    }
  };

  const handleInteraction = useCallback((clientX: number, clientY: number) => {
    if (!dragState || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const range = 50 / plannerZoom;

    if (dragState.type === 'pan') {
      const dx = (clientX - (dragState.startX || 0)) / rect.width * (range * 2);
      const dz = -(clientY - (dragState.startY || 0)) / rect.height * (range * 2);

      handlersRef.current.onUpdatePlanner({
        offset: {
          x: (dragState.initialOffset?.x || 0) + dx,
          z: (dragState.initialOffset?.z || 0) + dz
        }
      });
      return;
    }

    if (dragState.type === 'move') {
      const coordX = ((clientX - rect.left) / rect.width - 0.5) * (range * 2) - plannerOffset.x;
      const coordZ = (1 - (clientY - rect.top) / rect.height) * (range * 2) - plannerOffset.z;

      if (dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { x: coordX, z: coordZ });
      } else {
        handlersRef.current.onUpdateCamera(dragState.id, { x: coordX, z: coordZ });
      }
    } else {
      const targetObj = dragState.target === 'subject' ? subjects[dragState.id as 'a' | 'b'] : cameras[dragState.id];
      const objScreenX = rect.left + rect.width * (0.5 + (targetObj.x + plannerOffset.x) / (range * 2));
      const objScreenY = rect.top + rect.height * (1 - (targetObj.z + plannerOffset.z) / (range * 2));

      const dx = clientX - objScreenX;
      const dy = clientY - objScreenY;
      let angle = (Math.atan2(dx, -dy) * 180 / Math.PI + 360) % 360;

      if (dragState.type === 'rotate-body' && dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { rotation: angle });
      } else if (dragState.type === 'rotate-gaze' && dragState.target === 'subject') {
        handlersRef.current.onUpdateSubject(dragState.id, { gaze: angle });
      } else if (dragState.type === 'rotate-cam' && dragState.target === 'camera') {
        handlersRef.current.onUpdateCamera(dragState.id, { rotation: angle });
      }
    }
  }, [dragState, plannerZoom, plannerOffset, subjects, cameras]);

  useEffect(() => {
    const onMouseMove = (e: MouseEvent) => handleInteraction(e.clientX, e.clientY);
    const onTouchMove = (e: TouchEvent) => {
      if (e.touches.length === 2 && pinchState) {
        const dist = Math.hypot(
          e.touches[0].clientX - e.touches[1].clientX,
          e.touches[0].clientY - e.touches[1].clientY
        );
        const scale = dist / pinchState.initialDist;
        const newZoom = Math.max(0.1, Math.min(5, pinchState.initialZoom * scale));
        handlersRef.current.onUpdatePlanner({ zoom: newZoom });
      } else if (e.touches[0]) {
        handleInteraction(e.touches[0].clientX, e.touches[0].clientY);
      }
    };
    const onEnd = () => {
      setDragState(null);
      setPinchState(null);
    };

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('touchmove', onTouchMove, { passive: false });
    window.addEventListener('mouseup', onEnd);
    window.addEventListener('touchend', onEnd);

    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('touchmove', onTouchMove);
      window.removeEventListener('mouseup', onEnd);
      window.removeEventListener('touchend', onEnd);
    };
  }, [handleInteraction, pinchState]);

  const getPositionStyle = (obj: {x: number, z: number}) => {
    const range = 50 / plannerZoom;
    const left = `${(((obj.x + plannerOffset.x) / (range * 2)) + 0.5) * 100}%`;
    const bottom = `${((obj.z + plannerOffset.z) / (range * 2)) * 100}%`;
    return { left, bottom };
  };

  const renderSubject = (id: 'a' | 'b', config: SubjectConfig) => {
    const style = getPositionStyle(config);
    return (
      <div 
        key={id}
        style={style}
        className="absolute -translate-x-1/2 translate-y-1/2 z-20 group touch-none"
      >
        <div className="relative w-24 h-24 flex items-center justify-center">
          <div 
            onPointerDown={startDrag('move', 'subject', id)} 
            className="absolute inset-6 rounded-full bg-white/5 border border-white/10 hover:bg-white/20 transition-colors cursor-move z-10"
          />

          <div className="absolute inset-0 transition-transform duration-75" style={{ transform: `rotate(${config.rotation}deg)` }}>
            <svg viewBox="0 0 100 100" className="w-full h-full">
              <ellipse cx="50" cy="50" rx="30" ry="15" fill={id === 'a' ? 'rgba(99, 102, 241, 0.3)' : 'rgba(168, 85, 247, 0.3)'} stroke={id === 'a' ? '#6366f1' : '#a855f7'} strokeWidth="2" />
              <circle cx="50" cy="50" r="10" fill={id === 'a' ? '#6366f1' : '#a855f7'} />
            </svg>
            <div 
              onPointerDown={startDrag('rotate-body', 'subject', id)} 
              className="absolute top-2 left-1/2 -translate-x-1/2 w-6 h-6 bg-white rounded-full flex items-center justify-center cursor-alias shadow-lg border border-black/20 hover:scale-110 transition-transform"
            >
              <RotateCw className="w-3.5 h-3.5 text-black" />
            </div>
          </div>

          <div className="absolute inset-0 pointer-events-none" style={{ transform: `rotate(${config.gaze}deg)` }}>
             <div 
               onPointerDown={startDrag('rotate-gaze', 'subject', id)} 
               className="absolute -top-4 left-1/2 -translate-x-1/2 w-6 h-6 bg-emerald-500 rounded-full flex items-center justify-center cursor-alias shadow-lg border border-black/20 pointer-events-auto hover:scale-110 transition-transform"
             >
                <Eye className="w-3.5 h-3.5 text-white" />
             </div>
          </div>
          <div className="absolute top-full mt-2 px-2 py-0.5 bg-black/80 rounded text-[9px] font-black uppercase tracking-widest text-white/50 border border-white/5">{id}</div>
        </div>
      </div>
    );
  };

  const renderCamera = (cam: CameraConfig, index: number) => {
    const style = getPositionStyle(cam);
    const isActive = index === activeCameraIndex;
    const fov = getFovAngle(cam.lens);
    const fovHalfRad = (fov / 2) * (Math.PI / 180);
    const coneDepth = 80; // Distance to reach top edge in SVG coordinates
    const halfWidth = Math.tan(fovHalfRad) * coneDepth;

    return (
      <div 
        key={cam.id}
        style={style}
        className={`absolute -translate-x-1/2 translate-y-1/2 z-30 transition-all ${isActive ? 'scale-110 z-40' : 'opacity-40 hover:opacity-60'}`}
      >
        <div className="relative w-20 h-20 flex items-center justify-center">
          {/* CAMERA CONE (FRUSTUM) */}
          <div 
            className="absolute top-1/2 left-1/2 w-[300px] h-[300px] -translate-x-1/2 -translate-y-1/2 pointer-events-none z-0"
            style={{ 
              opacity: isActive ? 1 : 0.2,
              transform: `rotate(${cam.rotation}deg)`,
              transition: 'opacity 0.3s ease'
            }}
          >
            <svg viewBox="0 0 100 100" className="w-full h-full overflow-visible">
              <defs>
                <linearGradient id={`frustum-grad-${index}`} x1="50%" y1="50%" x2="50%" y2="0%">
                  <stop offset="0%" stopColor="#818cf8" stopOpacity="0.6" />
                  <stop offset="100%" stopColor="#818cf8" stopOpacity="0" />
                </linearGradient>
                <clipPath id={`frustum-clip-${index}`}>
                   <path d={`M 50 50 L ${50 - halfWidth} ${50 - coneDepth} L ${50 + halfWidth} ${50 - coneDepth} Z`} />
                </clipPath>
              </defs>

              {/* The Cone Path */}
              <path 
                d={`M 50 50 L ${50 - halfWidth} ${50 - coneDepth} L ${50 + halfWidth} ${50 - coneDepth} Z`} 
                fill={`url(#frustum-grad-${index})`}
                stroke="#a5b4fc" 
                strokeWidth="0.8"
                strokeOpacity={isActive ? "1" : "0.5"}
              />

              {/* Rule of Thirds Guide inside the Cone */}
              {isActive && (
                <g clipPath={`url(#frustum-clip-${index})`}>
                   {/* Rule of Thirds - Vertical radiates from center */}
                   <line x1="50" y1="50" x2={`${50 - halfWidth/3}`} y2={`${50 - coneDepth}`} stroke="#818cf8" strokeWidth="0.4" strokeOpacity="0.3" />
                   <line x1="50" y1="50" x2={`${50 + halfWidth/3}`} y2={`${50 - coneDepth}`} stroke="#818cf8" strokeWidth="0.4" strokeOpacity="0.3" />

                   {/* Rule of Thirds - Horizontal (Depth) */}
                   <line x1="0" y1={`${50 - coneDepth * 0.33}`} x2="100" y2={`${50 - coneDepth * 0.33}`} stroke="#818cf8" strokeWidth="0.4" strokeOpacity="0.3" />
                   <line x1="0" y1={`${50 - coneDepth * 0.66}`} x2="100" y2={`${50 - coneDepth * 0.66}`} stroke="#818cf8" strokeWidth="0.4" strokeOpacity="0.3" />
                </g>
              )}
            </svg>
          </div>

          <div 
            onPointerDown={startDrag('move', 'camera', index)}
            className={`absolute inset-4 rounded-xl border-2 flex items-center justify-center cursor-move transition-all z-10 ${isActive ? 'bg-indigo-600 border-indigo-400 text-white shadow-xl shadow-indigo-600/20' : 'bg-zinc-800 border-zinc-600 text-zinc-400'}`}
          >
            <Camera className="w-6 h-6" />
            <div 
              onPointerDown={startDrag('rotate-cam', 'camera', index)}
              className="absolute -top-3 left-1/2 -translate-x-1/2 w-6 h-6 bg-indigo-400 rounded-full flex items-center justify-center cursor-alias shadow-lg border border-black/20 hover:scale-110 transition-transform"
              style={{ transform: `rotate(${cam.rotation}deg) translateY(-24px)` }}
            >
              <RotateCw className="w-3.5 h-3.5 text-black" />
            </div>
          </div>
          <div className="absolute top-full mt-1 px-1.5 py-0.5 bg-black/80 rounded text-[8px] font-black uppercase tracking-widest text-white/40 border border-white/5 z-20">CAM {index + 1}</div>
        </div>
      </div>
    );
  };

  const gridOffset = {
    x: (plannerOffset.x * 30 * plannerZoom) % (30 * plannerZoom),
    z: (plannerOffset.z * 30 * plannerZoom) % (30 * plannerZoom)
  };

  return (
    <div 
      ref={containerRef}
      onPointerDown={handlePointerDown}
      onTouchStart={handleTouchStart}
      className="relative w-full aspect-square bg-[#0d0d0d] border border-white/5 overflow-hidden rounded-[2.5rem] shadow-2xl touch-none cursor-grab active:cursor-grabbing stage-deck"
      style={{ 
        backgroundImage: 'radial-gradient(circle at center, #1a1a1a 1.5px, transparent 1.5px)', 
        backgroundSize: `${30 * plannerZoom}px ${30 * plannerZoom}px`,
        backgroundPosition: `${50 + gridOffset.x}% ${50 - gridOffset.z}%`
      }}
    >
      <div className="absolute inset-0 pointer-events-none border border-white/5 opacity-20" />
      <div className="absolute bottom-4 left-1/2 -translate-x-1/2 px-3 py-1 bg-black/50 backdrop-blur-md rounded-full border border-white/10 text-[8px] font-black text-white/20 uppercase tracking-[0.4em] z-50">Stage Deck</div>

      {/* Subject Layers */}
      {renderSubject('a', subjects.a)}
      {subjects.activeCount === 2 && renderSubject('b', subjects.b)}

      {/* Camera Layers */}
      {cameras.map((cam, i) => renderCamera(cam, i))}
    </div>
  );
};

