import { GoogleGenAI } from "@google/genai";
import { StudioState, CameraConfig, SubjectConfig } from "../types";

/**
 * Image processing with safe defaults for Gemini payloads
 */
async function downscaleImage(dataUrl: string, maxWidth = 512, quality = 0.5): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failure"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Reference image load failed"));
    img.src = dataUrl;
  });
}

export const generateDraftPrompt = async (state: StudioState | any): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const parts: any[] = [];
  const activeCamera = state.cameras[state.activeCameraIndex];
  const isDuo = state.subjects.activeCount === 2;

  // Use a smaller size for the analysis phase
  // Filter references based on mode (Solo vs Duo)
  const allowedRefs = ['background', 'prop', 'char_a', 'pose_a'];
  if (isDuo) allowedRefs.push('char_b', 'pose_b');

  for (const key of allowedRefs) {
    const ref = state.references[key];
    if (ref?.dataUrl) {
      try {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.4);
        parts.push({ text: `REFERENCE_${key.toUpperCase()}:` });
        parts.push({ inlineData: { data, mimeType } });
      } catch (e) {
        console.warn(`Skipping reference ${key} due to processing error`, e);
      }
    }
  }

  const subjectAInfo = `Subject A is at X:${state.subjects.a.x}, Z:${state.subjects.a.z}, facing ${state.subjects.a.rotation}°, gaze at ${state.subjects.a.gaze}°.`;
  const subjectBInfo = isDuo ? `Subject B is at X:${state.subjects.b.x}, Z:${state.subjects.b.z}, facing ${state.subjects.b.rotation}°, gaze at ${state.subjects.b.gaze}°.` : "";

  const systemInstruction = `You are a Professional Cinematographer. 
Analyze visual references and technical stage data to create a unified cinematic script.
PRODUCTION MODE: ${isDuo ? 'DUO (Two Characters: A and B)' : 'SOLO (One Character: A)'}
${subjectAInfo}
${subjectBInfo}
Camera: X:${activeCamera.x}, Z:${activeCamera.z}, Lens:${activeCamera.lens}, Angle:${activeCamera.verticalAngle}.
Framing: ${state.inferredShotScale}.

Task: Write a vivid, detailed description (script) of the scene. 
If in DUO mode, you MUST describe the interaction, positioning, and visual identity of BOTH Subject A and Subject B.
Format: Return ONLY valid JSON with a "script" field.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview', // Switched to flash for significantly faster prompt generation
    contents: { 
      parts: [
        ...parts, 
        { text: `DIRECTIVE: Generate JSON script for ${isDuo ? 'TWO characters' : 'ONE character'}.` }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      thinkingConfig: { thinkingBudget: 0 } // Disable thinking for near-instant response
    }
  });

  return response.text || "";
};

export const generateStudioImage = async (state: StudioState | any, draftJson: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  const isDuo = state.subjects.activeCount === 2;
  let script = "";
  try {
    const clean = draftJson.replace(/```json/g, "").replace(/```/g, "").trim();
    const p = JSON.parse(clean);
    script = p.script || draftJson;
  } catch (e) {
    script = draftJson;
  }

  const parts: any[] = [];
  const relevantRefs = ['background', 'char_a', 'pose_a', 'prop'];
  if (isDuo) {
    relevantRefs.push('char_b', 'pose_b');
  }

  for (const key of relevantRefs) {
    const ref = state.references[key];
    if (ref?.dataUrl) {
      try {
        const { data, mimeType } = await downscaleImage(ref.dataUrl, 768, 0.5);
        parts.push({ text: `VISUAL_ASSET_${key.toUpperCase()}:` });
        parts.push({ inlineData: { data, mimeType } });
      } catch (e) {
        console.warn(`Processing failed for ${key}`, e);
      }
    }
  }

  const directive = `RENDER_DIRECTIVE:
1. PRODUCTION_MODE: ${isDuo ? 'DUO (Render Subject A AND Subject B)' : 'SOLO'}
2. SCENE_SCRIPT: ${script}
3. PHYSICS: Camera(X=${activeCamera.x}, Z=${activeCamera.z}), Lens=${activeCamera.lens}.
4. IDENTITY: Strict character match from CHAR_A${isDuo ? ' and CHAR_B' : ''}.
5. POSE: Posture from POSE_A${isDuo ? ' and POSE_B' : ''}.`;

  parts.push({ text: directive });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { 
      imageConfig: { 
        aspectRatio: "16:9", 
        imageSize: "1K" 
      } 
    }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) {
    throw new Error("The image generation model returned no pixel data.");
  }
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

