import { GoogleGenAI, Type } from "@google/genai";
import { StudioState, CameraConfig, SubjectConfig } from "../types";

/**
 * Image processing with safe defaults for Gemini payloads
 */
async function downscaleImage(dataUrl: string, maxWidth = 512, quality = 0.5): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failure"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Reference image load failed"));
    img.src = dataUrl;
  });
}

export const generateDraftPrompt = async (state: StudioState | any): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  const isDuo = state.subjects.activeCount === 2;

  const allowedRefs = ['background', 'prop', 'char_a', 'pose_a'];
  if (isDuo) allowedRefs.push('char_b', 'pose_b');

  // Parallelize image processing for speed
  const processedRefs = await Promise.all(
    allowedRefs.map(async (key) => {
      const ref = state.references[key];
      if (ref?.dataUrl) {
        try {
          const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.4);
          return { key, data, mimeType };
        } catch (e) {
          console.warn(`Skipping reference ${key}`, e);
          return null;
        }
      }
      return null;
    })
  );

  const parts: any[] = [];
  processedRefs.forEach(ref => {
    if (ref) {
      parts.push({ text: `REFERENCE_${ref.key.toUpperCase()}:` });
      parts.push({ inlineData: { data: ref.data, mimeType: ref.mimeType } });
    }
  });

  const subjectAInfo = `Subject A is at X:${state.subjects.a.x}, Z:${state.subjects.a.z}, facing ${state.subjects.a.rotation}°, gaze at ${state.subjects.a.gaze}°.`;
  const subjectBInfo = isDuo ? `Subject B is at X:${state.subjects.b.x}, Z:${state.subjects.b.z}, facing ${state.subjects.b.rotation}°, gaze at ${state.subjects.b.gaze}°.` : "";

  const systemInstruction = `You are a Professional Virtual Production Director.
Analyze visual references and technical stage data to create a unified cinematic script for an image generation model.
PRODUCTION MODE: ${isDuo ? 'DUO (RENDER TWO CHARACTERS: A AND B)' : 'SOLO (RENDER ONE CHARACTER: A)'}

TECHNICAL CONTEXT:
${subjectAInfo}
${subjectBInfo}
Camera Position: X:${activeCamera.x}, Z:${activeCamera.z}
Optics: Lens ${activeCamera.lens}, Vertical Angle ${activeCamera.verticalAngle}
Framing Objective: ${state.inferredShotScale}

INSTRUCTIONS:
1. Write a vivid, professional cinematic description.
2. If in DUO mode, you MUST explicitly describe BOTH Subject A and Subject B, their interactions, relative positions, and distinct visual identities based on CHAR_A/POSE_A and CHAR_B/POSE_B.
3. Ensure the environment matches the BACKGROUND reference.
4. Integrate any PROP reference naturally into the scene.
5. Focus on lighting, texture, and technical accuracy.

Format the output as a JSON object with a single "script" string property.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `TASK: Generate a ${isDuo ? 'Dual-Character' : 'Single-Character'} Production Script.` }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          script: {
            type: Type.STRING,
            description: "The cinematic scene description."
          }
        },
        required: ["script"]
      },
      thinkingConfig: { thinkingBudget: 0 }
    }
  });

  try {
    const parsed = JSON.parse(response.text || "{}");
    return parsed.script || response.text || "";
  } catch (e) {
    return response.text || "";
  }
};

export const generateStudioImage = async (state: StudioState | any, draftJson: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  const isDuo = state.subjects.activeCount === 2;

  let script = "";
  try {
    const clean = draftJson.replace(/```json/g, "").replace(/```/g, "").trim();
    const p = JSON.parse(clean);
    script = p.script || draftJson;
  } catch (e) {
    script = draftJson;
  }

  const relevantRefs = ['background', 'char_a', 'pose_a', 'prop'];
  if (isDuo) relevantRefs.push('char_b', 'pose_b');

  const processedAssets = await Promise.all(
    relevantRefs.map(async (key) => {
      const ref = state.references[key];
      if (ref?.dataUrl) {
        try {
          const { data, mimeType } = await downscaleImage(ref.dataUrl, 768, 0.5);
          return { key, data, mimeType };
        } catch (e) {
          return null;
        }
      }
      return null;
    })
  );

  const parts: any[] = [];
  processedAssets.forEach(asset => {
    if (asset) {
      parts.push({ text: `VISUAL_ASSET_${asset.key.toUpperCase()}:` });
      parts.push({ inlineData: { data: asset.data, mimeType: asset.mimeType } });
    }
  });

  const directive = `RENDER_DIRECTIVE:
1. PRODUCTION_MODE: ${isDuo ? 'DUO PERFORMANCE (RENDER TWO CHARACTERS)' : 'SOLO PERFORMANCE'}
2. CINEMATIC_SCRIPT: ${script}
3. PERSPECTIVE: Camera(X=${activeCamera.x}, Z=${activeCamera.z}), Lens=${activeCamera.lens}.
4. SUBJECT_A: Visual identity from CHAR_A, pose from POSE_A.
${isDuo ? '5. SUBJECT_B: Visual identity from CHAR_B, pose from POSE_B. SUBJECTS MUST BOTH BE VISIBLE.' : ''}`;

  parts.push({ text: directive });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { 
      imageConfig: { 
        aspectRatio: "16:9", 
        imageSize: "1K" 
      } 
    }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) {
    throw new Error("The image generation model failed to produce pixel data. Check your prompt or references.");
  }
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

