const App: React.FC = () => {
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [quotaError, setQuotaError] = useState<string | null>(null);
  const [activeMobileTab, setActiveMobileTab] = useState<'stage' | 'assets' | 'optics'>('stage');

  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    subjects: {
      a: { x: -5, z: 12, rotation: 180, gaze: 180 },
      b: { x: 5, z: 12, rotation: 180, gaze: 180 },
      activeCount: 1,
    },
    cameras: [
      {
        id: 'cam-1',
        x: 0,
        z: 0,
        rotation: 0,
        model: CAMERA_MODELS[0],
        lens: LENSES[2].label,
        verticalAngle: VERTICAL_ANGLES[1],
      }
    ],
    activeCameraIndex: 0,
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    isReviewingVideoPrompt: false,
    isGeneratingVideo: false,
    draftPrompt: '',
    plannerZoom: 1.0,
    plannerOffset: { x: 0, z: 0 },
  });

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(hasKey);
      } else {
        setHasApiKey(true);
      }
    };
    checkKey();
  }, []);

  const handleOpenSelectKey = async () => {
    if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
      await window.aistudio.openSelectKey();
      setQuotaError(null);
      setHasApiKey(true);
    }
  };

  const activeCamera = state.cameras[state.activeCameraIndex];

  const shotMetrics = useMemo(() => {
    const mm = LENSES.find(l => l.label === activeCamera.lens)?.mm || 50;

    // Group midpoint for distance in Duo mode
    const targetX = state.subjects.activeCount === 2 
      ? (state.subjects.a.x + state.subjects.b.x) / 2 
      : state.subjects.a.x;
    const targetZ = state.subjects.activeCount === 2 
      ? (state.subjects.a.z + state.subjects.b.z) / 2 
      : state.subjects.a.z;

    const dx = targetX - activeCamera.x;
    const dz = targetZ - activeCamera.z;
    const distInFeet = Math.sqrt(dx * dx + dz * dz);

    const distInMm = distInFeet * 304.8;
    const frameHeightInMm = (24 * distInMm) / mm;
    const frameHeightInFeet = frameHeightInMm / 304.8;

    let scale = "Wide Shot (WS)";
    let color = "text-blue-400";

    if (frameHeightInFeet < 1.5) {
      scale = "Extreme Close Up (ECU)";
      color = "text-rose-400";
    } else if (frameHeightInFeet < 4) {
      scale = "Close Up (CU)";
      color = "text-orange-400";
    } else if (frameHeightInFeet < 9) {
      scale = "Medium Shot (MS)";
      color = "text-emerald-400";
    } else if (frameHeightInFeet < 25) {
      scale = "Long Shot (LS)";
      color = "text-indigo-400";
    }

    return {
      distance: distInFeet,
      scale,
      color,
      frameHeight: frameHeightInFeet
    };
  }, [activeCamera, state.subjects.a, state.subjects.b, state.subjects.activeCount]);

  const handleUpload = (type: ReferenceType, dataUrl: string, mimeType: string) => {
    setState(prev => ({
      ...prev,
      references: { ...prev.references, [type]: { ...prev.references[type], dataUrl, mimeType } }
    }));
  };

  const updateSubject = (id: 'a' | 'b', updates: Partial<SubjectConfig>) => {
    setState(prev => ({
      ...prev,
      subjects: {
        ...prev.subjects,
        [id]: { ...prev.subjects[id], ...updates }
