import React, { useMemo } from 'react';
import { Camera, Maximize2 } from 'lucide-react';
import { CameraConfig, SubjectConfig, StudioState } from '../types';
import { LENSES } from '../constants';

interface ViewfinderProps {
  state: StudioState;
  inferredScale?: string;
}

const CameraViewfinder: React.FC<ViewfinderProps> = ({ state, inferredScale }) => {
  const { cameras, activeCameraIndex, subjects } = state;
  const cam = cameras[activeCameraIndex];

  const composition = useMemo(() => {
    const mm = LENSES.find(l => l.label === cam.lens)?.mm || 50;
    const aspect = 16 / 9;

    // Physics constant: Sensor height is 24mm (Full Frame standard)
    const sensorHeight = 24;

    const projectSubject = (sub: SubjectConfig) => {
      // 1. World displacement
      const dx = sub.x - cam.x;
      const dz = sub.z - cam.z;

      // 2. Local space (Camera coordinate system)
      // Camera rotation 0 faces Stage Deep (+Z).
      const rotRad = -cam.rotation * (Math.PI / 180);
      const localX = dx * Math.cos(rotRad) - dz * Math.sin(rotRad);
      const localZ = dx * Math.sin(rotRad) + dz * Math.cos(rotRad);

      // Behind camera check
      if (localZ <= 0.1) return null;

      // 3. Physical Frame Calculation (Feet)
      // FrameHeight = (SensorHeight * Distance) / FocalLength
      const frameHeightAtZ = (sensorHeight * localZ) / mm;
      const frameWidthAtZ = frameHeightAtZ * aspect;

      // 4. Vertical Projection (Feet)
      let cameraY = 5.0; // Standard eye level
      if (cam.verticalAngle.includes("Low")) cameraY = 1.5;
      if (cam.verticalAngle.includes("High")) cameraY = 12.0;
      if (cam.verticalAngle.includes("Bird")) cameraY = 30.0;

      const subjectHeadY = 5.5; // Avg head center height
      const relativeY = subjectHeadY - cameraY;

      // 5. Screen Mapping (%)
      // Center of screen is 50%. Offset is (LocalCoord / (TotalRange/2)) * 50
      const screenX = 50 + (localX / (frameWidthAtZ / 2)) * 50;

      // Cinematic Framing Logic:
      // In closeups, we want to see more head detail and less empty space above.
      // We adjust vertical projection to favor the upper third for the head.
      let verticalAdjustment = 0;
      if (frameHeightAtZ < 4) { // CU
        verticalAdjustment = 8;
      } else if (frameHeightAtZ < 9) { // MS
        verticalAdjustment = 4;
      }

      const screenY = 50 - (relativeY / (frameHeightAtZ / 2)) * 50 + verticalAdjustment;

      // 6. Visual Scaling
      // If subject is 6ft tall, and frame is H_ft tall, subject should occupy (6/H) of height.
      // Our SVG 'human' is base 100px? No, we use scale on the div.
      // We target the visual scale to match the percentage of the frame height occupied.
      const subjectPhysicalHeight = 6.0;
      const visualScale = (subjectPhysicalHeight / frameHeightAtZ) * 4.5; // Multiplier to normalize div size

      // 7. Gaze Orientation
      const angleToCam = (Math.atan2(cam.x - sub.x, cam.z - sub.z) * 180 / Math.PI + 360) % 360;
      const gazeDiff = Math.abs((sub.gaze - angleToCam + 540) % 360 - 180);
      const isFacing = gazeDiff < 45;
      const relativeGazeRad = (sub.gaze - angleToCam) * (Math.PI / 180);
      const gazeX = Math.sin(relativeGazeRad);

      return { 
        x: screenX, 
        y: screenY,
        scale: Math.min(20, Math.max(0.1, visualScale)),
        visible: screenX > -50 && screenX < 150 && localZ > 0.1,
        gazeX,
        isFacing,
        dist: localZ
      };
    };

    return {
      subA: projectSubject(subjects.a),
      subB: subjects.activeCount === 2 ? projectSubject(subjects.b) : null
    };
  }, [cam, subjects]);

  const renderSubject = (proj: any, color: string, label: string) => {
    if (!proj || !proj.visible) return null;

    const zIndex = Math.round(1000 - proj.dist * 10);

    return (
      <div 
        className="absolute transition-all duration-150 ease-out flex flex-col items-center pointer-events-none"
        style={{ 
          left: `${proj.x}%`, 
          top: `${proj.y}%`,
          transform: `translate(-50%, -10%) scale(${proj.scale})`,
          transformOrigin: 'top center',
          zIndex
        }}
      >
        {/* Head Visual */}
        <div className={`w-10 h-10 rounded-full border-2 ${color} bg-black/90 relative flex items-center justify-center shadow-2xl`}>
            <div 
              className="flex gap-1.5 transition-transform duration-200"
              style={{ transform: `translateX(${proj.gazeX * 4}px)` }}
            >
              <div className={`w-1.5 h-1.5 rounded-full ${proj.isFacing ? 'bg-white shadow-[0_0_5px_white]' : 'bg-white/10'}`} />
              <div className={`w-1.5 h-1.5 rounded-full ${proj.isFacing ? 'bg-white shadow-[0_0_5px_white]' : 'bg-white/10'}`} />
            </div>
        </div>

        {/* Torso Visual */}
        <div className={`w-16 h-32 -mt-1 rounded-t-[2.5rem] border-2 ${color} bg-black/40 backdrop-blur-sm relative overflow-hidden`}>
           <div className="absolute top-4 left-1/2 -translate-x-1/2 w-8 h-px bg-white/5" />
           <div className="absolute top-1/2 left-1/2 -translate-x-1/2 w-12 h-px bg-white/5" />
        </div>

        {/* HUD Data Tag */}
        <div className="mt-4 bg-black/80 backdrop-blur-md px-2 py-0.5 rounded-md border border-white/10 flex items-center gap-1.5">
          <span className="text-[6px] font-black text-white/40 uppercase tracking-widest">{label}</span>
          <span className="text-[5px] font-bold text-indigo-400 font-mono">Z:{proj.dist.toFixed(1)}FT</span>
        </div>
      </div>
    );
  };

  const currentScaleTag = inferredScale || "WS";
  const shortScaleTag = currentScaleTag.includes("(") ? currentScaleTag.split("(")[1].replace(")", "") : currentScaleTag;

  return (
    <div className="relative w-full aspect-video bg-[#030303] rounded-3xl border border-white/10 overflow-hidden shadow-2xl group select-none">
      {/* Cinematic Grid Lines */}
      <div className="absolute inset-0 pointer-events-none z-10 opacity-30">
        <div className="absolute top-1/3 w-full h-px bg-white/20" />
        <div className="absolute top-2/3 w-full h-px bg-white/20" />
        <div className="absolute left-1/3 h-full w-px bg-white/20" />
        <div className="absolute right-1/3 h-full w-px bg-white/20" />
      </div>

      {/* Frame Status Metadata */}
      <div className="absolute top-4 left-4 z-40 flex items-center gap-2">
        <div className="flex items-center gap-2 bg-black/60 backdrop-blur-md px-2.5 py-1.5 rounded-xl border border-white/10">
          <div className="w-2 h-2 rounded-full bg-red-600 animate-pulse shadow-[0_0_8px_red]" />
          <span className="text-[8px] font-mono font-bold text-white/90 tracking-tighter uppercase">Production Monitor</span>
        </div>
        <div className="bg-indigo-600/30 backdrop-blur-md px-2.5 py-1.5 rounded-xl border border-indigo-500/40">
          <span className="text-[9px] font-black text-indigo-400 font-mono tracking-widest uppercase">{shortScaleTag}</span>
        </div>
      </div>

      <div className="absolute bottom-4 right-4 z-40 text-right opacity-80">
        <p className="text-[10px] font-mono font-black text-white tracking-[0.2em] leading-none mb-1">{cam.lens.toUpperCase()}</p>
        <p className="text-[7px] font-bold text-white/30 uppercase tracking-[0.4em]">{cam.model}</p>
      </div>

      {/* Horizon & Depth Guides */}
      <div 
        className="absolute w-full h-px bg-white/5 z-0 pointer-events-none transition-all duration-700" 
        style={{ 
          top: cam.verticalAngle.includes("Low") ? "80%" : 
               cam.verticalAngle.includes("High") ? "30%" : 
               cam.verticalAngle.includes("Bird") ? "10%" : "50%" 
        }} 
      />

      {/* Subject Scene Layer */}
      <div className="absolute inset-0 z-20 overflow-hidden">
        {renderSubject(composition.subA, 'border-indigo-500', 'SUB_A')}
        {renderSubject(composition.subB, 'border-emerald-500', 'SUB_B')}
      </div>

      {/* Lens Vignette & Grading */}
      <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_150px_rgba(0,0,0,0.9)] z-30" />

      {/* Crop Brackets */}
      <div className="absolute inset-6 border border-white/5 rounded-3xl pointer-events-none z-30" />
      <div className="absolute top-8 left-8 w-4 h-4 border-t-2 border-l-2 border-white/20 z-40 rounded-tl-sm" />
      <div className="absolute top-8 right-8 w-4 h-4 border-t-2 border-r-2 border-white/20 z-40 rounded-tr-sm" />
      <div className="absolute bottom-8 left-8 w-4 h-4 border-b-2 border-l-2 border-white/20 z-40 rounded-bl-sm" />
      <div className="absolute bottom-8 right-8 w-4 h-4 border-b-2 border-r-2 border-white/20 z-40 rounded-br-sm" />
    </div>
  );
};

export default CameraViewfinder;

import React, { useState, useMemo, useEffect } from 'react';
import { Camera, Layers, Sun, Trash2, Wand2, Loader2, Settings2, RotateCw, ZoomIn, ZoomOut, Plus, X, Check, Maximize2, Compass, Eye, Key, AlertCircle, Play, Download, LayoutGrid, SlidersHorizontal, Ruler, Target, MonitorPlay, Users, User } from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage, SubjectConfig, CameraConfig } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, VERTICAL_ANGLES } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import LightRig from './components/LightRig';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import CameraViewfinder from './components/CameraViewfinder';
import { generateDraftPrompt, generateStudioImage, generateStudioVideo } from './services/geminiService';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [hasApiKey, setHasApiKey] = useState<boolean>(false);
  const [quotaError, setQuotaError] = useState<string | null>(null);
  const [activeMobileTab, setActiveMobileTab] = useState<'stage' | 'assets' | 'optics'>('stage');

  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: {
      positions: new Array(8).fill(false),
    },
    subjects: {
      a: { x: -5, z: 12, rotation: 180, gaze: 180 },
      b: { x: 5, z: 12, rotation: 180, gaze: 180 },
      activeCount: 1,
    },
    cameras: [
      {
        id: 'cam-1',
        x: 0,
        z: 0,
        rotation: 0,
        model: CAMERA_MODELS[0],
        lens: LENSES[2].label,
        verticalAngle: VERTICAL_ANGLES[1],
      }
    ],
    activeCameraIndex: 0,
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    isReviewingVideoPrompt: false,
    isGeneratingVideo: false,
    draftPrompt: '',
    plannerZoom: 1.0,
    plannerOffset: { x: 0, z: 0 },
  });

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(hasKey);
      } else {
        setHasApiKey(true);
      }
    };
    checkKey();
  }, []);

  const handleOpenSelectKey = async () => {
    if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
      await window.aistudio.openSelectKey();
      setQuotaError(null);
      setHasApiKey(true);
    }
  };

  const activeCamera = state.cameras[state.activeCameraIndex];

  const shotMetrics = useMemo(() => {
    const mm = LENSES.find(l => l.label === activeCamera.lens)?.mm || 50;

    // Group midpoint for framing calculation
    const targetX = state.subjects.activeCount === 2 
      ? (state.subjects.a.x + state.subjects.b.x) / 2 
      : state.subjects.a.x;
    const targetZ = state.subjects.activeCount === 2 
      ? (state.subjects.a.z + state.subjects.b.z) / 2 
      : state.subjects.a.z;

    const dx = targetX - activeCamera.x;
    const dz = targetZ - activeCamera.z;

    // PROJECT DISTANCE ALONG OPTICAL AXIS (Local Z)
    // This is the distance that determines framing in cinematic optics.
    const rotRad = -activeCamera.rotation * (Math.PI / 180);
    const localZ = dx * Math.sin(rotRad) + dz * Math.cos(rotRad);

    // Use localZ if subject is in front of camera, otherwise fallback to Euclidean for safety
    const distInFeet = localZ > 0.1 ? localZ : Math.sqrt(dx * dx + dz * dz);

    // Physical Frame Height (feet) = (SensorHeight[24mm] * Distance[ft]) / Lens[mm]
    const frameHeightInFeet = (24 * distInFeet) / mm;

    let scale = "Wide Shot (WS)";
    let color = "text-blue-400";

    if (frameHeightInFeet < 1.5) {
      scale = "Extreme Close Up (ECU)";
      color = "text-rose-400";
    } else if (frameHeightInFeet < 4) {
      scale = "Close Up (CU)";
      color = "text-orange-400";
    } else if (frameHeightInFeet < 9) {
      scale = "Medium Shot (MS)";
      color = "text-emerald-400";
    } else if (frameHeightInFeet < 25) {
      scale = "Long Shot (LS)";
      color = "text-indigo-400";
    }

    return {
      distance: distInFeet,
      scale,
      color,
      frameHeight: frameHeightInFeet
    };
  }, [activeCamera, state.subjects.a, state.subjects.b, state.subjects.activeCount]);

  const handleUpload = (type: ReferenceType, dataUrl: string, mimeType: string) => {
    setState(prev => ({
      ...prev,
      references: { ...prev.references, [type]: { ...prev.references[type], dataUrl, mimeType } }
    }));
  };

  const updateSubject = (id: 'a' | 'b', updates: Partial<SubjectConfig>) => {
    setState(prev => ({
      ...prev,
      subjects: {
        ...prev.subjects,
        [id]: { ...prev.subjects[id], ...updates }
      }
    }));
  };

  const updateCamera = (index: number, updates: Partial<CameraConfig>) => {
    setState(prev => {
      const newCameras = [...prev.cameras];
      newCameras[index] = { ...newCameras[index], ...updates };
      return { ...prev, cameras: newCameras };
    });
  };

  const updatePlanner = (updates: { zoom?: number; offset?: { x: number; z: number } }) => {
    setState(prev => ({
      ...prev,
      plannerZoom: updates.zoom !== undefined ? updates.zoom : prev.plannerZoom,
      plannerOffset: updates.offset !== undefined ? updates.offset : prev.plannerOffset,
    }));
  };

  const toggleSubjects = () => {
    setState(prev => ({
      ...prev,
      subjects: {
        ...prev.subjects,
        activeCount: prev.subjects.activeCount === 1 ? 2 : 1
      }
    }));
  };

  const addCamera = () => {
    if (state.cameras.length >= 4) return;
    const newCam: CameraConfig = {
      ...activeCamera,
      id: `cam-${Date.now()}`,
      x: activeCamera.x + 10,
      z: activeCamera.z
    };
    setState(prev => ({
      ...prev,
      cameras: [...prev.cameras, newCam],
      activeCameraIndex: prev.cameras.length
    }));
  };

  const checkErrorAndReset = (err: any) => {
    console.error("Studio AI Error:", err);
    let errMsg = "";
    if (typeof err === 'string') errMsg = err;
    else if (err instanceof Error) errMsg = err.message;
    else { try { errMsg = JSON.stringify(err); } catch (e) { errMsg = "Unknown error"; } }

    const isQuotaError = /RESOURCE_EXHAUSTED|limit: 0|quota/i.test(errMsg);
    const isKeyError = /expired|API_KEY_INVALID|INVALID_ARGUMENT|400|401/i.test(errMsg);
    const isNotFoundError = /Requested entity was not found/i.test(errMsg);

    if (isQuotaError || isKeyError || isNotFoundError) {
      setHasApiKey(false);
      setQuotaError(isQuotaError ? "API Quota exceeded." : "Invalid API Key.");
      return true;
    }
    return false;
  };

  const handleGeneratePrompt = async () => {
    setState(prev => ({ ...prev, isGeneratingPrompt: true }));
    try {
      const prompt = await generateDraftPrompt({ ...state, inferredShotScale: shotMetrics.scale });
      setState(prev => ({ ...prev, draftPrompt: prompt, isGeneratingPrompt: false, isReviewingPrompt: true }));
    } catch (err: any) {
      if (!checkErrorAndReset(err)) alert("Stage analysis failed. Check connectivity.");
      setState(prev => ({ ...prev, isGeneratingPrompt: false }));
    }
  };

  const handleFinalRender = async () => {
    setState(prev => ({ ...prev, isGenerating: true, isReviewingPrompt: false }));
    try {
      const result = await generateStudioImage({ ...state, inferredShotScale: shotMetrics.scale }, state.draftPrompt);
      setState(prev => ({ ...prev, generatedImage: result, isGenerating: false }));
    } catch (err: any) {
      if (!checkErrorAndReset(err)) alert("Final render failed.");
      setState(prev => ({ ...prev, isGenerating: false }));
    }
  };

  const handleInitiateVideoReview = () => {
    setState(prev => ({ ...prev, isReviewingVideoPrompt: true }));
  };

  const handleGenerateVideo = async () => {
    if (!state.generatedImage) return;
    setState(prev => ({ ...prev, isGeneratingVideo: true, isReviewingVideoPrompt: false, videoStatus: "Initializing Motion..." }));
    try {
      let script = state.draftPrompt;
      try { 
        const clean = state.draftPrompt.replace(/```json/g, "").replace(/```/g, "").trim();
        const parsed = JSON.parse(clean); 
        script = parsed.script || state.draftPrompt; 
      } catch (e) {}
      const videoUrl = await generateStudioVideo(state, script, state.generatedImage, (status) => setState(prev => ({ ...prev, videoStatus: status })));
      setState(prev => ({ ...prev, generatedVideo: videoUrl, isGeneratingVideo: false, videoStatus: undefined }));
    } catch (err: any) {
      if (!checkErrorAndReset(err)) alert("Animation failed.");
      setState(prev => ({ ...prev, isGeneratingVideo: false, videoStatus: undefined }));
    }
  };

  const openImageInNewWindow = () => {
    if (!state.generatedImage) return;
    const newWindow = window.open();
    if (newWindow) {
      newWindow.document.write(`<body style="margin:0; background:#000; display:flex; align-items:center; justify-content:center;"><img src="${state.generatedImage}" style="max-width:100%; max-height:100%;" /></body>`);
    }
  };

  const renderOptics = () => (
    <section className="space-y-6">
      <div className="flex items-center gap-2 mb-4 border-b border-white/5 pb-2">
        <Settings2 className="w-3.5 h-3.5 text-indigo-400" />
        <h2 className="text-[10px] font-black uppercase tracking-[0.2em] text-white/40">Optics</h2>
      </div>
      <div className="space-y-4">
        <div className="space-y-2">
           <label className="text-[9px] font-black text-white/30 uppercase tracking-widest ml-1">Focal Length</label>
           <select value={activeCamera.lens} onChange={(e) => updateCamera(state.activeCameraIndex, { lens: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs text-white/60 appearance-none focus:outline-none focus:border-indigo-500/30">
             {LENSES.map(l => <option key={l.label} value={l.label} className="bg-[#0d0d0d]">{l.label}</option>)}
           </select>
        </div>
        <div className="space-y-2">
           <label className="text-[9px] font-black text-white/30 uppercase tracking-widest ml-1">Angle</label>
           <select value={activeCamera.verticalAngle} onChange={(e) => updateCamera(state.activeCameraIndex, { verticalAngle: e.target.value })} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-xs text-white/60 appearance-none focus:outline-none focus:border-indigo-500/30">
             {VERTICAL_ANGLES.map(a => <option key={a} value={a} className="bg-[#0d0d0d]">{a}</option>)}
           </select>
        </div>
      </div>
    </section>
  );

  const renderAssetsList = () => (
    <div className="grid grid-cols-2 gap-2">
      {REFERENCE_SLOTS.filter(s => state.subjects.activeCount === 2 || !s.id.includes('_b')).map(slot => (
        <ReferenceUploader
          key={slot.id}
          slot={slot}
          dataUrl={state.references[slot.id].dataUrl}
          onUpload={(data, mime) => handleUpload(slot.id, data, mime)}
          onRemove={() => setState(prev => ({ ...prev, references: { ...prev.references, [slot.id]: { ...prev.references[slot.id], dataUrl: undefined } } }))}
        />
      ))}
    </div>
  );

  if (!hasApiKey || quotaError) {
    return (
      <div className="min-h-screen bg-[#080808] flex items-center justify-center p-6 text-white text-center">
        <div className="max-w-md bg-[#0a0a0a] border border-white/10 p-10 rounded-[2.5rem] space-y-8 shadow-2xl">
          <Key className="w-12 h-12 text-indigo-400 mx-auto" />
          <div className="space-y-2">
            <h1 className="text-xl font-black uppercase tracking-tight">{quotaError ? "System Offline" : "Access Key Required"}</h1>
            <p className="text-white/40 text-sm leading-relaxed">{quotaError || "A paid API key is required to access professional cinematic production models."}</p>
          </div>
          <button onClick={handleOpenSelectKey} className="w-full py-4 bg-indigo-600 rounded-2xl font-black text-xs uppercase tracking-widest">Select API Key</button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 bg-[#080808] flex flex-col text-white overflow-hidden">
      <header className="border-b border-white/5 p-3 bg-[#0a0a0a]/95 backdrop-blur-md flex items-center justify-between sticky top-0 z-[100] shrink-0">
        <div className="flex items-center gap-3">
          <Camera className="w-5 h-5 text-indigo-400" />
          <h1 className="text-sm font-black uppercase tracking-tight">Studio AI</h1>
        </div>
        <div className="flex items-center gap-3">
          {!state.isReviewingPrompt && !state.isReviewingVideoPrompt && !state.generatedImage && (
            <button onClick={handleGeneratePrompt} disabled={state.isGeneratingPrompt} className="px-5 py-2.5 bg-indigo-600 hover:bg-indigo-500 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center gap-2">
