            {(state.isGenerating || state.isGeneratingPrompt || state.isGeneratingVideo) && (
              <div className="absolute inset-0 bg-black/70 backdrop-blur-sm z-[200] flex flex-col items-center justify-center gap-4 text-center p-10">
                <div className="w-16 h-16 border-4 border-indigo-500/20 border-t-indigo-500 rounded-full animate-spin"></div>
                <p className="text-xs font-black uppercase tracking-[0.3em]">{state.videoStatus || 'Synthesizing Production...'}</p>
