            {state.generatedImage && !state.generatedVideo && (
              <div className="absolute inset-0 bg-black/95 z-[150] flex flex-col items-center justify-center p-8">
                <div className="max-w-4xl w-full aspect-video rounded-3xl overflow-hidden shadow-2xl border border-white/10 group relative">
                   <img src={state.generatedImage} className="w-full h-full object-cover" />
                   <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity gap-4">
                      <button onClick={openImageInNewWindow} className="px-6 py-3 bg-white/10 hover:bg-white/20 rounded-2xl text-xs font-black uppercase tracking-widest flex items-center gap-2 backdrop-blur-md border border-white/10"><Maximize2 className="w-4 h-4" /> Fullscreen</button>
                      <button onClick={handleInitiateVideoReview} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-500 rounded-2xl text-xs font-black uppercase tracking-widest flex items-center gap-2 border border-indigo-400/30"><Play className="w-4 h-4 fill-current" /> Animate Performance</button>
                   </div>
