import React, { useMemo } from 'react';
import { Camera, Maximize2 } from 'lucide-react';
import { CameraConfig, SubjectConfig, StudioState } from '../types';
import { LENSES } from '../constants';

interface ViewfinderProps {
  state: StudioState;
  inferredScale?: string;
}

const CameraViewfinder: React.FC<ViewfinderProps> = ({ state, inferredScale }) => {
  const { cameras, activeCameraIndex, subjects } = state;
  const cam = cameras[activeCameraIndex];

  const composition = useMemo(() => {
    const mm = LENSES.find(l => l.label === cam.lens)?.mm || 50;
    const aspect = 16 / 9;

    // Physics constant: Sensor height is 24mm (Full Frame standard)
    const sensorHeight = 24;

    const projectSubject = (sub: SubjectConfig) => {
      // 1. World displacement
      const dx = sub.x - cam.x;
      const dz = sub.z - cam.z;

      // 2. Local space (Camera coordinate system)
      // Camera rotation 0 faces Stage Deep (+Z).
      const rotRad = -cam.rotation * (Math.PI / 180);
      const localX = dx * Math.cos(rotRad) - dz * Math.sin(rotRad);
      const localZ = dx * Math.sin(rotRad) + dz * Math.cos(rotRad);

      // Behind camera check
      if (localZ <= 0.1) return null;

      // 3. Physical Frame Calculation (Feet)
      // FrameHeight = (SensorHeight * Distance) / FocalLength
      // This is the EXACT same formula used in App.tsx to determine the tag
      const frameHeightAtZ = (sensorHeight * localZ) / mm;
      const frameWidthAtZ = frameHeightAtZ * aspect;

      // 4. Vertical Projection (Feet)
      let cameraY = 5.0; // Standard eye level
      if (cam.verticalAngle.includes("Low")) cameraY = 1.5;
      if (cam.verticalAngle.includes("High")) cameraY = 12.0;
      if (cam.verticalAngle.includes("Bird")) cameraY = 30.0;

      // We anchor the subject visual by their eye-line (~5.5ft)
      const subjectHeadY = 5.5; 
      const relativeY = subjectHeadY - cameraY;

      // 5. Screen Mapping (%)
      const screenX = 50 + (localX / (frameWidthAtZ / 2)) * 50;

      // Cinematic Framing Rule of Thirds adjustment:
      // In professional cinematography, eyes are placed near the upper third (33%) 
      // of the frame for CU and MS shots. 
      let verticalAdjustment = 0;
      if (frameHeightAtZ < 4) { // Close Up (CU)
        verticalAdjustment = 12; // Bring face into tighter focus
      } else if (frameHeightAtZ < 9) { // Medium Shot (MS)
        verticalAdjustment = 6;
      } else if (frameHeightAtZ < 25) { // Long Shot (LS)
        verticalAdjustment = 2;
      }

      const screenY = 50 - (relativeY / (frameHeightAtZ / 2)) * 50 + verticalAdjustment;

      // 6. Visual Scaling
      // subjectPhysicalHeight (6ft) / frameHeightAtZ = fraction of screen height.
      // We normalize this so a scale of 1.0 means the subject fills the frame height.
      const subjectPhysicalHeight = 6.0;
      // Multiplier of 5.0 is used because the subject component's default height 
      // is roughly 20% of the container height.
      const visualScale = (subjectPhysicalHeight / frameHeightAtZ) * 5.0; 

      // 7. Gaze Orientation
      const angleToCam = (Math.atan2(cam.x - sub.x, cam.z - sub.z) * 180 / Math.PI + 360) % 360;
      const gazeDiff = Math.abs((sub.gaze - angleToCam + 540) % 360 - 180);
      const isFacing = gazeDiff < 45;
      const relativeGazeRad = (sub.gaze - angleToCam) * (Math.PI / 180);
      const gazeX = Math.sin(relativeGazeRad);

      return { 
        x: screenX, 
        y: screenY,
        scale: Math.min(25, Math.max(0.1, visualScale)),
        visible: screenX > -50 && screenX < 150 && localZ > 0.1,
        gazeX,
        isFacing,
        dist: localZ
      };
    };

    return {
      subA: projectSubject(subjects.a),
      subB: subjects.activeCount === 2 ? projectSubject(subjects.b) : null
    };
  }, [cam, subjects]);

  const renderSubject = (proj: any, color: string, label: string) => {
    if (!proj || !proj.visible) return null;

    const zIndex = Math.round(1000 - proj.dist * 10);

    return (
      <div 
        className="absolute transition-all duration-150 ease-out flex flex-col items-center pointer-events-none"
        style={{ 
          left: `${proj.x}%`, 
          top: `${proj.y}%`,
          transform: `translate(-50%, -10%) scale(${proj.scale})`,
          transformOrigin: 'top center',
          zIndex
        }}
      >
        {/* Head Visual */}
        <div className={`w-10 h-10 rounded-full border-2 ${color} bg-black/95 relative flex items-center justify-center shadow-[0_0_20px_rgba(0,0,0,0.5)]`}>
            <div 
              className="flex gap-1.5 transition-transform duration-200"
              style={{ transform: `translateX(${proj.gazeX * 4}px)` }}
            >
              <div className={`w-1.5 h-1.5 rounded-full ${proj.isFacing ? 'bg-white shadow-[0_0_5px_white]' : 'bg-white/10'}`} />
              <div className={`w-1.5 h-1.5 rounded-full ${proj.isFacing ? 'bg-white shadow-[0_0_5px_white]' : 'bg-white/10'}`} />
            </div>
        </div>

        {/* Torso Visual */}
        <div className={`w-16 h-32 -mt-1 rounded-t-[2.5rem] border-2 ${color} bg-black/50 backdrop-blur-sm relative overflow-hidden`}>
           <div className="absolute top-4 left-1/2 -translate-x-1/2 w-8 h-px bg-white/10" />
           <div className="absolute top-1/2 left-1/2 -translate-x-1/2 w-12 h-px bg-white/10" />
        </div>

        {/* HUD Data Tag */}
        <div className="mt-4 bg-black/90 backdrop-blur-md px-2 py-0.5 rounded border border-white/20 flex items-center gap-1.5 shadow-xl">
          <span className="text-[6px] font-black text-white/50 uppercase tracking-widest">{label}</span>
          <span className="text-[5px] font-bold text-indigo-400 font-mono">D:{proj.dist.toFixed(1)}ft</span>
        </div>
      </div>
    );
  };

  const currentScaleTag = inferredScale || "WS";
  const shortScaleTag = currentScaleTag.includes("(") ? currentScaleTag.split("(")[1].replace(")", "") : currentScaleTag;

  return (
    <div className="relative w-full aspect-video bg-[#020202] rounded-3xl border border-white/10 overflow-hidden shadow-2xl group select-none">
      {/* Cinematic Grid Lines */}
      <div className="absolute inset-0 pointer-events-none z-10 opacity-20">
        <div className="absolute top-1/3 w-full h-px bg-white/40" />
        <div className="absolute top-2/3 w-full h-px bg-white/40" />
        <div className="absolute left-1/3 h-full w-px bg-white/40" />
        <div className="absolute right-1/3 h-full w-px bg-white/40" />
      </div>

      {/* Frame Status Metadata */}
      <div className="absolute top-4 left-4 z-40 flex items-center gap-2">
        <div className="flex items-center gap-2 bg-black/80 backdrop-blur-md px-3 py-1.5 rounded-xl border border-white/20">
          <div className="w-2 h-2 rounded-full bg-red-600 animate-pulse shadow-[0_0_10px_red]" />
          <span className="text-[9px] font-mono font-black text-white tracking-tight uppercase">MONITOR_01</span>
