/**
 * Image processing with safe defaults for Gemini payloads
 */
async function downscaleImage(dataUrl: string, maxWidth = 512, quality = 0.5): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failure"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Reference image load failed"));
    img.src = dataUrl;
  });
}

/**
 * Helper to calculate composition metadata for the AI prompt
 */
const calculateCompositionMetadata = (state: StudioState) => {
  const cam = state.cameras[state.activeCameraIndex];
  const mm = 50; // default/placeholder
  const sensorHeight = 24;
  const aspect = 16/9;

  const project = (sub: SubjectConfig) => {
    const dx = sub.x - cam.x;
    const dz = sub.z - cam.z;
    const rotRad = -cam.rotation * (Math.PI / 180);
    const localZ = dx * Math.sin(rotRad) + dz * Math.cos(rotRad);
    if (localZ <= 0.1) return null;

    const frameHeightAtZ = (sensorHeight * localZ) / mm;
    const frameWidthAtZ = frameHeightAtZ * aspect;
    const heightPct = (6.0 / frameHeightAtZ) * 100;
    const screenX = 50 + ((sub.x - cam.x) / (frameWidthAtZ / 2)) * 50;

    return { x: screenX.toFixed(1), heightPct: heightPct.toFixed(1) };
  };

  return {
    subA: project(state.subjects.a),
    subB: state.subjects.activeCount === 2 ? project(state.subjects.b) : null
  };
};

export const generateDraftPrompt = async (state: StudioState | any): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  const isDuo = state.subjects.activeCount === 2;
  const comp = calculateCompositionMetadata(state);

  const allowedRefs = ['background', 'prop', 'char_a', 'pose_a'];
  if (isDuo) allowedRefs.push('char_b', 'pose_b');

  const processedRefs = await Promise.all(
    allowedRefs.map(async (key) => {
      const ref = state.references[key];
      if (ref?.dataUrl) {
        try {
          const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.4);
          return { key, data, mimeType };
        } catch (e) {
          console.warn(`Skipping reference ${key}`, e);
          return null;
        }
      }
      return null;
    })
  );

  const parts: any[] = [];
  processedRefs.forEach(ref => {
    if (ref) {
      parts.push({ text: `REFERENCE_${ref.key.toUpperCase()}:` });
      parts.push({ inlineData: { data: ref.data, mimeType: ref.mimeType } });
    }
  });

  const compositionGuide = `COMPOSITION_GUIDE (Viewport Relative):
- Subject A: Horizontal Center is ${comp.subA?.x}%, Occupies ${comp.subA?.heightPct}% of frame height.
${isDuo ? `- Subject B: Horizontal Center is ${comp.subB?.x}%, Occupies ${comp.subB?.heightPct}% of frame height.` : ''}`;

  const systemInstruction = `You are a Professional Virtual Production Director.
Analyze visual references and technical stage data to create a unified cinematic script.
PRODUCTION MODE: ${isDuo ? 'DUO PERFORMANCE' : 'SOLO PERFORMANCE'}

TECHNICAL CONTEXT:
${compositionGuide}
Optics: Lens ${activeCamera.lens}, Vertical Angle ${activeCamera.verticalAngle}
Shot Scale: ${state.inferredShotScale}

INSTRUCTIONS:
1. Write a vivid cinematic description.
2. Ensure the framing and subject size strictly match the COMPOSITION_GUIDE.
3. Integrate character visual identities (CHAR_A/B) and poses (POSE_A/B).
4. Match environment to BACKGROUND reference.

Format the output as a JSON object with a single "script" string property.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: `TASK: Generate a ${isDuo ? 'Dual' : 'Single'}-Character Production Script.` }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          script: {
            type: Type.STRING,
            description: "The cinematic scene description."
          }
        },
        required: ["script"]
      }
    }
  });

  try {
    const parsed = JSON.parse(response.text || "{}");
    return parsed.script || response.text || "";
  } catch (e) {
    return response.text || "";
  }
};

export const generateStudioImage = async (state: StudioState | any, draftJson: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  const isDuo = state.subjects.activeCount === 2;
  const comp = calculateCompositionMetadata(state);

  let script = "";
  try {
    const clean = draftJson.replace(/```json/g, "").replace(/```/g, "").trim();
    const p = JSON.parse(clean);
    script = p.script || draftJson;
  } catch (e) {
    script = draftJson;
  }

  const relevantRefs = ['background', 'char_a', 'pose_a', 'prop'];
  if (isDuo) relevantRefs.push('char_b', 'pose_b');

  const processedAssets = await Promise.all(
    relevantRefs.map(async (key) => {
      const ref = state.references[key];
      if (ref?.dataUrl) {
        try {
          const { data, mimeType } = await downscaleImage(ref.dataUrl, 768, 0.5);
          return { key, data, mimeType };
        } catch (e) {
          return null;
        }
      }
      return null;
    })
  );

  const parts: any[] = [];
  processedAssets.forEach(asset => {
    if (asset) {
      parts.push({ text: `VISUAL_ASSET_${asset.key.toUpperCase()}:` });
      parts.push({ inlineData: { data: asset.data, mimeType: asset.mimeType } });
    }
  });

  const directive = `RENDER_DIRECTIVE:
1. COMPOSITION: Subject A at ${comp.subA?.x}% screen width, ${comp.subA?.heightPct}% screen height. ${isDuo ? `Subject B at ${comp.subB?.x}% screen width, ${comp.subB?.heightPct}% screen height.` : ''}
2. PERFORMANCE: ${script}
3. ASSETS: Identity from CHAR references, poses from POSE references.
4. LENS: ${activeCamera.lens}, ${activeCamera.verticalAngle}.`;

  parts.push({ text: directive });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { 
      imageConfig: { 
        aspectRatio: "16:9", 
        imageSize: "1K" 
      } 
    }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) {
    throw new Error("Render engine failure. Pixel data missing.");
  }
  return `data:image/png;base64,${imgPart.inlineData.data}`;
};

export const generateStudioVideo = async (
  state: StudioState, 
  script: string, 
  baseImage: string, 
  onStatusChange: (s: string) => void
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  onStatusChange("Temporal Engine Booting...");
  const base64Data = baseImage.split(',')[1];

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Cinematic extension: ${script}. Exact lighting and subject continuity.`,
    image: { imageBytes: base64Data, mimeType: 'image/png' },
    config: { numberOfVideos: 1, resolution: '720p', aspectRatio: '16:9' }
  });

  while (!operation.done) {
    onStatusChange("Synthesizing Motion Frames...");
    await new Promise(r => setTimeout(r, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video synthesis failed.");

  const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await videoResponse.blob();
  return URL.createObjectURL(blob);
};

import React, { useMemo } from 'react';
import { Camera, Maximize2 } from 'lucide-react';
import { CameraConfig, SubjectConfig, StudioState } from '../types';
import { LENSES } from '../constants';

interface ViewfinderProps {
  state: StudioState;
  inferredScale?: string;
}

const CameraViewfinder: React.FC<ViewfinderProps> = ({ state, inferredScale }) => {
  const { cameras, activeCameraIndex, subjects } = state;
  const cam = cameras[activeCameraIndex];

  const composition = useMemo(() => {
    const mm = LENSES.find(l => l.label === cam.lens)?.mm || 50;
    const aspect = 16 / 9;
    const sensorHeight = 24;

    const projectSubject = (sub: SubjectConfig) => {
      const dx = sub.x - cam.x;
      const dz = sub.z - cam.z;
      const rotRad = -cam.rotation * (Math.PI / 180);
      const localX = dx * Math.cos(rotRad) - dz * Math.sin(rotRad);
      const localZ = dx * Math.sin(rotRad) + dz * Math.cos(rotRad);

      if (localZ <= 0.1) return null;

      // Calculate physical frame height at the subject's distance
      const frameHeightAtZ = (sensorHeight * localZ) / mm;
      const frameWidthAtZ = frameHeightAtZ * aspect;

      // Vertical anchoring based on camera height
      let cameraY = 5.0; // standard eye level
      if (cam.verticalAngle.includes("Low")) cameraY = 1.5;
      if (cam.verticalAngle.includes("High")) cameraY = 12.0;
      if (cam.verticalAngle.includes("Bird")) cameraY = 30.0;

      const subjectHeight = 6.0;
      const eyeLevel = 5.5; 
      const relativeY = eyeLevel - cameraY;

      // Mapping to screen space (%)
      const screenX = 50 + (localX / (frameWidthAtZ / 2)) * 50;

      // Standard cinematic eye-line position (target top third of frame)
      const eyeLineTarget = 33; 
      const screenY_eye = eyeLineTarget - (relativeY / (frameHeightAtZ / 2)) * 50;

      // The subject's physical height relative to the frame height (%)
      const heightPct = (subjectHeight / frameHeightAtZ) * 100;

      // Anchor the div so its eye line matches screenY_eye
      // Head is roughly 1/8th of height (12.5%). Eye is mid-head.
      const headTopToEyeOffset = (heightPct * 0.125) / 2; 
      const screenY_top = screenY_eye - headTopToEyeOffset;

      // Gaze direction relative to camera
      const angleToCam = (Math.atan2(cam.x - sub.x, cam.z - sub.z) * 180 / Math.PI + 360) % 360;
      const gazeDiff = Math.abs((sub.gaze - angleToCam + 540) % 360 - 180);
      const isFacing = gazeDiff < 45;
      const relativeGazeRad = (sub.gaze - angleToCam) * (Math.PI / 180);
      const gazeX = Math.sin(relativeGazeRad);

      return { 
        x: screenX, 
        y: screenY_top,
        heightPct,
        visible: screenX > -50 && screenX < 150 && localZ > 0.1,
        gazeX,
        isFacing,
        dist: localZ
      };
    };

    return {
      subA: projectSubject(subjects.a),
      subB: subjects.activeCount === 2 ? projectSubject(subjects.b) : null
    };
  }, [cam, subjects]);

  const renderSubject = (proj: any, color: string, label: string) => {
    if (!proj || !proj.visible) return null;

    const zIndex = Math.round(1000 - proj.dist * 10);
    // Human silhouette is roughly 40% as wide as tall
    const widthPct = proj.heightPct * 0.4;

    return (
      <div 
        className="absolute transition-all duration-300 ease-out flex flex-col items-center pointer-events-none"
        style={{ 
          left: `${proj.x}%`, 
          top: `${proj.y}%`,
          height: `${proj.heightPct}%`,
          width: `${widthPct}%`,
          zIndex
        }}
      >
        {/* Head Visual - silhouette-correct 12.5% height of subject */}
        <div className={`w-[40%] aspect-square rounded-full border-2 ${color} bg-black/95 relative flex items-center justify-center shadow-lg`}>
            <div 
              className="flex gap-[15%] transition-transform duration-200"
              style={{ transform: `translateX(${proj.gazeX * 25}%)` }}
            >
              <div className={`w-[25%] aspect-square rounded-full ${proj.isFacing ? 'bg-white shadow-[0_0_3px_white]' : 'bg-white/20'}`} />
              <div className={`w-[25%] aspect-square rounded-full ${proj.isFacing ? 'bg-white shadow-[0_0_3px_white]' : 'bg-white/20'}`} />
            </div>
        </div>

        {/* Torso/Body Visual */}
        <div className={`w-full flex-1 -mt-[5%] rounded-t-[45%] border-2 ${color} bg-black/60 backdrop-blur-sm relative overflow-hidden`}>
           <div className="absolute top-[25%] left-1/2 -translate-x-1/2 w-[40%] h-px bg-white/10" />
           <div className="absolute top-[50%] left-1/2 -translate-x-1/2 w-[60%] h-px bg-white/10" />
        </div>

        {/* Data Tag */}
        {proj.heightPct > 8 && (
          <div className="absolute top-full mt-2 bg-black/95 backdrop-blur-md px-1.5 py-0.5 rounded border border-white/20 flex flex-col items-center shadow-2xl min-w-[24px]">
            <span className="text-[5px] font-black text-white/40 uppercase tracking-tighter leading-none">{label}</span>
            <span className="text-[5px] font-bold text-indigo-400 font-mono leading-none mt-0.5">{proj.dist.toFixed(0)}FT</span>
          </div>
        )}
      </div>
    );
  };

  const currentScaleTag = inferredScale || "WS";
  const shortScaleTag = currentScaleTag.includes("(") ? currentScaleTag.split("(")[1].replace(")", "") : currentScaleTag;

  return (
    <div className="relative w-full aspect-video bg-[#010101] rounded-3xl border border-white/10 overflow-hidden shadow-2xl group select-none">
      {/* Viewfinder Grid */}
      <div className="absolute inset-0 pointer-events-none z-10 opacity-20">
        <div className="absolute top-1/3 w-full h-px bg-white/20" />
        <div className="absolute top-2/3 w-full h-px bg-white/20" />
        <div className="absolute left-1/3 h-full w-px bg-white/20" />
        <div className="absolute right-1/3 h-full w-px bg-white/20" />
      </div>

      {/* Metadata Overlay */}
      <div className="absolute top-3 left-3 z-40 flex items-center gap-2">
        <div className="flex items-center gap-1.5 bg-black/80 backdrop-blur-md px-2 py-1 rounded-lg border border-white/10">
          <div className="w-1.5 h-1.5 rounded-full bg-red-600 animate-pulse" />
          <span className="text-[7px] font-mono font-black text-white/90 tracking-tight uppercase">MONITOR_01</span>
        </div>
        <div className="bg-indigo-600/50 backdrop-blur-md px-2 py-1 rounded-lg border border-indigo-400/50">
          <span className="text-[8px] font-black text-white font-mono tracking-widest uppercase">{shortScaleTag}</span>
        </div>
      </div>

      <div className="absolute bottom-3 right-3 z-40 text-right opacity-60">
        <p className="text-[8px] font-mono font-black text-white tracking-[0.2em] leading-none mb-0.5">{cam.lens.toUpperCase()}</p>
        <p className="text-[6px] font-bold text-white/30 uppercase tracking-[0.4em]">{cam.model}</p>
      </div>

      {/* Horizon Line */}
      <div 
        className="absolute w-full h-px bg-white/5 z-0 pointer-events-none transition-all duration-700" 
        style={{ 
          top: cam.verticalAngle.includes("Low") ? "85%" : 
               cam.verticalAngle.includes("High") ? "35%" : 
               cam.verticalAngle.includes("Bird") ? "15%" : "50%" 
        }} 
      />

      {/* Subject Scene Layer */}
      <div className="absolute inset-0 z-20 overflow-hidden">
        {renderSubject(composition.subA, 'border-indigo-500', 'SUB_A')}
        {renderSubject(composition.subB, 'border-emerald-500', 'SUB_B')}
      </div>

      {/* Vignette */}
      <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_80px_rgba(0,0,0,0.8)]" />
    </div>
  );
};

