                    className="w-full bg-black/40 border border-white/10 rounded-lg px-2 py-2 text-[10px] font-bold text-white focus:outline-none focus:border-indigo-500 transition-colors"
                  >
                    {CAMERA_MODELS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[8px] font-bold text-white/20 uppercase tracking-wider">Optical Prime</label>
                  <select 
                    value={activeCamera.lens}
                    onChange={(e) => updateActiveCamera({ lens: e.target.value })}
                    className="w-full bg-black/40 border border-white/10 rounded-lg px-2 py-2 text-[10px] font-bold text-white focus:outline-none focus:border-indigo-500 transition-colors"
                  >
                    {LENSES.map(l => <option key={l.label} value={l.label}>{l.label}</option>)}
                  </select>
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-[8px] font-bold text-white/20 uppercase tracking-wider">Vertical Perspective</label>
                <select 
                  value={activeCamera.verticalAngle}
                  onChange={(e) => updateActiveCamera({ verticalAngle: e.target.value })}
                  className="w-full bg-black/40 border border-white/10 rounded-lg px-2 py-2 text-[10px] font-bold text-white focus:outline-none focus:border-indigo-500 transition-colors"
                >
                  {VERTICAL_ANGLES.map(a => <option key={a} value={a}>{a}</option>)}
                </select>
              </div>

              <ShotScalePicker 
                value={state.inferredShotScale || calculatedShotScale} 
                onChange={(val) => setState(s => ({ ...s, inferredShotScale: val }))} 
              />
            </div>
          </section>

          {/* Talent Config */}
          <section className="space-y-4">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
                <Users className="w-3 h-3" /> Talent Positioning
              </h2>
              <button 
                onClick={() => setState(s => ({ ...s, subjects: { ...s.subjects, activeCount: s.subjects.activeCount === 1 ? 2 : 1 } }))}
                className="text-[9px] font-bold text-indigo-400 bg-indigo-500/10 px-2 py-1 rounded-lg border border-indigo-500/20 hover:bg-indigo-500/20 transition-all"
              >
                {state.subjects.activeCount === 1 ? "+ Add Partner" : "Switch to Solo"}
              </button>
            </div>

            <div className="bg-black/20 p-4 rounded-2xl border border-white/5 space-y-8">
              <div className="space-y-4">
                <div className="flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full bg-indigo-500" />
                  <span className="text-[10px] font-black text-white uppercase tracking-widest">Subject A</span>
                </div>
                <OrientationSlider 
                  config={state.subjects.a} 
                  activeCamera={activeCamera}
                  onChange={(v) => setState(s => ({ ...s, subjects: { ...s.subjects, a: { ...s.subjects.a, rotation: v } } }))}
                />
                <GazeSelector 
                  subjectId="a" 
                  config={state.subjects.a} 
                  activeCamera={activeCamera}
                  otherSubject={state.subjects.activeCount === 2 ? state.subjects.b : undefined}
                  onChange={(v) => setState(s => ({ ...s, subjects: { ...s.subjects, a: { ...s.subjects.a, gaze: v } } }))}
                />
              </div>

              {state.subjects.activeCount === 2 && (
                <div className="space-y-4 pt-8 border-t border-white/5">
                  <div className="flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-purple-500" />
                    <span className="text-[10px] font-black text-white uppercase tracking-widest">Subject B</span>
                  </div>
                  <OrientationSlider 
                    config={state.subjects.b} 
                    activeCamera={activeCamera}
                    onChange={(v) => setState(s => ({ ...s, subjects: { ...s.subjects, b: { ...s.subjects.b, rotation: v } } }))}
                  />
                  <GazeSelector 
                    subjectId="b" 
                    config={state.subjects.b} 
                    activeCamera={activeCamera}
                    otherSubject={state.subjects.a}
                    onChange={(v) => setState(s => ({ ...s, subjects: { ...s.subjects, b: { ...s.subjects.b, gaze: v } } }))}
                  />
                </div>
              )}
            </div>
          </section>

          {/* Finance Section */}
          <section className="bg-white/5 rounded-2xl border border-white/10 p-4 space-y-4 shadow-inner">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
                <DollarSign className="w-3 h-3 text-emerald-400" /> Production Budget
              </h2>
              <span className="text-xs font-mono font-bold text-emerald-400">${state.usage.totalSpent.toFixed(4)}</span>
            </div>
            <div className="space-y-2">
              <div className="flex justify-between items-center text-[9px] uppercase tracking-wider text-white/20">
                <span>Directorial Analysis</span>
                <span className="text-white/40">${state.usage.analysis.toFixed(4)}</span>
              </div>
              <div className="flex justify-between items-center text-[9px] uppercase tracking-wider text-white/20">
                <span>Visual Render</span>
                <span className="text-white/40">${state.usage.render.toFixed(4)}</span>
              </div>
              <div className="flex justify-between items-center text-[9px] uppercase tracking-wider text-white/20">
                <span>Temporal Motion</span>
                <span className="text-white/40">${state.usage.video.toFixed(4)}</span>
              </div>
              <div className="pt-2 border-t border-white/5 flex justify-between items-center text-[9px] uppercase tracking-widest text-indigo-400 font-bold">
                <span>Total Tokens</span>
                <span>{state.usage.tokens.toLocaleString()}</span>
              </div>
            </div>
          </section>
        </div>

        {/* Primary CTA */}
        <div className="p-6 border-t border-white/5 bg-black/40 backdrop-blur-md">
          <button 
            disabled={state.isGeneratingPrompt}
            onClick={handleGeneratePrompt}
            className="w-full bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 text-white font-black text-sm py-4 rounded-2xl flex items-center justify-center gap-3 shadow-xl shadow-indigo-600/20 transition-all group"
          >
            {state.isGeneratingPrompt ? <Loader2 className="w-5 h-5 animate-spin" /> : <Wand2 className="w-5 h-5 group-hover:rotate-12 transition-transform" />}
            GENERATE PRODUCTION SCRIPT
          </button>
        </div>
      </div>

      {/* Main Viewport (Right) */}
      <div className="flex-1 flex flex-col relative bg-[#050505]">
        <div className="flex-1 p-8 flex flex-col gap-6 overflow-hidden">
          {/* Top Viewfinder */}
          <div className="w-full max-w-5xl mx-auto">
            <CameraViewfinder 
              state={state} 
              inferredScale={state.inferredShotScale || calculatedShotScale} 
            />
          </div>

          {/* Stage Floor Planner */}
          <div className="flex-1 flex flex-col min-h-0">
             <div className="flex items-center justify-between px-4 py-2 bg-white/5 border border-white/10 rounded-t-3xl border-b-0">
                <div className="flex items-center gap-3">
                   <Target className="w-4 h-4 text-indigo-400" />
                   <span className="text-[10px] font-black text-white/60 uppercase tracking-widest">Floor Plan & Spatial Audio</span>
                </div>
                <div className="flex items-center gap-4">
                  <div className="flex items-center gap-2 text-white/30">
                    <ZoomIn className="w-3 h-3" />
                    <span className="text-[8px] font-bold">PINCH TO ZOOM</span>
                  </div>
                  <div className="flex items-center gap-2 text-white/30">
                    <Move className="w-3 h-3" />
                    <span className="text-[8px] font-bold">DRAG TO PAN</span>
                  </div>
                </div>
             </div>
             <div className="flex-1 min-h-0 bg-[#080808] border border-white/10 rounded-b-3xl overflow-hidden relative shadow-inner">
                <FloorPlanner 
                  state={state}
                  onUpdateSubject={(id, updates) => setState(s => ({ ...s, subjects: { ...s.subjects, [id]: { ...s.subjects[id], ...updates } } }))}
                  onUpdateCamera={(idx, updates) => {
                    const newCams = [...state.cameras];
                    newCams[idx] = { ...newCams[idx], ...updates };
                    setState(s => ({ ...s, cameras: newCams }));
                  }}
                  onUpdatePlanner={(u) => setState(s => ({ ...s, ...u }))}
                  onSelectCamera={(idx) => setState(s => ({ ...s, activeCameraIndex: idx }))}
                />
             </div>
          </div>
        </div>

        {/* Directorial Overlays */}
        {(state.isReviewingPrompt || state.isGenerating || state.isReviewingVideoPrompt || state.isGeneratingVideo) && (
          <div className="absolute inset-0 z-[100] bg-[#0a0a0a]/95 backdrop-blur-2xl p-8 flex flex-col items-center justify-center overflow-y-auto">
            <button 
              onClick={() => setState(s => ({ ...s, isReviewingPrompt: false, isReviewingVideoPrompt: false }))}
              className="absolute top-8 right-8 text-white/20 hover:text-white transition-colors p-2"
            >
              <X className="w-10 h-10" />
            </button>

            <div className="max-w-4xl w-full space-y-10">
              <div className="text-center space-y-4">
                <h3 className="text-5xl font-black text-white tracking-tighter italic uppercase flex items-center justify-center gap-4">
                   <Tv className="w-12 h-12 text-indigo-500" />
                   Director's Preview
                </h3>
                <p className="text-indigo-400 text-xs font-black uppercase tracking-[0.5em] animate-pulse">
                  Phase: {state.isGenerating ? "Synthesizing High-Resolution Frames" : state.isGeneratingVideo ? "Generating Temporal Continuity" : "Script Evaluation"}
                </p>
              </div>

              {state.generatedImage ? (
                <div className="relative group rounded-[2.5rem] overflow-hidden border-4 border-white/10 shadow-[0_0_100px_rgba(99,102,241,0.2)] aspect-video bg-black/40">
                  {state.generatedVideo ? (
                    <video src={state.generatedVideo} autoPlay loop muted className="w-full h-full object-cover" />
                  ) : (
                    <img src={state.generatedImage} className="w-full h-full object-cover" />
                  )}
                  {state.isGeneratingVideo && (
                    <div className="absolute inset-0 bg-black/90 flex flex-col items-center justify-center gap-6">
                      <div className="relative">
                        <Loader2 className="w-20 h-20 text-indigo-500 animate-spin" />
                        <div className="absolute inset-0 flex items-center justify-center">
                           <Activity className="w-8 h-8 text-indigo-400 animate-pulse" />
                        </div>
                      </div>
                      <div className="text-center space-y-2">
                        <p className="text-white font-black tracking-[0.3em] text-sm uppercase">{state.videoStatus}</p>
                        <p className="text-white/20 text-[10px] font-bold uppercase tracking-widest">This process may take up to 60 seconds</p>
                      </div>
                    </div>
                  )}
                </div>
              ) : (
                <div className="bg-white/5 border border-white/10 p-12 rounded-[2.5rem] text-left font-serif leading-relaxed text-2xl text-white/90 italic shadow-2xl relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-1 h-full bg-indigo-500" />
                  "{state.draftPrompt}"
                </div>
              )}

              <div className="flex gap-6 justify-center">
                {!state.generatedImage && (
                  <button 
                    onClick={handleRenderImage}
                    disabled={state.isGenerating}
                    className="bg-white text-black font-black px-12 py-6 rounded-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-4 shadow-2xl group"
                  >
                    {state.isGenerating ? <Loader2 className="w-7 h-7 animate-spin" /> : <MonitorPlay className="w-7 h-7" />}
                    <div className="text-left">
                      <div className="text-lg leading-none">COMMIT TO RENDER</div>
                      <div className="text-[10px] opacity-40 uppercase tracking-widest mt-1">Cost: ${COST_PER_IMAGE.toFixed(2)}</div>
                    </div>
                  </button>
                )}
                {state.generatedImage && !state.generatedVideo && !state.isGeneratingVideo && (
                  <button 
                    onClick={handleGenerateVideo}
                    className="bg-indigo-600 text-white font-black px-12 py-6 rounded-2xl hover:bg-indigo-500 hover:scale-105 active:scale-95 transition-all flex items-center gap-4 shadow-2xl"
                  >
                    <Play className="w-7 h-7" />
                    <div className="text-left">
                      <div className="text-lg leading-none">ANIMATE SCENE</div>
                      <div className="text-[10px] opacity-40 uppercase tracking-widest mt-1">Cost: ${COST_PER_VIDEO.toFixed(2)}</div>
                    </div>
                  </button>
                )}
                {state.generatedVideo && (
                  <a 
                    href={state.generatedVideo} 
                    download="production-shot.mp4"
                    className="bg-emerald-600 text-white font-black px-12 py-6 rounded-2xl hover:bg-emerald-500 hover:scale-105 active:scale-95 transition-all flex items-center gap-4 shadow-2xl"
                  >
                    <Download className="w-7 h-7" />
                    <div className="text-left">
                      <div className="text-lg leading-none">EXPORT MASTER</div>
                      <div className="text-[10px] opacity-40 uppercase tracking-widest mt-1">Production Ready MP4</div>
                    </div>
                  </a>
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

export type ReferenceType = 
  | 'background' 
  | 'character' 
  | 'costume' 
  | 'prop' 
  | 'accessories' 
  | 'pose';

export interface ReferenceImage {
  id: ReferenceType;
  label: string;
  dataUrl?: string;
  mimeType?: string;
}

export interface SubjectConfig {
  x: number;
  z: number;
  rotation: number;
  gaze: number;
}

export interface CameraConfig {
  id: string;
  x: number;
  z: number;
  rotation: number;
  model: string;
  lens: string;
  verticalAngle: string;
}

export interface UsageStats {
  totalSpent: number;
  analysis: number;
  render: number;
  video: number;
  tokens: number;
}

export interface StudioState {
  references: Record<ReferenceType, ReferenceImage>;
  lighting: {
    positions: boolean[];
  };
  subjects: {
    a: SubjectConfig;
    activeCount: 1;
  };
  cameras: CameraConfig[];
  activeCameraIndex: number;
  isGenerating: boolean;
  isGeneratingPrompt: boolean;
  isReviewingPrompt: boolean;
  isReviewingVideoPrompt: boolean;
  isGeneratingVideo: boolean;
  videoStatus?: string;
  draftPrompt: string;
  generatedImage?: string;
  generatedVideo?: string;
  plannerZoom: number;
  plannerOffset: { x: number; z: number };
  usage: UsageStats;
  inferredShotScale?: string;
}

import { ReferenceType } from './types';

export const REFERENCE_SLOTS: { id: ReferenceType; label: string; group: string }[] = [
  { id: 'background', label: 'Background', group: 'Environment' },
  { id: 'character', label: 'Character', group: 'Subject' },
  { id: 'costume', label: 'Costume', group: 'Subject' },
  { id: 'prop', label: 'Prop', group: 'Scene' },
  { id: 'accessories', label: 'Accessories', group: 'Subject' },
  { id: 'pose', label: 'Pose Ref', group: 'Subject' },
];

export const CAMERA_MODELS = [
  "Arri Alexa 35",
  "Sony A7R V",
  "RED V-RAPTOR XL",
  "Blackmagic URSA Mini"
];

export const LENSES = [
  { label: "24mm f/1.4 (Wide)", mm: 24 },
  { label: "35mm f/1.4 (Storyteller)", mm: 35 },
  { label: "50mm f/1.2 (Natural)", mm: 50 },
  { label: "85mm f/1.4 (Portrait)", mm: 85 }
];

export const VERTICAL_ANGLES = [
  "Low Angle (Worm's Eye)",
  "Eye Level",
  "High Angle",
  "Bird's Eye (Top-Down)"
];

export const LIGHT_POSITIONS = [
  { label: 'Front', angle: 0 },
  { label: 'Front-Right', angle: 45 },
  { label: 'Right', angle: 90 },
  { label: 'Back-Right', angle: 135 },
  { label: 'Back', angle: 180 },
  { label: 'Back-Left', angle: 225 },
  { label: 'Left', angle: 270 },
  { label: 'Front-Left', angle: 315 },
];

export const SHOT_SCALES = [
  { id: 'ECU', label: "Extreme Close Up (ECU)" },
  { id: 'CU', label: "Close Up (CU)" },
  { id: 'MS', label: "Medium Shot (MS)" },
  { id: 'LS', label: "Long Shot (LS)" },
  { id: 'WS', label: "Wide Shot (WS)" }
];

import React, { useState, useMemo } from 'react';
import { 
  Camera, Layers, Wand2, Loader2, X, Play, Download, 
  Target, MonitorPlay, Users, Landmark, DollarSign, 
  Tv, Move, ZoomIn, Info, Activity, ShieldCheck
} from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage, CameraConfig } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, VERTICAL_ANGLES } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import CameraViewfinder from './components/CameraViewfinder';
import ShotScalePicker from './components/ShotScalePicker';
import { generateDraftPrompt, generateStudioImage, generateStudioVideo, COST_PER_IMAGE, COST_PER_VIDEO } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: { positions: new Array(8).fill(false) },
    subjects: {
      a: { x: 0, z: 12, rotation: 180, gaze: 180 },
      activeCount: 1,
    },
    cameras: [{
      id: 'cam-1', x: 0, z: 0, rotation: 0,
      model: CAMERA_MODELS[0], lens: LENSES[2].label, verticalAngle: VERTICAL_ANGLES[1],
    }],
    activeCameraIndex: 0,
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    isReviewingVideoPrompt: false,
    isGeneratingVideo: false,
    draftPrompt: '',
    plannerZoom: 1.0,
    plannerOffset: { x: 0, z: 0 },
    usage: { totalSpent: 0, analysis: 0, render: 0, video: 0, tokens: 0 },
    inferredShotScale: "Medium Shot (MS)"
  });

  const activeCamera = state.cameras[state.activeCameraIndex];

  const calculatedShotScale = useMemo(() => {
    const mm = LENSES.find(l => l.label === activeCamera.lens)?.mm || 50;
    const dx = state.subjects.a.x - activeCamera.x;
    const dz = state.subjects.a.z - activeCamera.z;
    const dist = Math.sqrt(dx*dx + dz*dz);
    const frameHeight = (24 * dist) / mm;

    if (frameHeight < 1.5) return "Extreme Close Up (ECU)";
    if (frameHeight < 4) return "Close Up (CU)";
    if (frameHeight < 8) return "Medium Shot (MS)";
    if (frameHeight < 20) return "Long Shot (LS)";
    return "Wide Shot (WS)";
  }, [activeCamera, state.subjects.a]);

  const handleGeneratePrompt = async () => {
    setState(s => ({ ...s, isGeneratingPrompt: true }));
    try {
      const { script, cost, tokens } = await generateDraftPrompt({ 
        ...state, 
        inferredShotScale: state.inferredShotScale || calculatedShotScale 
      });
      setState(s => ({
        ...s,
        draftPrompt: script,
        isGeneratingPrompt: false,
        isReviewingPrompt: true,
        usage: {
          ...s.usage,
          analysis: s.usage.analysis + cost,
          tokens: s.usage.tokens + tokens,
          totalSpent: s.usage.totalSpent + cost
        }
      }));
    } catch (e) {
      console.error(e);
      setState(s => ({ ...s, isGeneratingPrompt: false }));
    }
  };

  const handleRenderImage = async () => {
    setState(s => ({ ...s, isGenerating: true }));
    try {
      const { url, cost } = await generateStudioImage(state, state.draftPrompt);
      setState(s => ({
        ...s,
        generatedImage: url,
        isGenerating: false,
        isReviewingPrompt: false,
        isReviewingVideoPrompt: true,
        usage: {
          ...s.usage,
          render: s.usage.render + cost,
          totalSpent: s.usage.totalSpent + cost
        }
      }));
    } catch (e) {
      console.error(e);
      setState(s => ({ ...s, isGenerating: false }));
    }
  };

  const handleGenerateVideo = async () => {
    if (!state.generatedImage) return;
    setState(s => ({ ...s, isGeneratingVideo: true }));
    try {
      const { url, cost } = await generateStudioVideo(state, state.draftPrompt, state.generatedImage, (status) => {
        setState(s => ({ ...s, videoStatus: status }));
      });
      setState(s => ({
        ...s,
        generatedVideo: url,
        isGeneratingVideo: false,
        isReviewingVideoPrompt: false,
        usage: {
          ...s.usage,
          video: s.usage.video + cost,
          totalSpent: s.usage.totalSpent + cost
        }
      }));
    } catch (e) {
      console.error(e);
      setState(s => ({ ...s, isGeneratingVideo: false }));
    }
  };

  const updateActiveCamera = (updates: Partial<CameraConfig>) => {
    const newCams = [...state.cameras];
    newCams[state.activeCameraIndex] = { ...newCams[state.activeCameraIndex], ...updates };
    setState(s => ({ ...s, cameras: newCams }));
  };

  return (
    <div className="flex h-screen bg-[#050505] text-white overflow-hidden">
      {/* LEFT SIDEBAR: Controls & Finance */}
      <aside className="w-[400px] flex flex-col border-r border-white/5 bg-[#0d0d0d] shadow-2xl z-50">
        <header className="p-6 border-b border-white/5 flex items-center justify-between bg-black/20">
          <div className="flex items-center gap-3">
            <Landmark className="w-7 h-7 text-indigo-500" />
            <h1 className="text-xl font-black tracking-tighter uppercase">Studio AI</h1>
          </div>
          <div className="flex items-center gap-2 px-2 py-1 bg-emerald-500/10 rounded border border-emerald-500/20">
            <ShieldCheck className="w-3 h-3 text-emerald-400" />
            <span className="text-[9px] font-black text-emerald-400 uppercase tracking-widest">Live</span>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8">
          {/* 1. PRODUCTION FINANCE (Most visible) */}
          <section className="bg-indigo-600/10 rounded-2xl border border-indigo-500/20 p-5 space-y-4 shadow-lg shadow-indigo-500/5">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.2em] flex items-center gap-2">
                <DollarSign className="w-3 h-3" /> Session Expenditure
              </h2>
              <span className="text-sm font-mono font-bold text-white tracking-tight">
                ${state.usage.totalSpent.toFixed(4)}
              </span>
            </div>
            <div className="grid grid-cols-2 gap-3 pt-2">
              <div className="bg-black/20 rounded-lg p-2 border border-white/5">
                <p className="text-[8px] text-white/30 uppercase font-bold">Renders</p>
                <p className="text-xs font-mono text-indigo-400">${state.usage.render.toFixed(3)}</p>
              </div>
              <div className="bg-black/20 rounded-lg p-2 border border-white/5">
                <p className="text-[8px] text-white/30 uppercase font-bold">Tokens</p>
                <p className="text-xs font-mono text-indigo-400">{state.usage.tokens.toLocaleString()}</p>
              </div>
            </div>
          </section>

          {/* 2. REFERENCE ASSETS */}
          <section className="space-y-4">
            <h2 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
              <Layers className="w-3 h-3" /> Visual References
            </h2>
            <div className="grid grid-cols-3 gap-2">
              {REFERENCE_SLOTS.map(slot => (
                <ReferenceUploader 
                  key={slot.id} 
                  slot={slot} 
                  dataUrl={state.references[slot.id].dataUrl}
                  onUpload={(url, mime) => setState(s => ({
                    ...s, references: { ...s.references, [slot.id]: { ...s.references[slot.id], dataUrl: url, mimeType: mime } }
                  }))}
                  onRemove={() => setState(s => ({
                    ...s, references: { ...s.references, [slot.id]: { ...s.references[slot.id], dataUrl: undefined } }
                  }))}
                />
              ))}
            </div>
          </section>

          {/* 3. OPTICS & FRAMING (The missing panel) */}
          <section className="bg-white/5 p-4 rounded-2xl border border-white/10 space-y-5">
