// Pricing Constants in INR (1 USD = 84.0 INR)
export const COST_PER_IMAGE = 2.50; // ~0.03 USD
export const COST_PER_VIDEO = 12.60; // ~0.15 USD
export const COST_PER_1K_TOKENS = 0.0084; // ~0.0001 USD

async function downscaleImage(dataUrl: string, maxWidth = 512, quality = 0.5): Promise<{ data: string; mimeType: string }> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      let width = img.width;
      let height = img.height;
      if (width > maxWidth || height > maxWidth) {
        if (width > height) {
          height = (maxWidth / width) * height;
          width = maxWidth;
        } else {
          width = (maxWidth / height) * width;
          height = maxWidth;
        }
      }
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error("Canvas context failure"));
      ctx.fillStyle = "white";
      ctx.fillRect(0, 0, width, height);
      ctx.drawImage(img, 0, 0, width, height);
      const scaledDataUrl = canvas.toDataURL('image/jpeg', quality);
      resolve({ data: scaledDataUrl.split(',')[1], mimeType: 'image/jpeg' });
    };
    img.onerror = () => reject(new Error("Reference image load failed"));
    img.src = dataUrl;
  });
}

const calculateCompositionMetadata = (state: StudioState) => {
  const cam = state.cameras[state.activeCameraIndex];
  const mm = parseInt(cam.lens) || 50; 
  const sensorHeight = 24;
  const aspect = 16/9;

  const project = (sub: SubjectConfig) => {
    // Distance calculation relative to camera coordinate system
    const dx = sub.x - cam.x;
    const dz = sub.z - cam.z;

    // Rotate to camera local space
    const rotRad = -cam.rotation * (Math.PI / 180);
    const localZ = dx * Math.sin(rotRad) + dz * Math.cos(rotRad);

    if (localZ <= 0.1) return null;

    const frameHeightAtZ = (sensorHeight * localZ) / mm;
    // Assuming human height is 6.0 units
    const heightPct = (6.0 / frameHeightAtZ) * 100;

    // Horizontal projection
    const localX = dx * Math.cos(rotRad) - dz * Math.sin(rotRad);
    const frameWidthAtZ = frameHeightAtZ * aspect;
    const screenX = 50 + (localX / (frameWidthAtZ / 2)) * 50;

    return { 
      x: Math.max(0, Math.min(100, screenX)).toFixed(1), 
      heightPct: Math.max(0.1, Math.min(100, heightPct)).toFixed(1),
      distance: localZ.toFixed(1)
    };
  };

  return {
    subA: project(state.subjects.a),
  };
};

export const generateDraftPrompt = async (state: StudioState): Promise<{ script: string; cost: number; tokens: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  const comp = calculateCompositionMetadata(state);
  const shotScale = state.inferredShotScale || "Medium Shot (MS)";

  // Logic for Extreme Wide Shot (EWS) and Wide Shot (WS)
  const isEWS = shotScale.includes("EWS") || (comp.subA && parseFloat(comp.subA.heightPct) < 10);
  const isWide = isEWS || shotScale.includes("WS") || shotScale.includes("LS");

  const slots: string[] = ['background', 'character', 'costume', 'prop', 'accessories', 'pose'];
  const processedRefs = await Promise.all(
    slots.map(async (key) => {
      const ref = state.references[key as any];
      if (ref?.dataUrl) {
        try {
          const { data, mimeType } = await downscaleImage(ref.dataUrl, 512, 0.4);
          return { key, data, mimeType };
        } catch (e) { return null; }
      }
      return null;
    })
  );

  const parts: any[] = [];
  processedRefs.forEach(ref => {
    if (ref) {
      parts.push({ text: `REFERENCE_${ref.key.toUpperCase()}:` });
      parts.push({ inlineData: { data: ref.data, mimeType: ref.mimeType } });
    }
  });

  const compositionGuide = `
=== MACHINE_TAGS ===
SHOT_SCALE: ${isEWS ? 'EXTREME WIDE SHOT (EWS)' : shotScale}
SUB_A_POSITION: X=${comp.subA?.x}%, SCREEN_HEIGHT_PERCENTAGE=${comp.subA?.heightPct}%
DISTANCE_FROM_LENS: ${comp.subA?.distance}ft
LENS: ${activeCamera.lens}
CAMERA_ELEVATION: ${activeCamera.verticalAngle}
SUBJECT_BODY_YAW: ${state.subjects.a.rotation}deg
GAZE_DIRECTION: ${state.subjects.a.gaze}deg
RENDER_PRIORITY: ${isEWS ? 'ENVIRONMENTAL_DEPTH_AND_ATMOSPHERIC_PERSPECTIVE' : 'SUBJECT_CLARITY'}
SUBJECT_DETAIL_MODE: ${isEWS ? 'POSTURE_AND_SILHOUETTE_ONLY' : 'TEXTURE_AND_FACIAL_DETAIL'}
`;

  const systemInstruction = `You are a Virtual Production Render Engine. 
MANDATORY CONSTRAINTS:
1. SCREEN_HEIGHT_PERCENTAGE IS ABSOLUTE. If < 10%, the character must appear tiny within a vast environment.
2. For EWS/WS: Do NOT render fine facial details. Focus on the pose, silhouette, and costume colors. The environment must be massive, utilizing atmospheric perspective (haze/depth) to show scale. 
3. Respect CAMERA_ELEVATION for the horizon line. 
4. Character should not "overpower" the frame in wide shots; they are a small component of the architecture/landscape.
5. Combine visual cues from the REFERENCE images into a cohesive cinematic description.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { 
      parts: [
        ...parts, 
        { text: compositionGuide },
        { text: `Synthesize the production description for the image generator.` }
      ] 
    },
    config: { 
      systemInstruction, 
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          script: { type: Type.STRING, description: "The final cinematic prompt" }
        },
        required: ["script"]
      }
    }
  });

  const text = response.text || "";
  const tokens = Math.ceil(text.length / 4) + 2000; 
  const cost = (tokens / 1000) * COST_PER_1K_TOKENS;

  try {
    const parsed = JSON.parse(text);
    return { script: parsed.script || text, cost, tokens };
  } catch (e) {
    return { script: text, cost, tokens };
  }
};

export const generateStudioImage = async (state: StudioState, draftJson: string): Promise<{ url: string; cost: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const activeCamera = state.cameras[state.activeCameraIndex];
  const comp = calculateCompositionMetadata(state);

  let script = "";
  try {
    const clean = draftJson.replace(/```json/g, "").replace(/```/g, "").trim();
    const p = JSON.parse(clean);
    script = p.script || draftJson;
  } catch (e) {
    script = draftJson;
  }

  const shotScale = state.inferredShotScale || "MS";
  const isEWS = shotScale.includes("EWS") || (comp.subA && parseFloat(comp.subA.heightPct) < 10);

  const slots = ['background', 'character', 'costume', 'prop', 'accessories', 'pose'];
  const processedAssets = await Promise.all(
    slots.map(async (key) => {
      const ref = state.references[key as any];
      if (ref?.dataUrl) {
        try {
          const { data, mimeType } = await downscaleImage(ref.dataUrl, 768, 0.5);
          return { key, data, mimeType };
        } catch (e) { return null; }
      }
      return null;
    })
  );

  const parts: any[] = [];
  processedAssets.forEach(asset => {
    if (asset) {
      parts.push({ text: `VISUAL_ASSET_${asset.key.toUpperCase()}:` });
      parts.push({ inlineData: { data: asset.data, mimeType: asset.mimeType } });
    }
  });

  const machineTags = `
=== MACHINE_TAGS ===
SCALE: ${isEWS ? 'EXTREME WIDE SHOT' : shotScale}
SUBJECT_FRAME_PERCENTAGE: ${comp.subA?.heightPct}%
SUBJECT_POSITION_X: ${comp.subA?.x}%
LENS: ${activeCamera.lens}
VIRTUAL_DEPTH_PRIORITY: ${isEWS ? 'ENVIRONMENT_AND_ATMOSPHERE' : 'SUBJECT_TEXTURES'}
RENDER_MODE: PHOTOREALISTIC_CINEMATIC
`;

  parts.push({ text: machineTags + "\n" + script });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts },
    config: { 
      imageConfig: { aspectRatio: "16:9", imageSize: "1K" } 
    }
  });

  const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (!imgPart?.inlineData) throw new Error("Render Engine Failure: No image data received.");

  return { 
    url: `data:image/png;base64,${imgPart.inlineData.data}`, 
    cost: COST_PER_IMAGE 
  };
};

export const generateStudioVideo = async (
  state: StudioState, 
  script: string, 
  baseImage: string, 
  onStatusChange: (s: string) => void
): Promise<{ url: string; cost: number }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  onStatusChange("Initializing Temporal Engine...");

  const base64Data = baseImage.split(',')[1];

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: `Animate strictly maintaining scale and composition from the base image. Focus on environmental mood and subtle character movement. Prompt: ${script}`,
    image: { imageBytes: base64Data, mimeType: 'image/png' },
    config: { numberOfVideos: 1, resolution: '720p', aspectRatio: '16:9' }
  });

  while (!operation.done) {
    onStatusChange("Synthesizing Motion Frames...");
    await new Promise(r => setTimeout(r, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
    if (operation.error) {
      throw new Error(`Temporal Synthesis Failed: ${operation.error.message}`);
    }
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video Export Failed: Download link not generated.");

  const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  if (!videoResponse.ok) throw new Error("Video Stream Failed: Could not fetch video file.");

  const blob = await videoResponse.blob();
  return { url: URL.createObjectURL(blob), cost: COST_PER_VIDEO };
};

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Camera, Layers, Wand2, Loader2, X, Play, Download, 
  Target, MonitorPlay, Users, Landmark, 
  Tv, Move, ZoomIn, Activity, ShieldCheck, ChevronLeft, ChevronRight, Settings2, Eye, Menu, Wallet
} from 'lucide-react';
import { StudioState, ReferenceType, ReferenceImage, CameraConfig } from './types';
import { REFERENCE_SLOTS, CAMERA_MODELS, LENSES, VERTICAL_ANGLES } from './constants';
import ReferenceUploader from './components/ReferenceUploader';
import FloorPlanner from './components/FloorPlanner';
import OrientationSlider from './components/OrientationSlider';
import GazeSelector from './components/GazeSelector';
import CameraViewfinder from './components/CameraViewfinder';
import ShotScalePicker from './components/ShotScalePicker';
import { generateDraftPrompt, generateStudioImage, generateStudioVideo, COST_PER_IMAGE, COST_PER_VIDEO } from './services/geminiService';

/**
 * Interface representing the AI Studio global object provided by the environment.
 */
interface AIStudio {
  hasSelectedApiKey: () => Promise<boolean>;
  openSelectKey: () => Promise<void>;
}

declare global {
  interface Window {
    /**
     * Optional access to the aistudio interface for API key management.
     */
    aistudio: AIStudio;
  }
}

const App: React.FC = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isViewfinderOpen, setIsViewfinderOpen] = useState(true);

  const [state, setState] = useState<StudioState>({
    references: REFERENCE_SLOTS.reduce((acc, slot) => {
      acc[slot.id] = { id: slot.id, label: slot.label };
      return acc;
    }, {} as Record<ReferenceType, ReferenceImage>),
    lighting: { positions: new Array(8).fill(false) },
    subjects: {
      a: { x: 0, z: 12, rotation: 180, gaze: 180 },
      activeCount: 1,
    },
    cameras: [{
      id: 'cam-1', x: 0, z: 0, rotation: 0,
      model: CAMERA_MODELS[0], lens: LENSES[2].label, verticalAngle: VERTICAL_ANGLES[1],
    }],
    activeCameraIndex: 0,
    isGenerating: false,
    isGeneratingPrompt: false,
    isReviewingPrompt: false,
    isReviewingVideoPrompt: false,
    isGeneratingVideo: false,
    draftPrompt: '',
    plannerZoom: 1.0,
    plannerOffset: { x: 0, z: 0 },
    usage: { totalSpent: 0, analysis: 0, render: 0, video: 0, tokens: 0 },
    inferredShotScale: "Medium Shot (MS)"
  });

  const activeCamera = state.cameras[state.activeCameraIndex];

  const calculatedShotScale = useMemo(() => {
    const mm = LENSES.find(l => l.label === activeCamera.lens)?.mm || 50;
    const dx = state.subjects.a.x - activeCamera.x;
    const dz = state.subjects.a.z - activeCamera.z;
    const dist = Math.sqrt(dx*dx + dz*dz);
    const frameHeight = (24 * dist) / mm;

    if (frameHeight < 1.5) return "Extreme Close Up (ECU)";
    if (frameHeight < 4) return "Close Up (CU)";
    if (frameHeight < 8) return "Medium Shot (MS)";
    if (frameHeight < 20) return "Long Shot (LS)";
    if (frameHeight < 45) return "Wide Shot (WS)";
    return "Extreme Wide Shot (EWS)";
  }, [activeCamera, state.subjects.a]);

  const handleGeneratePrompt = async () => {
    setState(s => ({ ...s, isGeneratingPrompt: true }));
    try {
      const { script, cost, tokens } = await generateDraftPrompt({ 
        ...state, 
        inferredShotScale: state.inferredShotScale || calculatedShotScale 
      });
      setState(s => ({
        ...s,
        draftPrompt: script,
        isGeneratingPrompt: false,
        isReviewingPrompt: true,
        usage: {
          ...s.usage,
          analysis: s.usage.analysis + cost,
          tokens: s.usage.tokens + tokens,
          totalSpent: s.usage.totalSpent + cost
        }
      }));
    } catch (e) {
      console.error(e);
      setState(s => ({ ...s, isGeneratingPrompt: false }));
    }
  };

  const handleRenderImage = async () => {
    // API key selection check for Gemini 3 Pro Image generation.
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }

    setState(s => ({ ...s, isGenerating: true }));
    try {
      const { url, cost } = await generateStudioImage(state, state.draftPrompt);
      setState(s => ({
        ...s,
        generatedImage: url,
        isGenerating: false,
        isReviewingPrompt: false,
        isReviewingVideoPrompt: true,
        usage: {
          ...s.usage,
          render: s.usage.render + cost,
          totalSpent: s.usage.totalSpent + cost
        }
      }));
    } catch (e) {
      console.error(e);
      setState(s => ({ ...s, isGenerating: false }));
    }
  };

  const handleGenerateVideo = async () => {
    if (!state.generatedImage) return;

    // API key selection check before initiating Veo video generation.
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }

    setState(s => ({ ...s, isGeneratingVideo: true }));
    try {
      const { url, cost } = await generateStudioVideo(state, state.draftPrompt, state.generatedImage, (status) => {
        setState(s => ({ ...s, videoStatus: status }));
      });
      setState(s => ({
        ...s,
        generatedVideo: url,
        isGeneratingVideo: false,
        isReviewingVideoPrompt: false,
        usage: {
          ...s.usage,
          video: s.usage.video + cost,
          totalSpent: s.usage.totalSpent + cost
        }
      }));
    } catch (e) {
      console.error(e);
      setState(s => ({ ...s, isGeneratingVideo: false }));
      alert("Temporal synthesis failed. Please check your paid API key status.");
    }
  };

  const updateActiveCamera = (updates: Partial<CameraConfig>) => {
    const newCams = [...state.cameras];
    newCams[state.activeCameraIndex] = { ...newCams[state.activeCameraIndex], ...updates };
    setState(s => ({ ...s, cameras: newCams }));
  };

  return (
    <div className="flex h-screen bg-[#050505] text-white overflow-hidden flex-col md:flex-row">
      {/* MOBILE HEADER */}
      <header className="md:hidden p-4 border-b border-white/5 flex items-center justify-between bg-[#0d0d0d] z-[60]">
        <div className="flex items-center gap-2">
          <Landmark className="w-6 h-6 text-indigo-500" />
          <h1 className="text-lg font-black tracking-tighter uppercase">Studio AI</h1>
        </div>
        <button 
          onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          className="p-2 bg-white/5 rounded-lg border border-white/10 active:scale-95 transition-transform"
        >
          {isSidebarOpen ? <X className="w-5 h-5" /> : <Menu className="w-5 h-5" />}
        </button>
      </header>

      {/* LEFT SIDEBAR: Controls & Finance (Hidable/Responsive) */}
      <aside className={`
        fixed inset-0 z-50 bg-[#0d0d0d] transition-transform duration-300 md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        w-full md:w-[360px] lg:w-[400px] flex flex-col border-r border-white/5 shadow-2xl
      `}>
        <header className="hidden md:flex p-6 border-b border-white/5 items-center justify-between bg-black/20">
          <div className="flex items-center gap-3">
            <Landmark className="w-7 h-7 text-indigo-500" />
            <h1 className="text-xl font-black tracking-tighter uppercase">Studio AI</h1>
          </div>
          <button 
            onClick={() => setIsSidebarOpen(false)}
            className="p-1.5 hover:bg-white/5 rounded-md text-white/40 transition-colors"
          >
            <ChevronLeft className="w-5 h-5" />
          </button>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-6 space-y-8">
          {/* PRODUCTION FINANCE (INR) */}
          <section className="bg-indigo-600/10 rounded-2xl border border-indigo-500/20 p-5 space-y-4 shadow-lg shadow-indigo-500/5">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.2em] flex items-center gap-2">
                <Wallet className="w-3 h-3" /> Production Wallet
              </h2>
              <span className="text-sm font-mono font-bold text-white tracking-tight">
                ₹{state.usage.totalSpent.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 4 })}
              </span>
            </div>
            <div className="grid grid-cols-2 gap-3 pt-2">
              <div className="bg-black/20 rounded-lg p-2 border border-white/5">
                <p className="text-[8px] text-white/30 uppercase font-bold">Renders</p>
                <p className="text-xs font-mono text-indigo-400">₹{state.usage.render.toFixed(2)}</p>
              </div>
              <div className="bg-black/20 rounded-lg p-2 border border-white/5">
                <p className="text-[8px] text-white/30 uppercase font-bold">Tokens</p>
                <p className="text-xs font-mono text-indigo-400">{state.usage.tokens.toLocaleString()}</p>
              </div>
            </div>
          </section>

          {/* REFERENCE ASSETS (All 6 slots) */}
          <section className="space-y-4">
            <h2 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
              <Layers className="w-3 h-3" /> Asset Library
            </h2>
            <div className="grid grid-cols-3 gap-2">
              {REFERENCE_SLOTS.map(slot => (
                <ReferenceUploader 
                  key={slot.id} 
                  slot={slot} 
                  dataUrl={state.references[slot.id].dataUrl}
                  onUpload={(url, mime) => setState(s => ({
                    ...s, references: { ...s.references, [slot.id]: { ...s.references[slot.id], dataUrl: url, mimeType: mime } }
                  }))}
                  onRemove={() => setState(s => ({
                    ...s, references: { ...s.references, [slot.id]: { ...s.references[slot.id], dataUrl: undefined } }
                  }))}
                />
              ))}
            </div>
          </section>

          {/* OPTICS SETTINGS */}
          <section className="bg-white/5 p-4 rounded-2xl border border-white/10 space-y-5">
            <h2 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
              <Settings2 className="w-3 h-3" /> Optical Config
            </h2>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-1.5">
                  <label className="text-[8px] font-bold text-white/30 uppercase tracking-wider">Body</label>
                  <select 
                    value={activeCamera.model}
                    onChange={(e) => updateActiveCamera({ model: e.target.value })}
                    className="w-full bg-black/40 border border-white/10 rounded-lg px-2 py-2 text-[10px] font-bold focus:border-indigo-500 focus:outline-none transition-colors"
                  >
                    {CAMERA_MODELS.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[8px] font-bold text-white/30 uppercase tracking-wider">Lens</label>
                  <select 
                    value={activeCamera.lens}
                    onChange={(e) => updateActiveCamera({ lens: e.target.value })}
                    className="w-full bg-black/40 border border-white/10 rounded-lg px-2 py-2 text-[10px] font-bold focus:border-indigo-500 focus:outline-none transition-colors"
                  >
                    {LENSES.map(l => <option key={l.label} value={l.label}>{l.label}</option>)}
                  </select>
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="text-[8px] font-bold text-white/30 uppercase tracking-wider">Elevation</label>
                <select 
                  value={activeCamera.verticalAngle}
                  onChange={(e) => updateActiveCamera({ verticalAngle: e.target.value })}
                  className="w-full bg-black/40 border border-white/10 rounded-lg px-2 py-2 text-[10px] font-bold focus:border-indigo-500 focus:outline-none transition-colors"
                >
                  {VERTICAL_ANGLES.map(a => <option key={a} value={a}>{a}</option>)}
                </select>
              </div>
              <ShotScalePicker 
                value={state.inferredShotScale || calculatedShotScale} 
                onChange={(val) => setState(s => ({ ...s, inferredShotScale: val }))} 
              />
            </div>
          </section>

          {/* TALENT POSTURE */}
          <section className="space-y-4 pb-12">
            <h2 className="text-[10px] font-black text-white/30 uppercase tracking-[0.2em] flex items-center gap-2">
              <Users className="w-3 h-3" /> Talent Posture
            </h2>
            <div className="bg-black/40 p-5 rounded-2xl border border-white/5 space-y-6">
              <OrientationSlider 
                config={state.subjects.a} 
                activeCamera={activeCamera}
                onChange={(v) => setState(s => ({ ...s, subjects: { ...s.subjects, a: { ...s.subjects.a, rotation: v } } }))}
              />
              <GazeSelector 
                subjectId="a" 
                config={state.subjects.a} 
                activeCamera={activeCamera}
                onChange={(v) => setState(s => ({ ...s, subjects: { ...s.subjects, a: { ...s.subjects.a, gaze: v } } }))}
              />
            </div>
          </section>
        </div>

        <footer className="p-4 md:p-6 border-t border-white/5 bg-black/40 backdrop-blur-md">
          <button 
            disabled={state.isGeneratingPrompt}
