                <div className="flex gap-4">
                  <button 
                    onClick={handleRenderImage}
                    disabled={state.isGenerating}
                    className="flex-1 bg-white text-black py-4 rounded-2xl font-black uppercase tracking-widest text-sm flex items-center justify-center gap-3 hover:bg-indigo-500 hover:text-white transition-all active:scale-95 disabled:opacity-50"
                  >
                    {state.isGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5 fill-current" />}
