                      <div className="h-1.5 bg-white/5 rounded-full overflow-hidden">
                        <div className="h-full bg-indigo-500 animate-pulse w-full" />
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {state.generatedVideo && (
          <div className="fixed inset-0 z-[110] bg-black flex items-center justify-center p-4">
            <div className="w-full max-w-5xl aspect-video bg-[#0d0d0d] rounded-[3rem] border border-white/10 shadow-2xl overflow-hidden relative group">
              <video 
