                  <span className="text-[9px] font-black uppercase tracking-[0.3em] text-white/60">Stage Viewfinder (Pre-viz)</span>
               </header>
               <CameraViewfinder state={state} inferredScale={state.inferredShotScale || calculatedShotScale} />
            </div>
          )}
        </div>

        {state.isReviewingPrompt && (
          <div className="fixed inset-0 z-[100] bg-black/90 backdrop-blur-xl flex items-center justify-center p-4">
