                <div className="p-8 md:p-12 space-y-8 flex flex-col justify-center border-l border-white/5">
                  <div className="space-y-3">
                    <h3 className="text-3xl font-black uppercase tracking-tighter">Physical Synthesis</h3>
                    <p className="text-sm text-white/40 leading-relaxed">
                      Static frame has been calculated using optics metadata. Initialize temporal engine to synthesize 5 seconds of motion?
                    </p>
                  </div>
                  <div className="space-y-4 pt-4">
                    <button 
                      onClick={handleGenerateVideo}
                      disabled={state.isGeneratingVideo}
                      className="w-full bg-indigo-600 hover:bg-indigo-500 py-5 rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-3 shadow-xl transition-all active:scale-95 disabled:opacity-50"
                    >
                      {state.isGeneratingVideo ? <Loader2 className="w-6 h-6 animate-spin" /> : <MonitorPlay className="w-6 h-6" />}
                      Animate Production
                    </button>
                    <div className="flex gap-3">
                      <a 
                        href={state.generatedImage} 
                        download="studio_render.png"
                        className="flex-1 bg-white/5 hover:bg-white/10 border border-white/10 py-4 rounded-2xl font-black uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 transition-all"
                      >
                        <Download className="w-4 h-4" /> Save Still
                      </a>
                      <button 
                        onClick={() => setState(s => ({ ...s, isReviewingVideoPrompt: false }))}
                        className="flex-1 bg-white/5 hover:bg-white/10 border border-white/10 py-4 rounded-2xl font-black uppercase tracking-widest text-[10px] flex items-center justify-center gap-2 transition-all"
                      >
                        <X className="w-4 h-4" /> Close
                      </button>
                    </div>
                  </div>
                  {state.isGeneratingVideo && (
                    <div className="space-y-3 pt-4">
                      <div className="flex justify-between text-[10px] font-black uppercase tracking-[0.2em] text-indigo-400">
                        <span>{state.videoStatus || 'Synthesizing...'}</span>
                      </div>
                      <div className="h-1.5 bg-white/5 rounded-full overflow-hidden">
                        <div className="h-full bg-indigo-500 animate-pulse w-full" />
                      </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {state.generatedVideo && (
          <div className="fixed inset-0 z-[110] bg-black flex items-center justify-center p-4">
            <div className="w-full max-w-5xl aspect-video bg-[#0d0d0d] rounded-[3rem] border border-white/10 shadow-2xl overflow-hidden relative group">
              <video 
                src={state.generatedVideo} 
                autoPlay 
                loop 
                controls 
                className="w-full h-full object-contain"
              />
              <button 
                onClick={() => setState(s => ({ ...s, generatedVideo: undefined }))}
                className="absolute top-8 right-8 p-4 bg-black/60 hover:bg-red-500/80 backdrop-blur-md rounded-full text-white transition-all opacity-0 group-hover:opacity-100"
              >
                <X className="w-8 h-8" />
              </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

