              <div className="flex items-center gap-3">
                <Target className="w-4 h-4 text-indigo-500" />
                <span className="text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] text-white/60">Floor Planner</span>
              </div>
              <div className="flex items-center gap-2 md:gap-4">
                <button 
                  onClick={() => setIsViewfinderOpen(!isViewfinderOpen)}
                  className={`p-1.5 rounded-lg border flex items-center gap-2 transition-all ${
                    isViewfinderOpen ? 'bg-indigo-500/20 border-indigo-500 text-indigo-400' : 'bg-white/5 border-white/10 text-white/40'
                  }`}
                >
                  <Eye className="w-3.5 h-3.5" />
                  <span className="text-[8px] font-bold uppercase hidden sm:inline">Camera Viewfinder</span>
                </button>
              </div>
            </header>

            <div className="flex-1 min-h-0 border border-white/5 rounded-b-2xl md:rounded-b-[2.5rem] bg-[#080808] relative overflow-hidden shadow-inner">
              <FloorPlanner 
                state={state}
                onUpdateSubject={(id, updates) => setState(s => ({ ...s, subjects: { ...s.subjects, [id]: { ...s.subjects[id], ...updates } } }))}
                onUpdateCamera={(idx, updates) => {
                  const newCams = [...state.cameras];
                  newCams[idx] = { ...newCams[idx], ...updates };
                  setState(s => ({ ...s, cameras: newCams }));
                }}
                onUpdatePlanner={(u) => setState(s => ({ ...s, ...u }))}
                onSelectCamera={(idx) => setState(s => ({ ...s, activeCameraIndex: idx }))}
              />

              {isViewfinderOpen && (
                <div className="absolute top-4 right-4 w-44 sm:w-64 md:w-80 shadow-2xl z-40 transform transition-all animate-in fade-in slide-in-from-top-4 duration-300">
                  <div className="bg-black/90 p-1.5 rounded-2xl border border-white/20 ring-1 ring-black/50 overflow-hidden">
                    <CameraViewfinder state={state} inferredScale={state.inferredShotScale || calculatedShotScale} />
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {(state.isReviewingPrompt || state.isGenerating || state.isReviewingVideoPrompt || state.isGeneratingVideo) && (
          <div className="absolute inset-0 z-[100] bg-[#050505]/95 backdrop-blur-3xl p-4 md:p-8 flex items-center justify-center overflow-y-auto">
            <button 
              onClick={() => setState(s => ({ ...s, isReviewingPrompt: false, isReviewingVideoPrompt: false, isGenerating: false, isGeneratingVideo: false }))}
              className="absolute top-6 right-6 md:top-10 md:right-10 text-white/20 hover:text-white transition-colors"
            >
              <X className="w-8 h-8 md:w-10 md:h-10" />
            </button>

            <div className="max-w-4xl w-full space-y-8 md:space-y-12">
              <div className="text-center space-y-2 md:space-y-4">
                <h3 className="text-4xl md:text-6xl font-black italic tracking-tighter uppercase flex items-center justify-center gap-4 md:gap-6">
                  <Tv className="w-10 h-10 md:w-14 md:h-14 text-indigo-500" />
                  Production Cut
                </h3>
                <p className="text-indigo-400 text-[10px] md:text-xs font-black uppercase tracking-[0.4em] md:tracking-[0.6em] animate-pulse">
                  {state.isGenerating ? "Synthesizing High-Fidelity Textures" : state.isGeneratingVideo ? "Generating Temporal Continuity" : "Analyzing Production Narrative"}
                </p>
              </div>

              {state.generatedImage ? (
                <div className="relative rounded-2xl md:rounded-[3rem] overflow-hidden border-2 md:border-4 border-white/10 shadow-[0_0_150px_rgba(99,102,241,0.1)] aspect-video bg-black/40">
                  {state.generatedVideo ? (
                    <video src={state.generatedVideo} autoPlay loop muted playsInline className="w-full h-full object-cover" />
                  ) : (
                    <img src={state.generatedImage} className="w-full h-full object-cover" />
                  )}
                  {state.isGeneratingVideo && (
                    <div className="absolute inset-0 bg-black/85 flex flex-col items-center justify-center gap-6">
                      <div className="relative">
                        <Loader2 className="w-12 h-12 md:w-20 md:h-20 text-indigo-500 animate-spin" />
                        <Activity className="absolute inset-0 m-auto w-6 h-6 md:w-8 md:h-8 text-indigo-400 animate-pulse" />
                      </div>
                      <div className="text-center">
                         <p className="text-white font-black tracking-widest text-xs md:text-sm uppercase">{state.videoStatus}</p>
                         <p className="text-white/20 text-[8px] md:text-[10px] font-bold uppercase mt-2 tracking-widest">Veo Engine active</p>
                      </div>
                    </div>
                  )}
                </div>
              ) : (
                <div className="bg-[#111] border border-white/10 p-6 md:p-12 rounded-2xl md:rounded-[3rem] text-left font-serif text-lg md:text-2xl text-white/80 italic leading-relaxed shadow-2xl relative overflow-hidden group">
                  <div className="absolute top-0 left-0 w-2 h-full bg-indigo-600 transition-all group-hover:w-3" />
                  "{state.draftPrompt}"
                </div>
              )}

              <div className="flex flex-col sm:flex-row gap-4 md:gap-6 justify-center">
                {!state.generatedImage && (
                  <button 
                    onClick={handleRenderImage}
                    disabled={state.isGenerating}
                    className="bg-white text-black font-black px-8 md:px-12 py-4 md:py-6 rounded-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-4 shadow-2xl justify-center"
                  >
                    {state.isGenerating ? <Loader2 className="w-6 h-6 md:w-8 md:h-8 animate-spin" /> : <MonitorPlay className="w-6 h-6 md:w-8 md:h-8" />}
                    <div className="text-left">
                      <div className="text-base md:text-xl font-black uppercase">Commit Render</div>
                      <div className="text-[8px] md:text-[10px] opacity-40 font-bold uppercase tracking-widest">Cost: ₹{COST_PER_IMAGE.toFixed(2)}</div>
                    </div>
                  </button>
                )}
                {state.generatedImage && !state.generatedVideo && !state.isGeneratingVideo && (
                  <button 
                    onClick={handleGenerateVideo}
                    className="bg-indigo-600 text-white font-black px-8 md:px-12 py-4 md:py-6 rounded-2xl hover:bg-indigo-500 hover:scale-105 active:scale-95 transition-all flex items-center gap-4 shadow-2xl justify-center"
                  >
                    <Play className="w-6 h-6 md:w-8 md:h-8" />
                    <div className="text-left">
                      <div className="text-base md:text-xl uppercase font-black">Animate Sequence</div>
                      <div className="text-[8px] md:text-[10px] opacity-40 font-bold uppercase tracking-widest">Cost: ₹{COST_PER_VIDEO.toFixed(2)}</div>
                    </div>
                  </button>
                )}
                {state.generatedVideo && (
                  <a 
                    href={state.generatedVideo}
                    download="production_output.mp4"
                    className="bg-emerald-600 text-white font-black px-8 md:px-12 py-4 md:py-6 rounded-2xl hover:bg-emerald-500 hover:scale-105 transition-all flex items-center gap-4 shadow-2xl justify-center"
                  >
                    <Download className="w-6 h-6 md:w-8 md:h-8" />
                    <div className="text-left">
                      <div className="text-base md:text-xl uppercase font-black">Export Master</div>
                      <div className="text-[8px] md:text-[10px] opacity-40 font-bold uppercase tracking-widest">Download MP4</div>
                    </div>
                  </a>
                )}
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

